/* ====== begin assets/js/swiss-pois.js ====== */
/* ───────────────────────── Switzerland POI dataset ─────────────────────────
   Curated points of interest across all 26 cantons of Switzerland for the
   sightseeing route planner. Researched with parallel agents and verified
   against Wikipedia / Wikimedia Commons (coordinates, elevations, images).
   159 POIs.

   Schema (single-letter keys mirror passes-data.js for compactness):
     n      name                                 (string)
     la, lo latitude, longitude                  (decimal degrees, 5 dp)
     e      elevation in metres                  (number, optional)
     co     ISO-3166 country code                ("CH" here, "IT" in italy-pois.js)
     region geographic region                    (see REGIONS below)
     cat    primary category                     (see CATEGORIES below)
     themes cross-cutting interest tags          (array)
     access how to get there                     (subset of car/cable-car/cogwheel/funicular/train/boat/foot)
     season when to visit                        (subset of spring/summer/autumn/winter)
     dur    typical visit duration (hours)       (number)
     sc     notability score (1-10)              (10 = unmissable, 7 = excellent, 5 = solid, 3 = niche)
     td     short description                    (≤250 chars)
     rs     why-visit rationale                  (≤200 chars)
     wl, wt Wikipedia language code + title
     bp     hero photo URL (Wikimedia Commons)

   CATEGORIES:
     mountain-summit      Mountain summit / cable‑car peak
     alpine-lake          Alpine or scenic lake
     waterfall-gorge      Waterfall or gorge
     glacier              Glacier viewpoint or experience
     old-town             Heritage old town / UNESCO city
     castle-fortress      Castle or fortress
     monastery-church     Abbey, monastery or notable church
     scenic-railway       Scenic railway line / cog as POI
     funicular            Funicular ride as POI (signature historic / record-breaking)
     bridge-engineering   Bridge or engineering marvel
     village              Charming village worth its own visit
     national-park        National park / nature reserve
     spa-wellness         Thermal spa / wellness town
     viewpoint-panorama   Panoramic viewpoint / observation deck
     museum-cultural      Museum / cultural site
     geology-cave         Cave / geological feature
     wine-region          Wine region / vineyard landscape
     special-experience   Other unique experience

   REGIONS (POI counts):
     Valais                        27
     Bernese Oberland              22
     Central Switzerland           18
     Ticino                        15
     Engadin                       14
     Eastern Switzerland           13
     Vaud / Lake Geneva            12
     Graubünden                    12
     Basel / Aargau                 7
     Bern / Emmental                5
     Fribourg                       5
     Zürich                         5
     Jura / Neuchâtel               4

   THEMES (filter / multi-select):
     unesco, family-friendly, summer-only, winter-sport, year-round,
     swimmable, photogenic, panoramic-view, cable-car, cogwheel-railway,
     car-accessible, hike-required, boat-accessible, historic, architecture,
     food-drink, iconic, hidden-gem, spa-wellness, special-experience.
*/

const SWISS_POIS = [
  {"n":"Oeschinensee (Oeschinen Lake)","la":46.49833,"lo":7.72694,"e":1578,"co":"CH","region":"Bernese Oberland","cat":"alpine-lake","themes":["unesco","photogenic","swimmable","cable-car","summer-only","iconic"],"access":["cable-car","foot"],"season":["spring","summer","autumn"],"dur":3,"sc":9,"td":"UNESCO-listed emerald lake at 1,578 m above Kandersteg, encircled by 2,000 m limestone cliffs. Gondola lift plus 20-min walk to shore; rowboats and cold-water swimming in summer.","rs":"One of Switzerland's most photographed mountain lakes; UNESCO WHS setting, dramatic amphitheatre of cliffs, superb summer swimming.","wl":"en","wt":"Oeschinen Lake","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/20190725_Oeschinensee-Panorama%2C_Kandersteg_%2806540-42_stitch%29.jpg?width=800"},
  {"n":"Trift Bridge (Triftbrücke)","la":46.6936,"lo":8.36,"e":1740,"co":"CH","region":"Bernese Oberland","cat":"bridge-engineering","themes":["photogenic","hike-required","summer-only","hidden-gem","iconic"],"access":["cable-car","foot"],"season":["summer","autumn"],"dur":4,"sc":8,"td":"170 m pedestrian suspension bridge hanging 100 m above the Triftsee near Gadmen — one of the longest and highest in the Alps. Reached by cable car + 1.5 hr hike; created because the Trift Glacier retreated.","rs":"Most dramatic hike-to suspension bridge in the Alps; glacier retreat created the lake below it — a living climate story.","wl":"en","wt":"Trift Bridge","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Trift_Bridge_02.JPG?width=800"},
  {"n":"Schloss Thun (Thun Castle)","la":46.76008,"lo":7.62982,"e":null,"co":"CH","region":"Bernese Oberland","cat":"castle-fortress","themes":["historic","architecture","car-accessible","year-round","family-friendly"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":1.5,"sc":7,"td":"12th-century Zähringen castle towering over Thun's old town and Lake Thun. The 4-turreted keep is a Swiss cultural monument; museum inside; rooftop walkway atop the hall roof between the towers.","rs":"Best-preserved Zähringen castle in Switzerland; remarkable rooftop walkway between turrets; gateway view over Lake Thun.","wl":"en","wt":"Thun Castle","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/SchlossThun_6385.jpg?width=800"},
  {"n":"Schloss Spiez (Spiez Castle)","la":46.68915,"lo":7.68738,"e":null,"co":"CH","region":"Bernese Oberland","cat":"castle-fortress","themes":["historic","architecture","photogenic","car-accessible","boat-accessible","year-round"],"access":["car","train","boat","foot"],"season":["spring","summer","autumn"],"dur":1.5,"sc":7,"td":"Medieval castle on a vine-clad peninsula jutting into Lake Thun, founded 933 AD. Romanesque church, history museum, and wine cellar; one of Switzerland's most photogenic lakeside castle settings.","rs":"Switzerland's most scenically set castle — vine-covered peninsula on Lake Thun, Romanesque church, and its own vineyard.","wl":"en","wt":"Spiez Castle","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Schloss_Spiez.jpg?width=800"},
  {"n":"Jungfraujoch – Top of Europe","la":46.54722,"lo":7.98056,"e":3463,"co":"CH","region":"Bernese Oberland","cat":"mountain-summit","themes":["unesco","iconic","cogwheel-railway","panoramic-view","photogenic","year-round","family-friendly"],"access":["cogwheel","train"],"season":["spring","summer","autumn","winter"],"dur":4,"sc":10,"td":"Highest railway station in Europe at 3,463 m on the Jungfrau saddle. UNESCO World Heritage area. Sphinx Observatory, vast Aletsch Glacier views, Ice Palace, and snow activities year-round.","rs":"Europe's highest railway station; UNESCO World Heritage landscape with direct Aletsch Glacier access; the defining Swiss alpine icon.","wl":"en","wt":"Jungfraujoch","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Sphinx_et_Jungfrau_-_img_06980.jpg?width=800"},
  {"n":"Schilthorn / Piz Gloria","la":46.55722,"lo":7.83528,"e":2970,"co":"CH","region":"Bernese Oberland","cat":"mountain-summit","themes":["iconic","panoramic-view","cable-car","photogenic","year-round","winter-sport","family-friendly"],"access":["cable-car"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":9,"td":"2,970 m summit above Mürren with 360° revolving Piz Gloria restaurant. James Bond filming location (On Her Majesty's Secret Service). Views of 200 peaks including Eiger, Mönch and Jungfrau.","rs":"360° revolving restaurant, James Bond legend, unobstructed Eiger-Mönch-Jungfrau panorama; cable car from Stechelberg via Mürren.","wl":"en","wt":"Schilthorn","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Schilthorn_with_Bernese_Alps%2C_2012_August.jpg?width=800"},
  {"n":"Schynige Platte Railway","la":46.65611,"lo":7.90694,"e":1987,"co":"CH","region":"Bernese Oberland","cat":"scenic-railway","themes":["panoramic-view","cogwheel-railway","summer-only","photogenic","family-friendly"],"access":["cogwheel","train"],"season":["summer","autumn"],"dur":3,"sc":8,"td":"Victorian cogwheel railway (1893) climbing from Wilderswil to a 1,987 m plateau above Lake Brienz. Alpine botanical garden at the top; classic start of the Faulhorn-First ridge walk.","rs":"One of Switzerland's oldest and most scenic cogwheel lines; alpine garden plus direct access to the finest Jungfrau-front ridgewalk.","wl":"en","wt":"Schynige Platte","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Schynige_Platte.jpg?width=800"},
  {"n":"Brienzer Rothorn","la":46.78694,"lo":8.04694,"e":2350,"co":"CH","region":"Bernese Oberland","cat":"scenic-railway","themes":["panoramic-view","photogenic","summer-only","cogwheel-railway","iconic"],"access":["cogwheel","foot"],"season":["summer","autumn"],"dur":4,"sc":8,"td":"Switzerland's last regular steam-operated cogwheel mountain railway, running from Brienz to 2,350 m since 1892. Summit panorama spans the Bernese and Lucerne Alps; descent option via Sörenberg cable car.","rs":"Switzerland's sole surviving steam cogwheel railway; summit straddles two cantons with panoramas across two alpine ranges.","wl":"en","wt":"Brienzer Rothorn","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Brienzer_Rothorn.jpg?width=800"},
  {"n":"Harder Kulm","la":46.7,"lo":7.85,"e":1322,"co":"CH","region":"Bernese Oberland","cat":"viewpoint-panorama","themes":["panoramic-view","photogenic","family-friendly","year-round"],"access":["funicular"],"season":["spring","summer","autumn","winter"],"dur":1.5,"sc":8,"td":"'The Top of Interlaken': 10-minute funicular ride from town to 1,322 m. Glass-floored Two Lakes Bridge observation deck frames Lake Thun, Lake Brienz, and the Eiger-Mönch-Jungfrau wall.","rs":"Fastest panoramic payoff in the Bernese Oberland; bird's-eye view over both Interlaken lakes in under 10 minutes.","wl":"en","wt":"Harderkulm","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/14_Harder_Kulm_Lac_Thoune_Photo_by_Giles_Laurent.jpg?width=800"},
  {"n":"First Cliff Walk, Grindelwald","la":46.66056,"lo":8.05361,"e":2184,"co":"CH","region":"Bernese Oberland","cat":"viewpoint-panorama","themes":["panoramic-view","cable-car","photogenic","family-friendly","iconic"],"access":["cable-car"],"season":["spring","summer","autumn"],"dur":3,"sc":8,"td":"Cable car to 2,184 m above Grindelwald. Cliff Walk overhang trail, First Flyer zipline, and an easy 1 hr walk to Bachalpsee — a mirror lake reflecting the Eiger and Schreckhorn.","rs":"Best Eiger front-face panorama; cliff walkway, zipline, and Bachalpsee reflection shot all in one half-day outing.","wl":"en","wt":"First (Grindelwald)","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Grindelwald_First.jpg?width=800"},
  {"n":"Lauterbrunnen Valley","la":46.595,"lo":7.90745,"e":802,"co":"CH","region":"Bernese Oberland","cat":"village","themes":["iconic","photogenic","car-accessible","year-round","panoramic-view"],"access":["car","train"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":8,"td":"Valley-floor village at 802 m hemmed in by sheer limestone cliffs bearing 72 waterfalls up to 300 m high. Transport hub for car-free Mürren, Wengen, and Kleine Scheidegg; the definitive Bernese Oberland valley.","rs":"Switzerland's most dramatic valley: 72 waterfalls, vertical walls, and gateway to the entire Jungfrau region above.","wl":"en","wt":"Lauterbrunnen","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/1_lauterbrunnen_valley_wengen_2022.jpg?width=800"},
  {"n":"Mürren","la":46.55944,"lo":7.89222,"e":1638,"co":"CH","region":"Bernese Oberland","cat":"village","themes":["iconic","photogenic","winter-sport","year-round","panoramic-view","hidden-gem"],"access":["cable-car","funicular","train"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":8,"td":"Car-free cliff village at 1,638 m with a direct sight line to Eiger, Mönch and Jungfrau. Widely regarded as the birthplace of modern Alpine skiing. Lower cable car from Lauterbrunnen; base for Schilthorn.","rs":"Quintessential Swiss car-free Alpine village; arguably the finest EMJ-trilogy view from any inhabited settlement.","wl":"en","wt":"Mürren","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/1_M%C3%BCrren_2022.jpg?width=800"},
  {"n":"Iseltwald","la":46.7,"lo":7.967,"e":566,"co":"CH","region":"Bernese Oberland","cat":"village","themes":["photogenic","car-accessible","swimmable","boat-accessible","hidden-gem","food-drink"],"access":["car","boat"],"season":["spring","summer","autumn"],"dur":1.5,"sc":7,"td":"Tiny car-accessible village on a peninsula in turquoise Lake Brienz. The private lakeside pier became famous after appearing in Netflix's 'Squid Game: The Challenge.' Beach access and boat excursions.","rs":"Most scenic lakeside village in the Brienz region; Netflix-famous pier, extraordinary turquoise water, uncrowded feel.","wl":"en","wt":"Iseltwald","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/5902_-_Iseltwald.JPG?width=800"},
  {"n":"Trümmelbach Falls","la":46.56907,"lo":7.91498,"e":null,"co":"CH","region":"Bernese Oberland","cat":"waterfall-gorge","themes":["iconic","family-friendly","photogenic","year-round"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":1.5,"sc":8,"td":"Europe's only accessible glacial waterfalls inside a mountain — 10 cascades carrying up to 20,000 l/s of Eiger-Mönch-Jungfrau meltwater. Tunnel lift inside the rock; spray-drenched walkways.","rs":"Unique: a glacial drainage system you walk through inside a mountain; nowhere else in Europe offers this experience.","wl":"en","wt":"Trümmelbach Falls","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Trummelbach.JPG?width=800"},
  {"n":"Staubbach Falls","la":46.58965,"lo":7.90551,"e":null,"co":"CH","region":"Bernese Oberland","cat":"waterfall-gorge","themes":["iconic","photogenic","car-accessible","year-round","historic"],"access":["car","train","foot"],"season":["spring","summer","autumn"],"dur":0.5,"sc":7,"td":"297 m free-falling waterfall on the western cliff of Lauterbrunnen valley — one of Switzerland's highest. Inspired Goethe's 1779 poem. A path leads visitors behind the spray curtain.","rs":"Switzerland's most visible free-fall waterfall; walk-behind path, Goethe connection, and it defines the iconic valley skyline.","wl":"en","wt":"Staubbach Falls","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Lauterbrunnen_Staubbach.jpg?width=800"},
  {"n":"Reichenbach Falls","la":46.71361,"lo":8.18306,"e":null,"co":"CH","region":"Bernese Oberland","cat":"waterfall-gorge","themes":["historic","photogenic","year-round","family-friendly"],"access":["car","funicular","foot"],"season":["spring","summer","autumn"],"dur":1.5,"sc":7,"td":"250 m cascade near Meiringen, fictional death-site of Sherlock Holmes vs Moriarty in Conan Doyle's 'The Final Problem.' Served by a vintage funicular (1899). Seven drops; powerful upper fall at 110 m.","rs":"Literary landmark where Holmes 'died'; vintage funicular, one of the Alps' most powerful cascades, near Meiringen.","wl":"en","wt":"Reichenbach Falls","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Reichenbachfall_2007.jpg?width=800"},
  {"n":"Aareschlucht (Aare Gorge)","la":46.71778,"lo":8.21361,"e":null,"co":"CH","region":"Bernese Oberland","cat":"waterfall-gorge","themes":["family-friendly","photogenic","year-round","car-accessible"],"access":["car","train","foot"],"season":["spring","summer","autumn"],"dur":1.5,"sc":7,"td":"Narrow limestone gorge cut by the Aare near Meiringen; 2 km long with cliffs 50 m high and passages as narrow as 1 m. Illuminated walkway open since 1889; can combine with Reichenbach Falls.","rs":"One of Switzerland's most dramatic short gorge walks; atmospheric lighting, 1 m-wide passages, easy train access from Meiringen.","wl":"en","wt":"Aare Gorge","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Aareschlucht_166_7.jpg?width=800"},
  {"n":"Glacier Garden (Gletschergarten), Lucerne","la":47.059,"lo":8.3117,"e":null,"co":"CH","region":"Central Switzerland","cat":"geology-cave","themes":["family-friendly","year-round","historic","hidden-gem"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":1.5,"sc":7,"td":"Outdoor geological site steps from the Lion Monument with 32 glacial potholes (Gletschertöpfe) up to 8 m deep, carved by meltwater 20,000 years ago. Museum contains Switzerland's oldest large-scale panoramic relief map (1882).","rs":"Europe's best-preserved set of glacial potholes; the adjacent 1882 Swiss Alps relief map is a cartographic masterpiece.","wl":"de","wt":"Gletschergarten","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Panorama_Gletschergarten.jpg?width=800"},
  {"n":"Engelberg Abbey","la":46.82226,"lo":8.41065,"e":1021,"co":"CH","region":"Central Switzerland","cat":"monastery-church","themes":["historic","architecture","year-round","family-friendly"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":1.5,"sc":7,"td":"Benedictine monastery founded in 1120 at the foot of the Titlis valley. Still an active abbey with a grand Baroque church, a library holding 12th-century manuscripts, monastery cheese production, and guided tours.","rs":"900-year-old living monastery; magnificent Baroque church; historically the ecclesiastical sovereign of Obwalden canton.","wl":"en","wt":"Engelberg Abbey","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Engelberg_Kloster_085.jpg?width=800"},
  {"n":"Mount Pilatus","la":46.97389,"lo":8.24111,"e":2129,"co":"CH","region":"Central Switzerland","cat":"mountain-summit","themes":["iconic","cogwheel-railway","cable-car","panoramic-view","year-round","photogenic","family-friendly","winter-sport"],"access":["cogwheel","cable-car"],"season":["spring","summer","autumn","winter"],"dur":4,"sc":9,"td":"Iconic 2,129 m massif looming over Lucerne. Served by the world's steepest cogwheel railway (48% gradient, from Alpnachstad) and a cable car from Kriens; classic round trip combines both.","rs":"Lucerne's defining mountain; world's steepest cogwheel railway; do the classic round-trip with boat to Alpnachstad.","wl":"en","wt":"Pilatus (mountain)","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Luzern_-_Mount_Pilatus_-_March_2019_%2801%29.jpg?width=800"},
  {"n":"Mount Rigi (Rigi Kulm)","la":47.05667,"lo":8.48556,"e":1797,"co":"CH","region":"Central Switzerland","cat":"mountain-summit","themes":["iconic","cogwheel-railway","year-round","panoramic-view","photogenic","boat-accessible","winter-sport"],"access":["cogwheel","cable-car","boat"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":9,"td":"'Queen of the Mountains' at 1,797 m, surrounded by Lakes Lucerne, Zug and Lauerz. Home of Europe's first mountain cogwheel railway (1871). Famous for sunrise views over 50+ Alpine peaks.","rs":"Europe's first mountain railway (1871); sunrise panoramas over Central Switzerland; perfect combine with Lake Lucerne steamer.","wl":"en","wt":"Rigi","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Lauerzersee.jpg?width=800"},
  {"n":"Mount Titlis (Engelberg)","la":46.7725,"lo":8.43722,"e":3238,"co":"CH","region":"Central Switzerland","cat":"mountain-summit","themes":["iconic","cable-car","year-round","winter-sport","panoramic-view","photogenic","family-friendly"],"access":["cable-car"],"season":["spring","summer","autumn","winter"],"dur":4,"sc":9,"td":"3,238 m glacier peak above Engelberg; highest year-round summit in Central Switzerland. World's first rotating cable car (Rotair), glacier cave walk, and Titlis Cliff Walk suspension bridge at 3,041 m.","rs":"Only year-round glacier in Central Switzerland; world's first rotating cable car; cliff walk at 3,000 m is a world-class experience.","wl":"en","wt":"Titlis","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Titlis_W.jpg?width=800"},
  {"n":"Stanserhorn","la":46.92972,"lo":8.34028,"e":1898,"co":"CH","region":"Central Switzerland","cat":"mountain-summit","themes":["panoramic-view","cable-car","summer-only","photogenic","family-friendly","hidden-gem"],"access":["funicular","cable-car"],"season":["spring","summer","autumn"],"dur":3,"sc":7,"td":"1,898 m summit above Stans, served by the world's first open-top double-decker cable car ('CabriO', 2012). 360° panorama from the Bernese Oberland to the Black Forest; paragliders launch from the top.","rs":"World's only open-top double-decker gondola makes every ascent a panoramic experience; often overlooked gem near Lucerne.","wl":"en","wt":"Stanserhorn","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Stanserhorn.jpg?width=800"},
  {"n":"Fronalpstock / Stoos","la":46.96808,"lo":8.63728,"e":1921,"co":"CH","region":"Central Switzerland","cat":"funicular","themes":["panoramic-view","cable-car","winter-sport","photogenic","year-round","iconic"],"access":["funicular","cable-car"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":7,"td":"1,921 m summit above car-free Stoos village (1,300 m). Reached via the Stoosbahn — the world's steepest funicular (110% gradient, opened 2017). Panorama over all four arms of Lake Lucerne and the Uri Alps.","rs":"World's steepest funicular delivers you to a 360° Alpine panorama; car-free Stoos village is a bonus charm.","wl":"en","wt":"Fronalpstock (Schwyz)","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Fronalpstock_big.jpg?width=800"},
  {"n":"Lion Monument (Löwendenkmal)","la":47.05833,"lo":8.31056,"e":null,"co":"CH","region":"Central Switzerland","cat":"museum-cultural","themes":["iconic","historic","architecture","year-round","family-friendly"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":0.5,"sc":8,"td":"Monumental 1821 rock relief of a dying lion carved into a cliff face, commemorating 760 Swiss Guards killed in the 1792 French Revolution. Mark Twain called it 'the most mournful and moving piece of stone in the world.'","rs":"Mark Twain's 'most mournful stone in the world'; visited by 1.4 million annually; steps from the Glacier Garden and Kapellbrücke.","wl":"en","wt":"Lion Monument","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Lion_Monument.jpg?width=800"},
  {"n":"Swiss Museum of Transport (Verkehrshaus)","la":47.05083,"lo":8.33722,"e":null,"co":"CH","region":"Central Switzerland","cat":"museum-cultural","themes":["family-friendly","year-round","iconic","food-drink"],"access":["car","train","boat"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":8,"td":"Switzerland's most-visited museum (1 million+ visitors/year), opened 1959 on Lucerne's lakefront. Covers all transport: trains, aircraft, ships, cable cars. Also hosts a planetarium, IMAX cinema, and Swiss Chocolate Adventure.","rs":"Switzerland's most popular museum by attendance; every transport technology in one lakeside complex; unmissable for families.","wl":"en","wt":"Swiss Museum of Transport","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Verkehrshaus_der_Schweiz_Halle_Strassenverkehr.jpg?width=800"},
  {"n":"Lucerne Old Town & Kapellbrücke","la":47.05167,"lo":8.3075,"e":null,"co":"CH","region":"Central Switzerland","cat":"old-town","themes":["iconic","historic","architecture","year-round","family-friendly","photogenic","food-drink"],"access":["car","train","boat"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":10,"td":"Medieval city centre anchored by the 1360-built Kapellbrücke — Europe's oldest surviving covered wooden bridge — with its Wasserturm and interior panel paintings. Frescoed façades, preserved walls, lakefront.","rs":"Switzerland's most visited city and most photographed bridge; the old town can be paired with every mountain in the region.","wl":"en","wt":"Kapellbrücke","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Kapellbruecke.JPG?width=800"},
  {"n":"Lake Lucerne Paddle Steamers","la":47.0503,"lo":8.3094,"e":null,"co":"CH","region":"Central Switzerland","cat":"special-experience","themes":["iconic","boat-accessible","year-round","family-friendly","photogenic","panoramic-view","food-drink"],"access":["boat"],"season":["spring","summer","autumn","winter"],"dur":4,"sc":8,"td":"Fleet of five restored Belle Époque paddle steamers on Vierwaldstättersee, some dating from 1901. Routes pass Rütli, Pilatus, Rigi, and the Bürgenstock cliffs; dining on board; year-round service from Lucerne.","rs":"Most atmospheric way to see Lake Lucerne; historic steamers connect all major landmarks and allow mix-and-match mountain days.","wl":"en","wt":"Lake Lucerne","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Vierwaldstaettersee.jpg?width=800"},
  {"n":"Hammetschwand Elevator / Bürgenstock","la":47.00033,"lo":8.39868,"e":1132,"co":"CH","region":"Central Switzerland","cat":"special-experience","themes":["iconic","panoramic-view","photogenic","architecture","year-round"],"access":["boat","funicular","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":8,"td":"Europe's highest outdoor elevator (153 m ascent in under 1 minute) on the Bürgenstock cliff above Lake Lucerne, operating since 1905. Iron lattice tower tops out on a panoramic terrace 600 m above the lake.","rs":"Europe's highest outdoor lift on a vertiginous cliff face; the cliff-edge promenade around the Bürgenstock plateau is equally spectacular.","wl":"en","wt":"Hammetschwand Elevator","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Luzern_B%C3%BCrgenstock_Hammetschwand_lift.jpg?width=800"},
  {"n":"Rütli Meadow","la":46.969,"lo":8.593,"e":null,"co":"CH","region":"Central Switzerland","cat":"special-experience","themes":["historic","boat-accessible","year-round","iconic","hike-required"],"access":["boat","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":8,"td":"Mountain meadow on Lake Uri's western shore; traditional site of the 1291 Rütli Oath founding the Swiss Confederacy. National monument reachable only by boat or foot. Annual Swiss National Day ceremony held here.","rs":"Switzerland's symbolic founding meadow; accessible only by boat from Lucerne, which adds pilgrimage drama; free to visit.","wl":"en","wt":"Rütli","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/R%C3%BCtli.jpg?width=800"},
  {"n":"Tellskapelle (Tell's Chapel)","la":46.93264,"lo":8.611862,"e":null,"co":"CH","region":"Central Switzerland","cat":"special-experience","themes":["historic","boat-accessible","year-round","iconic"],"access":["boat","foot"],"season":["spring","summer","autumn","winter"],"dur":1,"sc":7,"td":"Lakeside chapel built on the rocky Tellsplatte ledge on Lake Uri, where William Tell allegedly leapt from Gessler's boat to freedom. Pilgrimage site since 1388 with 16th-century frescoes depicting the Tell legend.","rs":"Touchstone of the William Tell legend on the shores of Lake Uri; best reached by paddle steamer from Lucerne.","wl":"de","wt":"Tellskapelle","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Tellskapelle2000.jpg?width=800"},
  {"n":"Andermatt","la":46.61667,"lo":8.58333,"e":1444,"co":"CH","region":"Central Switzerland","cat":"village","themes":["winter-sport","year-round","historic","car-accessible","food-drink"],"access":["car","train"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":7,"td":"Historic Swiss Army garrison village at 1,444 m in the Uri Alps, now transformed into a luxury alpine resort. Year-round hub for the Gotthard region; 180 km ski area connected with Sedrun and Disentis.","rs":"Switzerland's most ambitious new mountain resort development; strategic crossroads for Schöllenen, Furka and Gotthard; excellent base.","wl":"en","wt":"Andermatt","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Andermatt.jpg?width=800"},
  {"n":"Schöllenen Gorge & Devil's Bridge","la":46.6475,"lo":8.59,"e":null,"co":"CH","region":"Central Switzerland","cat":"waterfall-gorge","themes":["historic","photogenic","car-accessible","year-round","architecture"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":1.5,"sc":7,"td":"Dramatic granite gorge of the upper Reuss between Göschenen and Andermatt. The legendary Teufelsbrücke (Devil's Bridge) was the key to the St Gotthard route; Napoleon crossed with 15,000 troops in 1799.","rs":"Switzerland's most historically loaded gorge; Napoleon's 1799 crossing, Devil's Bridge legend, and sheer granite walls make it unmissable en route to Andermatt.","wl":"en","wt":"Schöllenen Gorge","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/2007-10-02_Sch%C3%B6llenen_02.jpg?width=800"},
  {"n":"Riffelsee","la":45.98333,"lo":7.76222,"e":2757,"co":"CH","region":"Valais","cat":"alpine-lake","themes":["photogenic","panoramic-view","iconic","hike-required","swimmable"],"access":["cogwheel","foot"],"season":["summer","autumn"],"dur":1.5,"sc":8,"td":"Alpine lake (2,757 m) 10 min from Rotenboden station on the Gornergratbahn. Its glassy surface mirrors the Matterhorn in one of the most reproduced travel photographs in the world. Central stop on the Five Lakes Walk above Zermatt.","rs":"Best-known Matterhorn mirror-reflection lake in Switzerland; centrepiece of the celebrated Five Lakes Walk and a must for photographers.","wl":"en","wt":"Riffelsee","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Riffelsee_1.jpg?width=800"},
  {"n":"Märjelensee","la":46.44077,"lo":8.09199,"e":2348,"co":"CH","region":"Valais","cat":"alpine-lake","themes":["unesco","photogenic","hike-required","summer-only"],"access":["cable-car","foot"],"season":["summer","autumn"],"dur":3,"sc":7,"td":"Glacial lake (2,348 m) dammed against the eastern edge of the Aletsch Glacier. Its shoreline is formed by glacier ice; the turquoise water reflects seracs and rock walls. Reached by hiking trails from Fiescheralp, within the UNESCO World Heritage Area.","rs":"Rare periglacial lake with a glacier ice shoreline; an iconic and photogenic destination within the UNESCO Aletsch World Heritage Area.","wl":"en","wt":"Märjelensee","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Aletschgletscher_M%C3%A4rjelensee.jpg?width=800"},
  {"n":"Lac de Moiry","la":46.13028,"lo":7.57056,"e":2249,"co":"CH","region":"Valais","cat":"alpine-lake","themes":["car-accessible","photogenic","summer-only","panoramic-view"],"access":["car","foot"],"season":["summer","autumn"],"dur":2,"sc":7,"td":"Vivid turquoise reservoir (2,249 m) at the head of Val d'Anniviers, backed by the Moiry Glacier and sheer rock walls. The 148 m arch dam (1958) is reached by a scenic mountain road; hikers can continue up to the glacier snout.","rs":"Exceptionally photogenic high-altitude reservoir with an active glacier backdrop in Val d'Anniviers; one of Valais's finest alpine lake drives.","wl":"en","wt":"Lac de Moiry","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Barrage_de_Moiry.jpg?width=800"},
  {"n":"Charles Kuonen Suspension Bridge","la":46.10004,"lo":7.80319,"e":null,"co":"CH","region":"Valais","cat":"bridge-engineering","themes":["hike-required","photogenic","summer-only"],"access":["foot"],"season":["spring","summer","autumn"],"dur":2,"sc":8,"td":"At 494 m the world's longest pedestrian suspension bridge at its July 2017 opening, strung 85 m above the Grabengufer ravine near Randa. Its transparent mesh deck looks down to the valley. Part of the Europaweg trail from Grächen to Zermatt.","rs":"Former world-record holder for longest pedestrian suspension bridge (2017); thrilling engineering on a classic high-level Alpine trail above Mattertal.","wl":"en","wt":"Charles Kuonen Suspension Bridge","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/H%C3%A4ngebr%C3%BCcke_Randa.jpg?width=800"},
  {"n":"Grande Dixence Dam","la":46.08056,"lo":7.40389,"e":null,"co":"CH","region":"Valais","cat":"bridge-engineering","themes":["car-accessible","photogenic","summer-only"],"access":["car","foot"],"season":["summer","autumn"],"dur":2,"sc":8,"td":"World's tallest gravity dam (285 m, completed 1961), impounding the 7 km Lac des Dix in Val d'Hérémence. A funicular inside the dam wall carries visitors 200 m to the crest; guided interior tours and a panoramic dam-top walk available.","rs":"World's tallest gravity dam and 7th-tallest dam overall; internal funicular and visitor access make it a globally unique engineering monument.","wl":"en","wt":"Grande Dixence Dam","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Barrage_de_la_Grande-Dixence.jpg?width=800"},
  {"n":"Mauvoisin Dam","la":45.99806,"lo":7.34917,"e":null,"co":"CH","region":"Valais","cat":"bridge-engineering","themes":["car-accessible","photogenic","summer-only"],"access":["car","foot"],"season":["summer","autumn"],"dur":2,"sc":7,"td":"One of the world's tallest arch dams (250 m, completed 1957) spanning the Val de Bagnes beneath Mont Blanc de Cheilon. The 4.9 km Lac de Mauvoisin reservoir and remote valley setting make it a rewarding engineering excursion.","rs":"World's 8th-tallest dam; a spectacular mid-century Alpine engineering feat in a remote valley below the Grand Combin massif.","wl":"en","wt":"Mauvoisin Dam","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Mauvoisin_dam.jpg?width=800"},
  {"n":"Tourbillon Castle","la":46.23639,"lo":7.36694,"e":null,"co":"CH","region":"Valais","cat":"castle-fortress","themes":["historic","architecture","panoramic-view","photogenic"],"access":["foot"],"season":["spring","summer","autumn"],"dur":1,"sc":7,"td":"Medieval castle ruins (1297–1308) on a steep rocky hill above Sion, built as a bishops' fortress and destroyed by fire in 1788. Forms an iconic double-hill skyline with Valère Basilica opposite; sweeping views over the Rhône valley.","rs":"Iconic medieval ruin forming Sion's landmark double-hill silhouette with Valère Basilica; Swiss national heritage significance.","wl":"en","wt":"Tourbillon Castle","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Ch%C3%A2teau_de_Tourbillon_-_2022.jpg?width=800"},
  {"n":"Pyramides d'Euseigne","la":46.17222,"lo":7.42278,"e":979,"co":"CH","region":"Valais","cat":"geology-cave","themes":["car-accessible","year-round","photogenic","family-friendly"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":0.5,"sc":7,"td":"Glacial moraine hoodoos in Val d'Hérens: columns up to 15 m tall, each capped by a protective boulder of harder rock. The road to Evolène passes through a tunnel cut beneath the largest group — a striking and unique geological roadside curiosity.","rs":"Switzerland's most dramatic hoodoo formation; the main road tunnels beneath the pyramids, making it a uniquely memorable car-accessible stop.","wl":"en","wt":"Euseigne","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Euseigne_depuis_Saint-Martin_-_2022.jpg?width=800"},
  {"n":"Aletsch Glacier","la":46.44222,"lo":8.07722,"e":null,"co":"CH","region":"Valais","cat":"glacier","themes":["unesco","iconic","photogenic","summer-only","hike-required","panoramic-view"],"access":["foot","cable-car"],"season":["summer","autumn"],"dur":4,"sc":10,"td":"The largest glacier in the Alps (23 km, 81 km²) and a UNESCO World Heritage Site. Its curved river of ice reaches 940 m depth at Konkordiaplatz; best seen from Eggishorn or Bettmerhorn, or explored on guided glacier walks.","rs":"Largest glacier in the Alps and centrepiece of the UNESCO Jungfrau-Aletsch World Heritage Site; a globally significant natural monument.","wl":"en","wt":"Aletsch Glacier","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Switzerland%2C_Bettmeralp_%2819505442736%29.jpg?width=800"},
  {"n":"Valère Basilica","la":46.2339,"lo":7.3644,"e":615,"co":"CH","region":"Valais","cat":"monastery-church","themes":["historic","architecture","year-round","car-accessible","photogenic"],"access":["foot","car"],"season":["spring","summer","autumn","winter"],"dur":1.5,"sc":8,"td":"Romanesque-Gothic fortified church (12th–14th c.) on a rocky hill above Sion, housing the world's oldest playable pipe organ (c. 1435). Swiss Cultural Property of National Significance, with sweeping views over the Rhône valley.","rs":"One of Switzerland's finest medieval ecclesiastical monuments; houses the world's oldest playable pipe organ, still played at concerts.","wl":"en","wt":"Valère Basilica","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Val%C3%A8re_et_Haut_de_Cry.jpg?width=800"},
  {"n":"Matterhorn","la":45.97639,"lo":7.65861,"e":4478,"co":"CH","region":"Valais","cat":"mountain-summit","themes":["iconic","photogenic","panoramic-view","summer-only","hike-required"],"access":["foot"],"season":["summer"],"dur":0.5,"sc":10,"td":"The world's most photographed mountain (4,478 m), an almost perfect pyramid straddling the Swiss–Italian border above Zermatt. The summit demands technical Alpine skills; most visitors admire it from Zermatt, the Riffelsee, or Gornergrat.","rs":"Globally iconic symbol of the Alps; recognised worldwide as the emblem of Switzerland and the Alpine ideal.","wl":"en","wt":"Matterhorn","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Matterhorn_from_Domh%C3%BCtte_-_2.jpg?width=800"},
  {"n":"Klein Matterhorn – Matterhorn Glacier Paradise","la":45.93833,"lo":7.72972,"e":3883,"co":"CH","region":"Valais","cat":"mountain-summit","themes":["cable-car","panoramic-view","year-round","winter-sport","iconic","photogenic"],"access":["cable-car"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":9,"td":"At 3,883 m the highest cable-car station in Europe, above Zermatt. Features a year-round ski area on the Breithorn Plateau, a carved glacier ice palace, and sweeping views stretching to Mont Blanc and Gran Paradiso.","rs":"Highest aerial tramway in Europe; combines year-round glacier skiing, an ice palace, and a summit panorama accessible without climbing.","wl":"en","wt":"Klein Matterhorn","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/KleinMatterhorn_edit.jpg?width=800"},
  {"n":"Leukerbad","la":46.383,"lo":7.633,"e":1411,"co":"CH","region":"Valais","cat":"spa-wellness","themes":["year-round","family-friendly","car-accessible","winter-sport"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":8,"td":"Europe's largest alpine thermal spa resort (1,411 m) in a dramatic cirque below the Gemmi Pass. Springs at 51 °C known since Roman times; the Burgerbad and Alpentherme offer outdoor thermal pools, waterfalls and panoramic mountain views.","rs":"Largest alpine thermal spa resort in Europe; Roman-era hot springs with year-round wellness tourism in a spectacular high-mountain bowl.","wl":"en","wt":"Leukerbad","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Leukerbad2.jpg?width=800"},
  {"n":"Mittelallalin – Allalin Ice Cave","la":46.05778,"lo":7.905,"e":3456,"co":"CH","region":"Valais","cat":"glacier","themes":["cable-car","year-round","winter-sport","family-friendly"],"access":["cable-car"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":8,"td":"Reached by the world's highest underground funicular (Metro Alpin) from Saas-Fee: at 3,456 m features the world's highest revolving restaurant and a spectacular carved glacier cave inside the Fee Glacier, visited year-round.","rs":"World's highest revolving restaurant and a year-round glacier ice cave; reached by the world's highest underground funicular above Saas-Fee.","wl":"en","wt":"Mittelallalin","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Allalin.jpg?width=800"},
  {"n":"Gornergrat","la":45.98333,"lo":7.78472,"e":3089,"co":"CH","region":"Valais","cat":"viewpoint-panorama","themes":["cogwheel-railway","panoramic-view","iconic","year-round","winter-sport","photogenic"],"access":["cogwheel"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":9,"td":"Europe's highest open-air cogwheel railway (1898) climbs to 3,089 m above Zermatt for a 360° panorama of 29 four-thousanders including the Matterhorn and Dufourspitze. Observatory, Kulmhotel and restaurant at the terminus.","rs":"World's highest open-air rack railway + panorama of 29 four-thousanders; Zermatt's most iconic and most-visited high-altitude excursion.","wl":"en","wt":"Gornergrat","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Gornergrat.jpg?width=800"},
  {"n":"Eggishorn","la":46.43139,"lo":8.09417,"e":2927,"co":"CH","region":"Valais","cat":"mountain-summit","themes":["cable-car","panoramic-view","photogenic","summer-only","unesco"],"access":["cable-car","foot"],"season":["spring","summer","autumn"],"dur":2.5,"sc":8,"td":"Classic summit viewpoint (2,927 m) above Fiesch with the finest aerial perspective of the Great Aletsch Glacier — Europe's largest, 23 km long. Cable car from Fiesch; short hike to summit. Within the UNESCO Jungfrau-Aletsch World Heritage Site.","rs":"Benchmark viewpoint for the Aletsch Glacier within the UNESCO Swiss Alps Jungfrau-Aletsch World Heritage Site; panoramas to the Matterhorn and Dom.","wl":"en","wt":"Eggishorn","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Eggishorn%2C_Berner_Alpen%2C_Wallis%2C_Switzerland%2C_from_southwest.jpg?width=800"},
  {"n":"Mont Fort","la":46.08056,"lo":7.31861,"e":3328,"co":"CH","region":"Valais","cat":"mountain-summit","themes":["cable-car","panoramic-view","winter-sport","photogenic"],"access":["cable-car"],"season":["summer","winter"],"dur":3,"sc":8,"td":"At 3,328 m the high point of the vast 4 Vallées ski area above Verbier, reached by cable car. The panorama spans from Mont Blanc and Grand Combin to the Matterhorn; year-round glacier skiing on the Tortin glacier in winter.","rs":"Highest peak of the 4 Vallées (Verbier area), offering one of Valais's broadest cable-car summit panoramas above the Val de Bagnes.","wl":"en","wt":"Mont Fort","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Mont_Fort_Buckelpiste_017.JPG?width=800"},
  {"n":"Crans-Montana","la":46.31194,"lo":7.4825,"e":null,"co":"CH","region":"Valais","cat":"viewpoint-panorama","themes":["car-accessible","year-round","winter-sport","panoramic-view","family-friendly"],"access":["car","cable-car"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":7,"td":"Sunny resort plateau in central Valais, south-facing above the Rhône valley, with sweeping views to the Pennine Alps. Known for the Omega European Masters golf and the Plaine Morte glacier (3,000 m), accessible by cable car.","rs":"Premier Valais resort plateau; south-facing panoramic position, year-round appeal, and access to the high-altitude Plaine Morte glacier above the Rhône.","wl":"en","wt":"Crans-Montana","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Crans_Montana_Helico_HtPlateau_Golf_OlivierMaire.jpg?width=800"},
  {"n":"Zermatt","la":46.017,"lo":7.75,"e":1608,"co":"CH","region":"Valais","cat":"village","themes":["iconic","year-round","winter-sport","historic","food-drink","family-friendly"],"access":["train","foot"],"season":["spring","summer","autumn","winter"],"dur":4,"sc":10,"td":"Switzerland's most iconic mountain resort (1,608 m), entirely car-free and dominated by the Matterhorn. Hub for the Gornergratbahn, Klein Matterhorn cable car, and Five Lakes Walk. World-class skiing November–April; rich alpine heritage.","rs":"Switzerland's most visited mountain destination; global gateway to the Matterhorn, Gornergrat, and Klein Matterhorn — a year-round icon.","wl":"en","wt":"Zermatt","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/1_zermatt_evening_2022.jpg?width=800"},
  {"n":"Saas-Fee","la":46.10967,"lo":7.92917,"e":1800,"co":"CH","region":"Valais","cat":"village","themes":["iconic","year-round","winter-sport","family-friendly","photogenic","hidden-gem"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":8,"td":"Car-free 'Pearl of the Alps' (1,800 m) ringed by 13 four-thousanders and the Fee Glacier. Year-round skiing via the world's highest underground funicular (Metro Alpin to 3,456 m); vibrant car-free village with glacial backdrop.","rs":"One of Switzerland's most photogenic car-free villages; encircled by an extraordinary crown of 4,000 m peaks and a permanent glacier.","wl":"en","wt":"Saas-Fee","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Saas-Fee_Ort%2C_Januar_2009.jpg?width=800"},
  {"n":"Bettmeralp","la":46.383,"lo":8.083,"e":1970,"co":"CH","region":"Valais","cat":"village","themes":["cable-car","year-round","photogenic","winter-sport","unesco","family-friendly"],"access":["cable-car","foot"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":7,"td":"Car-free terrace village (1,970 m) above the Rhône valley, reached by cable car from Betten. Part of the UNESCO Aletsch Arena; trails lead to the Bettmerhorn viewpoint, Aletsch Glacier margin, and Märjelensee lake.","rs":"Car-free gateway village of the UNESCO Aletsch Arena; combines winter skiing, glacier views, and direct trail access to the Aletsch Glacier.","wl":"en","wt":"Bettmeralp","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Bettmeralp_mit_Bettmerhorn.jpg?width=800"},
  {"n":"Grimentz","la":46.18083,"lo":7.57611,"e":1553,"co":"CH","region":"Valais","cat":"village","themes":["historic","photogenic","car-accessible","year-round","hidden-gem","food-drink"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":7,"td":"One of Switzerland's finest intact traditional villages (1,553 m) in Val d'Anniviers, with 16th-century dark-larch chalets and famous vin des glaciers cellars. Consistently rated among Switzerland's most beautiful villages.","rs":"Quintessential Valais timber village; renowned for vin des glaciers (mountain-aged wine) and a remarkably intact medieval streetscape in Val d'Anniviers.","wl":"en","wt":"Grimentz","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Grimentz_-_ao%C3%BBt_2022.jpg?width=800"},
  {"n":"Evolène","la":46.117,"lo":7.5,"e":1371,"co":"CH","region":"Valais","cat":"village","themes":["historic","photogenic","car-accessible","hidden-gem"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":6,"td":"Authentic traditional village (1,371 m) in Val d'Hérens, known for original timber architecture, the Évolène cattle breed, and women's folk costumes still worn daily. Gateway to high-altitude Arolla and the imposing Dent Blanche (4,357 m).","rs":"Best-preserved traditional Val d'Hérens village; living Alpine folklore with daily costume-wearing and gateway to the Arolla climbing area.","wl":"en","wt":"Evolène","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Evolene.jpg?width=800"},
  {"n":"Chillon Castle (Château de Chillon)","la":46.41444,"lo":6.9275,"e":372,"co":"CH","region":"Vaud / Lake Geneva","cat":"castle-fortress","themes":["iconic","historic","architecture","photogenic","year-round","car-accessible","boat-accessible","family-friendly"],"access":["car","train","boat","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":10,"td":"Switzerland's most-visited historic monument: an 11th-c. island castle on Lake Geneva that inspired Lord Byron's 'The Prisoner of Chillon' (1816). Lakeside ramparts, dungeon, frescoed Bernese rooms.","rs":"Switzerland #1 historic monument by visits; Byron-immortalised setting on Lake Geneva with one of the most photographed castle silhouettes in Europe.","wl":"en","wt":"Chillon Castle","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/86_-_Ch%C3%A2teau_de_Chillon_-_Septembre_2020.jpg?width=800"},
  {"n":"Aigle Castle & Wine Museum","la":46.315,"lo":6.97611,"e":430,"co":"CH","region":"Vaud / Lake Geneva","cat":"castle-fortress","themes":["historic","architecture","food-drink","year-round","car-accessible"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":1.5,"sc":7,"td":"Picturesque 13th-century castle rising from the Chablais vineyards south of Lake Geneva. Houses the Museum of Wine, Vine and Label; the surrounding appellation produces outstanding Chasselas and Pinot Noir.","rs":"Compact and photogenic castle-in-vineyard ensemble at the gateway to Valais; ideal for pairing with Lavaux as part of a Vaud wine-route day, with easy rail and road access.","wl":"en","wt":"Aigle Castle","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Ch%C3%A2teau_d%27Aigle_2022_%282%29.jpg?width=800"},
  {"n":"Glacier 3000 / Diablerets Peak Walk","la":46.32722,"lo":7.2025,"e":2971,"co":"CH","region":"Vaud / Lake Geneva","cat":"glacier","themes":["panoramic-view","photogenic","cable-car","year-round","winter-sport","family-friendly"],"access":["car","cable-car"],"season":["spring","summer","autumn","winter"],"dur":4,"sc":8,"td":"Year-round glacier atop Les Diablerets at 2,971 m, featuring the Peak Walk by Tissot — world's first suspension bridge linking two mountain summits. Dog sledding, a snow bus and glacier hikes complete the offer.","rs":"Vaud's only accessible year-round glacier; the Peak Walk bridge and diverse all-season activities give it a strong independent identity distinct from larger Valais glacier destinations.","wl":"en","wt":"Glacier 3000","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Glacier3000.jpg?width=800"},
  {"n":"Lausanne Cathedral (Notre-Dame)","la":46.5225,"lo":6.63556,"e":495,"co":"CH","region":"Vaud / Lake Geneva","cat":"monastery-church","themes":["historic","architecture","year-round","panoramic-view"],"access":["train","funicular","foot"],"season":["spring","summer","autumn","winter"],"dur":1.5,"sc":8,"td":"Finest Gothic cathedral in Switzerland, consecrated 1275. Intricate polychrome rose window, richly painted medieval nave, and Europe's last active 'nightwatch' crier — calling the hours from the tower since 1405.","rs":"Architectural masterpiece of Swiss Gothic on the old-town heights; the active medieval nightwatch tradition and position above Lausanne's roofscape make it uniquely compelling.","wl":"en","wt":"Lausanne Cathedral","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Lausanne-cathe7.JPG?width=800"},
  {"n":"Olympic Museum, Lausanne","la":46.50861,"lo":6.63389,"e":null,"co":"CH","region":"Vaud / Lake Geneva","cat":"museum-cultural","themes":["family-friendly","year-round","iconic"],"access":["train","funicular","foot"],"season":["spring","summer","autumn","winter"],"dur":2.5,"sc":8,"td":"World's foremost Olympic museum in Lausanne, the IOC's official headquarters city. Over 10,000 artefacts spanning every Games, interactive galleries, torch relay exhibits, and a sculpture park terrace over Lake Geneva.","rs":"Lausanne is the Olympic Capital; this landmark lakeshore museum is essential for sports fans and families, and offers one of the finest terrace views over Lake Geneva.","wl":"en","wt":"Olympic Museum","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Losanna%2C_museo_olimpico%2C_ext..JPG?width=800"},
  {"n":"Avenches — Roman Amphitheatre (Aventicum)","la":46.88333,"lo":7.03333,"e":479,"co":"CH","region":"Vaud / Lake Geneva","cat":"museum-cultural","themes":["historic","architecture","year-round","car-accessible","hidden-gem"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":7,"td":"Roman capital of Helvetia (Aventicum), featuring a 16,000-seat amphitheatre, a Corinthian tower, well-preserved walls and an excellent Roman museum. Opera and concerts staged in the arena each summer.","rs":"Switzerland's most significant Roman site; the intact arena and quality museum rival Provençal equivalents and attract far fewer crowds — an underrated highlight between Geneva and Bern.","wl":"en","wt":"Avenches","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Avenches_%28Town%29.jpg?width=800"},
  {"n":"Geneva — Jet d'Eau & Old Town","la":46.20611,"lo":6.155,"e":373,"co":"CH","region":"Vaud / Lake Geneva","cat":"special-experience","themes":["iconic","year-round","car-accessible","boat-accessible","historic","photogenic","architecture"],"access":["car","train","boat","foot"],"season":["spring","summer","autumn","winter"],"dur":5,"sc":10,"td":"Switzerland's cosmopolitan capital: the 140 m Jet d'Eau fountain, St-Pierre Cathedral, Reformation Wall, and the elegant Old Town. UN European HQ, world-class dining, and Lake Geneva at its most expansive.","rs":"Switzerland's most internationally significant city; the Jet d'Eau is one of the world's great civic landmarks, anchoring a historically, diplomatically and culturally extraordinary destination.","wl":"en","wt":"Jet d'Eau","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Jet_d%27eau_de_Gen%C3%A8ve_%28swiss%29.jpg?width=800"},
  {"n":"Rochers de Naye","la":46.43194,"lo":6.97617,"e":2042,"co":"CH","region":"Vaud / Lake Geneva","cat":"mountain-summit","themes":["panoramic-view","photogenic","cogwheel-railway","family-friendly","summer-only"],"access":["cogwheel"],"season":["spring","summer","autumn"],"dur":3,"sc":8,"td":"Alpine summit at 2,042 m above Montreux reached by the scenic GoldenPass MOB cog railway. Sweeping panorama over Lake Geneva, the Bernese Alps and the Jura; home to the 'Marmots' Paradise' family attraction.","rs":"Combines a delightful cogwheel journey with spectacular Lake Geneva and Alpine vistas; the accessible summit and marmot habitat make it a top family and photography destination from Montreux.","wl":"en","wt":"Rochers de Naye","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Sumspic_Rochers_de_Naye_en_hiver.JPG?width=800"},
  {"n":"Montreux Riviera","la":46.435,"lo":6.9125,"e":372,"co":"CH","region":"Vaud / Lake Geneva","cat":"village","themes":["iconic","year-round","photogenic","food-drink","car-accessible","boat-accessible","panoramic-view"],"access":["car","train","boat"],"season":["spring","summer","autumn","winter"],"dur":4,"sc":9,"td":"Belle Époque lakeside resort renowned for its Jazz Festival, floral promenade, Freddie Mercury statue and palm-tree microclimate. Dents du Midi and Chillon Castle frame spectacular Lake Geneva views.","rs":"Switzerland's most glamorous lakeside resort; the legendary Jazz Festival, grand hotels and immediate proximity to Chillon and Lavaux make it an extremely high-value route hub.","wl":"en","wt":"Montreux","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Montreux_%28Svizzera%29_Panoramica_del_centro_della_citt%C3%A0_dal_lago.jpg?width=800"},
  {"n":"Lavaux Vineyard Terraces","la":46.49194,"lo":6.74611,"e":null,"co":"CH","region":"Vaud / Lake Geneva","cat":"wine-region","themes":["unesco","photogenic","iconic","historic","food-drink","year-round","car-accessible","boat-accessible","panoramic-view"],"access":["train","car","boat","foot"],"season":["spring","summer","autumn","winter"],"dur":4,"sc":9,"td":"UNESCO-listed terraced vineyards between Lausanne and Montreux, cultivated since the 12th century. Villages of Lutry, Rivaz, Épesses and Saint-Saphorin cling to steep hillsides above sparkling Lake Geneva.","rs":"UNESCO wine landscape of exceptional beauty; medieval terraces, golden Chasselas vines, lake reflections and boat-accessible wine villages define the most scenic stretch of Lake Geneva's north shore.","wl":"en","wt":"Lavaux","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Lavaux_Switzerland.jpg?width=800"},
  {"n":"Gruyères Village & Castle","la":46.58333,"lo":7.08333,"e":829,"co":"CH","region":"Fribourg","cat":"old-town","themes":["iconic","historic","architecture","food-drink","family-friendly","year-round","car-accessible","photogenic"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":3.5,"sc":9,"td":"Perfectly preserved 13th-century hilltop village in the Fribourg pre-Alps, crowned by a medieval castle with mountain panoramas. Famous for Gruyère cheese fondue, double-cream desserts and the HR Giger Museum.","rs":"Switzerland's most visited medieval village ensemble; the intact single cobbled street, castle, cheese culture and the unexpected Giger Museum give it unmatched variety for a small site.","wl":"en","wt":"Gruyères","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Gruy%C3%A8res_et_sa_cit%C3%A9_m%C3%A9di%C3%A9vale.jpg?width=800"},
  {"n":"Murten / Morat — Medieval Walled Town","la":46.91667,"lo":7.11667,"e":450,"co":"CH","region":"Fribourg","cat":"old-town","themes":["historic","architecture","year-round","car-accessible","boat-accessible","swimmable"],"access":["car","train","boat"],"season":["spring","summer","autumn","winter"],"dur":2.5,"sc":7,"td":"Switzerland's best-preserved complete medieval town wall, with an intact 13th-century covered walkway and arcaded streets. Bilingual (German/French) town; lakeside beaches, boat links to Neuchâtel and Biel.","rs":"Unique example of an entirely intact medieval enceinte; the bilingual heritage, lakeside setting and summer swimming make it a relaxed and authentic stop off the main tourist trail.","wl":"en","wt":"Murten","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Stadt-murten.jpg?width=800"},
  {"n":"Creux du Van — Jura Rocky Cirque","la":46.9325,"lo":6.72361,"e":1463,"co":"CH","region":"Jura / Neuchâtel","cat":"geology-cave","themes":["panoramic-view","photogenic","hike-required","hidden-gem"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":4,"sc":8,"td":"Natural Jurassic limestone amphitheatre 1,400 m wide and 150 m deep above the Val de Travers. Wild ibex and chamois roam the clifftops; the sunrise panorama over mist-filled valleys is legendary among hikers.","rs":"Switzerland's most dramatic natural rock feature outside the Alps; the wild ibex population, sheer cliffs and layered sunrise mist make it the Jura's single most compelling natural destination.","wl":"en","wt":"Creux du Van","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Creux_du_Van.jpg?width=800"},
  {"n":"La Chaux-de-Fonds — UNESCO Watchmaking City","la":47.10278,"lo":6.83,"e":1000,"co":"CH","region":"Jura / Neuchâtel","cat":"museum-cultural","themes":["unesco","historic","architecture","special-experience","year-round","car-accessible"],"access":["car","train"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":7,"td":"UNESCO-listed watchmaking city at 1,000 m, rebuilt on a rational grid plan after an 1794 fire to optimise natural light for watchmakers. Birthplace of Le Corbusier; International Watchmaking Museum spans 3,000 years.","rs":"UNESCO inscription recognises a unique industrial urban landscape shaped entirely by one craft; the watchmaking museum and Le Corbusier birthplace attract architecture and horology enthusiasts worldwide.","wl":"en","wt":"La Chaux-de-Fonds","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/La_Chaux_de_Fonds.jpg?width=800"},
  {"n":"Neuchâtel — Old Town & Lake","la":47,"lo":6.93333,"e":430,"co":"CH","region":"Jura / Neuchâtel","cat":"old-town","themes":["historic","architecture","year-round","car-accessible","boat-accessible","swimmable","panoramic-view"],"access":["car","train","boat"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":7,"td":"Elegant golden-sandstone university town on the shores of Switzerland's largest entirely Swiss lake. Medieval castle-collegiate church ensemble above the old town, lively market streets and a grand lakeside promenade.","rs":"Underrated architectural gem; the warm sandstone townscape, château-church silhouette and crowd-free lakeside promenade offer a refined Romand experience far less visited than Lausanne or Geneva.","wl":"en","wt":"Neuchâtel","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Vuevilledeneuchatel.jpg?width=800"},
  {"n":"Vallée de Joux — Watchmaking Valley","la":46.58333,"lo":6.21667,"e":1004,"co":"CH","region":"Jura / Neuchâtel","cat":"special-experience","themes":["hidden-gem","historic","food-drink","year-round","car-accessible","winter-sport","swimmable"],"access":["car","train"],"season":["spring","summer","autumn","winter"],"dur":4,"sc":7,"td":"Secluded Jura valley at 1,000 m, spiritual birthplace of Swiss haute horlogerie and home to Audemars Piguet and Vallée de Joux. Scenic Lac de Joux, cross-country skiing in winter, and the AP Watch Museum in Le Brassus.","rs":"The spiritual home of Swiss fine watchmaking; the valley's scenic isolation, Lac de Joux and the world-class Audemars Piguet museum make it a unique cultural destination for discerning travellers.","wl":"en","wt":"Vallée de Joux","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Vallee_de_joux.jpg?width=800"},
  {"n":"Emmentaler Schaukäserei (Affoltern)","la":47.05,"lo":7.717,"e":801,"co":"CH","region":"Bern / Emmental","cat":"museum-cultural","themes":["food-drink","family-friendly","year-round","car-accessible","historic"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":7,"td":"Switzerland's showcase Emmental dairy in Affoltern im Emmental, where you can watch traditional Emmentaler AOP cheese being made in a historic farmstead. Hands-on tours, tasting, and restaurant serving authentic Bernese specialities.","rs":"Best place in Switzerland to witness authentic large-wheel Emmentaler cheese production; emblematic of Bernese food culture and agritourism.","wl":"en","wt":"Affoltern im Emmental","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Schaukaeserei_Affoltern_04_09.jpg?width=800"},
  {"n":"Old City of Bern","la":46.94806,"lo":7.45028,"e":542,"co":"CH","region":"Bern / Emmental","cat":"old-town","themes":["unesco","iconic","historic","architecture","year-round","car-accessible","food-drink","family-friendly"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":4.5,"sc":10,"td":"Switzerland's UNESCO-listed medieval capital (1983) on a dramatic Aare loop. Six km of arcaded sandstone laubengänge, the 14th-c. Zytglogge clock tower, Rose Garden panorama, Bear Park, Federal Palace and Bern Minster cathedral.","rs":"Switzerland's political capital and UNESCO World Heritage old town; unparalleled ensemble of medieval arcades, fountains and civic architecture.","wl":"en","wt":"Old City (Bern)","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Bern_luftaufnahme.png?width=800"},
  {"n":"Solothurn Old Town","la":47.20833,"lo":7.53722,"e":432,"co":"CH","region":"Bern / Emmental","cat":"old-town","themes":["historic","architecture","year-round","car-accessible","hidden-gem","boat-accessible"],"access":["car","train","foot","boat"],"season":["spring","summer","autumn","winter"],"dur":2.5,"sc":8,"td":"Widely called Switzerland's most beautiful baroque town, Solothurn holds 11 churches, 11 towers, 11 fountains and an obsession with the number 11 unique in Europe. The Italian-style St Ursen Cathedral presides over a compact, walkable Altstadt.","rs":"Best-kept secret in western Switzerland; the baroque old town rivals anything in Bern or Basel in quality but receives a fraction of the visitors.","wl":"en","wt":"Solothurn","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Solothurn_2023.jpg?width=800"},
  {"n":"St. Peter's Island (Petersinsel)","la":47.07083,"lo":7.1425,"e":474,"co":"CH","region":"Bern / Emmental","cat":"special-experience","themes":["historic","hidden-gem","boat-accessible","swimmable","photogenic","food-drink"],"access":["boat","foot"],"season":["spring","summer","autumn"],"dur":3,"sc":8,"td":"Peaceful peninsula on Lake Biel where Jean-Jacques Rousseau spent five blissful weeks in 1765, calling it the happiest time of his life. A Cluniac monastery turned inn, oak forests, vine terraces and quiet lakeside swimming beaches.","rs":"Rousseau's 'favourite place in the world'; a genuine escape from tourism accessed only by boat, with extraordinary literary and natural heritage.","wl":"en","wt":"Saint Peter's Island","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Twann_am_Bielersee_mit_Petersinsel.jpg?width=800"},
  {"n":"Gurten","la":46.91722,"lo":7.44361,"e":858,"co":"CH","region":"Bern / Emmental","cat":"viewpoint-panorama","themes":["panoramic-view","year-round","family-friendly","winter-sport","photogenic"],"access":["funicular","train","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":7,"td":"Bern's beloved local mountain at 858 m, reached by tram and funicular in 20 minutes from the city centre. Panorama spans the Jura, city of Bern and the full arc of the Bernese Alps. Hosts the annual Gurtenfestival music event.","rs":"Bern's closest panoramic viewpoint; easily combined with a city visit and offers one of the best foreground-city-plus-Alps compositions in Switzerland.","wl":"en","wt":"Gurten (mountain)","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Gurten_4734.jpg?width=800"},
  {"n":"Hallwyl Castle (Wasserschloss)","la":47.32319,"lo":8.19417,"e":450,"co":"CH","region":"Basel / Aargau","cat":"castle-fortress","themes":["historic","architecture","year-round","car-accessible","family-friendly","photogenic"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":8,"td":"One of Switzerland's most important moated water castles, built on two islands in the Aabach river. The remarkably intact complex (first mentioned 1256) with drawbridge, towers and richly furnished rooms is owned by the Canton of Aargau.","rs":"Switzerland's finest Wasserschloss; the two-island setting, intact medieval fabric and excellent museum put it above most Alpine castles for atmosphere.","wl":"en","wt":"Hallwyl Castle","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Schloss_Hallwyl_July_21st_2005.jpg?width=800"},
  {"n":"Habsburg Castle","la":47.46274,"lo":8.18104,"e":488,"co":"CH","region":"Basel / Aargau","cat":"castle-fortress","themes":["historic","year-round","car-accessible","hike-required"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":1.5,"sc":7,"td":"Ancestral seat of the House of Habsburg, built c.1020–30 on the Wülpelsberg in Aargau. The partly-restored west wing and atmospheric ruins offer panoramic views; this hilltop castle gave its name to a 600-year European dynasty.","rs":"Birthplace of the Habsburg dynasty that shaped European history for 600 years; compact, car-accessible and historically weighty.","wl":"en","wt":"Habsburg Castle","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Habsburg_%28Aargau%2C_Switzerland%29.jpg?width=800"},
  {"n":"Lenzburg Castle","la":47.38738,"lo":8.18548,"e":508,"co":"CH","region":"Basel / Aargau","cat":"castle-fortress","themes":["historic","architecture","year-round","car-accessible","family-friendly"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":7,"td":"One of Switzerland's largest and best-preserved hilltop castles (pre-1036), rising 100 m above Lenzburg on an almost perfectly circular hill. Home to a comprehensive historical museum; the hill also contains Neolithic burial grounds.","rs":"Major Aargau castle with 1,000-year history, richly furnished museum rooms, and neolithic context — all within 30 min of Basel and Zurich.","wl":"en","wt":"Lenzburg Castle","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Schloss_Lenzburg_-_Gesamtansicht1.jpg?width=800"},
  {"n":"Basel Minster & Altstadt","la":47.55667,"lo":7.59222,"e":260,"co":"CH","region":"Basel / Aargau","cat":"monastery-church","themes":["historic","architecture","year-round","car-accessible","panoramic-view","photogenic"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":2.5,"sc":8,"td":"Basel's red sandstone Minster (built 1019–1500) crowns a Rhine terrace with sweeping river views. The surrounding old town shelters world-class art museums (Kunstmuseum, Tinguely), the historic Rhine ferries and vibrant market squares.","rs":"Basel's defining landmark; the Minster terrace gives the finest view of the Rhine bend in all of northern Switzerland, and the art scene is unmatched.","wl":"en","wt":"Basel Minster","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Basler_-_Basler_M%C3%BCnster_Westfassade.jpg?width=800"},
  {"n":"Augusta Raurica","la":47.53389,"lo":7.72139,"e":270,"co":"CH","region":"Basel / Aargau","cat":"museum-cultural","themes":["historic","family-friendly","year-round","car-accessible","architecture"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":2.5,"sc":8,"td":"Switzerland's best-preserved Roman archaeological site, founded ~44 BC. The open-air museum at Augst features a 10,000-seat theatre, temples, forum and an exceptional silver treasure. The oldest known Roman colony on the Rhine.","rs":"Finest Roman ruins in Switzerland; authentic outdoor museum atmosphere with excavated streets, theatre and treasure house make it deeply educational.","wl":"en","wt":"Augusta Raurica","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Augusta_Raurica_-_Theater2.jpg?width=800"},
  {"n":"Rapperswil Castle & Old Town","la":47.22734,"lo":8.81551,"e":416,"co":"CH","region":"Zürich","cat":"castle-fortress","themes":["historic","architecture","boat-accessible","car-accessible","year-round","photogenic","family-friendly"],"access":["car","train","boat"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":8,"td":"The 'Town of Roses' perches on a peninsula on Lake Zurich. Its 13th-century castle (housing the Polish National Museum since 1870), Capuchin monastery, famous rose garden with 15,000 roses and medieval old town draw day-trippers from Zurich.","rs":"Best castle-and-old-town combination on Lake Zurich; year-round boat access, rose spectacle in June and strong historical depth.","wl":"en","wt":"Schloss Rapperswil","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Rapperswil_-_Hafen_-_Schloss-Pfarrkirche_-_Seedamm_2014-09-23_15-20-02.JPG?width=800"},
  {"n":"Lindt Home of Chocolate","la":47.3184,"lo":8.551,"e":430,"co":"CH","region":"Zürich","cat":"museum-cultural","themes":["family-friendly","food-drink","year-round","car-accessible","boat-accessible","iconic"],"access":["car","train","boat"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":8,"td":"Award-winning chocolate museum in Kilchberg (opened 2020) built beside the Lindt & Sprüngli factory on Lake Zurich. Centrepiece is the world's tallest free-standing chocolate fountain (9 m). Attracts 800,000 visitors per year.","rs":"Switzerland's most-visited new museum; unique combination of industrial heritage, food culture and architecturally striking building on the lake shore.","wl":"en","wt":"Lindt Home of Chocolate","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Two_story_chocolate_fountain_in_the_lobby_of_the_Lindt_factory_in_Zurich%2C_Switzerland_%2852167915483%29.jpg?width=800"},
  {"n":"Zürich Old Town & Grossmünster","la":47.37014,"lo":8.54399,"e":408,"co":"CH","region":"Zürich","cat":"old-town","themes":["iconic","historic","architecture","year-round","car-accessible","boat-accessible","food-drink","family-friendly"],"access":["car","train","foot","boat"],"season":["spring","summer","autumn","winter"],"dur":5,"sc":10,"td":"Switzerland's largest city straddles the Limmat. Key sights: Romanesque Grossmünster (c.1100), Gothic Fraumünster with Chagall windows, arcaded Niederdorf lanes, Lindenhof hill and lake promenades. World-class museums and dining.","rs":"Switzerland's cultural and financial capital; the Altstadt concentrates an extraordinary density of religious, civic and artistic heritage.","wl":"en","wt":"Grossmünster","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Grossm%C3%BCnster_-_M%C3%BCnsterhof_2014-05-23_12-08-43.JPG?width=800"},
  {"n":"Uetliberg","la":47.34944,"lo":8.49139,"e":870,"co":"CH","region":"Zürich","cat":"viewpoint-panorama","themes":["panoramic-view","year-round","family-friendly","car-accessible","winter-sport","photogenic"],"access":["train","foot","car"],"season":["spring","summer","autumn","winter"],"dur":2.5,"sc":8,"td":"Zürich's 'local mountain' at 870 m, reached in 25 min by direct train from Zürich HB (S10 line). A 25 m viewing tower offers panoramas over the city, Lake Zurich and the Alps. Winter sledging, summer hiking and the Planet Trail.","rs":"Zürich's signature viewpoint: unmatched panorama over city and lake, accessible in minutes by train — a must-do prologue to any Zürich visit.","wl":"en","wt":"Uetliberg","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Uetliberg_-_Wollishofen_-_Z%C3%BCrichhorn_2012-09-27_16-15-12.JPG?width=800"},
  {"n":"Klöntalersee","la":47.02556,"lo":8.98056,"e":848,"co":"CH","region":"Eastern Switzerland","cat":"alpine-lake","themes":["hidden-gem","photogenic","swimmable","car-accessible","year-round","family-friendly"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":7,"td":"Remote glacial valley lake in Canton Glarus at 848 m, formed by an ancient rockslide. Crystal-clear water, reflection of the Glarus Alps and a quiet lakeshore trail make it a perfect scenic detour from the busy tourist trail.","rs":"One of Eastern Switzerland's finest alpine lakes; easily driven to yet largely unknown outside regional visitors — an ideal hidden-gem stop.","wl":"en","wt":"Klöntalersee","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Glarus_Kloentalersee.jpg?width=800"},
  {"n":"Schaffhausen & Munot Fortress","la":47.69694,"lo":8.63972,"e":433,"co":"CH","region":"Eastern Switzerland","cat":"castle-fortress","themes":["historic","architecture","year-round","car-accessible","panoramic-view","photogenic"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":2.5,"sc":7,"td":"Schaffhausen's circular Munot fortress (1564–89) towers over the Rhine and a sea of vineyards. The city boasts Switzerland's densest concentration of oriel windows and elaborate Renaissance frescoes on its guild houses.","rs":"The Munot is a unique circular Renaissance fortress; Schaffhausen's old town rivals Stein am Rhein in architectural richness and is far less crowded.","wl":"en","wt":"Munot","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Festung_Munot_mit_dem_Rhein.jpg?width=800"},
  {"n":"Tamina Gorge (Taminaschlucht)","la":46.98137,"lo":9.48843,"e":680,"co":"CH","region":"Eastern Switzerland","cat":"waterfall-gorge","themes":["historic","hike-required","car-accessible","spa-wellness","photogenic"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":8,"td":"A narrow limestone slot canyon carved 200 m deep by the Tamina river near Bad Ragaz. A 750 m-long footpath leads through the gorge to the medieval Altes Bad Pfäfers thermal spa, once described as unrivalled in the Swiss Alps.","rs":"Unique natural gorge with medieval thermal-spa history; geologist Albert Heim declared it unmatched in the Swiss Alps for grandeur.","wl":"de","wt":"Taminaschlucht","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Taminaschlucht.jpg?width=800"},
  {"n":"Abbey of Saint Gall","la":47.42306,"lo":9.37722,"e":670,"co":"CH","region":"Eastern Switzerland","cat":"monastery-church","themes":["unesco","historic","architecture","year-round","car-accessible","iconic"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":10,"td":"UNESCO World Heritage baroque abbey complex (1983) in St Gallen. Founded in the 7th century by Irish monk St Gall, its library holds over 170,000 volumes including priceless Carolingian illuminated manuscripts.","rs":"One of the best-preserved examples of a Carolingian monastery in Europe; UNESCO site and home to one of the world's oldest and richest libraries.","wl":"en","wt":"Abbey of Saint Gall","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/StGallen_asv2022-10_F%C3%BCrstabtei_img1.jpg?width=800"},
  {"n":"Säntis","la":47.24937,"lo":9.34331,"e":2502,"co":"CH","region":"Eastern Switzerland","cat":"mountain-summit","themes":["cable-car","panoramic-view","iconic","year-round","winter-sport","photogenic"],"access":["cable-car","foot"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":9,"td":"Highest peak of NE Switzerland at 2,502 m, accessible by cable car from Schwägalp. Sweeping 360° panorama spanning the Alps, Lake Constance and Black Forest. Meteorological station, restaurant and winter ski slopes on summit.","rs":"Most prominent summit in Eastern Switzerland (prominence 2,021 m); cable car makes it an iconic, accessible year-round destination.","wl":"en","wt":"Säntis","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/S%C3%A4ntis_mountain_by_sunset.jpg?width=800"},
  {"n":"Stein am Rhein","la":47.667,"lo":8.85,"e":401,"co":"CH","region":"Eastern Switzerland","cat":"old-town","themes":["historic","architecture","photogenic","year-round","car-accessible","boat-accessible"],"access":["car","train","boat"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":8,"td":"One of Switzerland's finest preserved medieval towns: a riverside streetscape of half-timbered houses with elaborate fresco murals. Benedictine St George's Abbey and hilltop Hohenklingen Castle complete the scene.","rs":"Outstanding ensemble of intact medieval frescoed townhouses on the Rhine; recipient of the prestigious Prix Wakker conservation award.","wl":"en","wt":"Stein am Rhein","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Stein_am_Rhein_mit_Kloster_St._Georgen_und_Burg_Hohenklingen-20111009.jpg?width=800"},
  {"n":"Ebenalp & Berggasthaus Äscher","la":47.28417,"lo":9.41083,"e":1640,"co":"CH","region":"Eastern Switzerland","cat":"special-experience","themes":["cable-car","photogenic","iconic","hike-required","food-drink"],"access":["cable-car","train","foot"],"season":["spring","summer","autumn"],"dur":4,"sc":9,"td":"The Berggasthaus Äscher cliff inn (1,454 m) is embedded dramatically in a limestone overhang — one of the world's most-shared mountain images. Cable car from Wasserauen, hike through prehistoric Wildkirchli caves to reach it.","rs":"Globally viral image of a restaurant built into a cliff face; combines accessible cable car, cave archaeology and iconic alpine food.","wl":"en","wt":"Ebenalp","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Luftbild_Ebenalp.jpg?width=800"},
  {"n":"Appenzell","la":47.33111,"lo":9.41139,"e":800,"co":"CH","region":"Eastern Switzerland","cat":"village","themes":["historic","architecture","food-drink","family-friendly","year-round","photogenic","car-accessible"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":2.5,"sc":8,"td":"Charming capital of Appenzell Innerrhoden with elaborately painted facades, traditional embroidery, Appenzeller cheese and Biber gingerbread. Gateway to the Alpstein; hosts Switzerland's last open-air Landsgemeinde democracy.","rs":"Most distinctive traditional village in NE Switzerland; living folk architecture, unique dairy food culture and direct access to Alpstein hiking.","wl":"en","wt":"Appenzell (village)","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Adlerplatz_in_Appenzell_%282017%29.jpg?width=800"},
  {"n":"Rhine Falls (Rheinfall)","la":47.67722,"lo":8.61583,"e":364,"co":"CH","region":"Eastern Switzerland","cat":"waterfall-gorge","themes":["iconic","family-friendly","year-round","boat-accessible","car-accessible","photogenic"],"access":["car","train","boat"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":10,"td":"Europe's most powerful waterfall — 150 m wide, 23 m high, with up to 600 m³/s flow. Boat trips to the central rock, viewpoints on both Rhine banks and nearby Laufen Castle make this a quintessential Swiss attraction.","rs":"Most powerful waterfall in Europe by flow rate; supremely accessible and dramatic, it features on virtually every Switzerland travel itinerary.","wl":"en","wt":"Rhine Falls","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/SBB_RABe_514_DTZ_Rheinfall.jpg?width=800"},
  {"n":"Seerenbach Falls & Walensee","la":47.1414,"lo":9.1597,"e":422,"co":"CH","region":"Eastern Switzerland","cat":"waterfall-gorge","themes":["hidden-gem","photogenic","boat-accessible","hike-required","summer-only"],"access":["boat","foot"],"season":["spring","summer","autumn"],"dur":4,"sc":8,"td":"Three dramatic cascades (50 m, 305 m, 190 m) plunge into Lake Walen on the road-less southern shore. Reached by ferry from Weesen or by foot from Quinten — one of Switzerland's most spectacular waterfall trios.","rs":"Switzerland's longest triple waterfall system; the inaccessible south shore of Walensee creates a genuine off-the-beaten-path experience.","wl":"en","wt":"Seerenbach Falls","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Seerenbachfall_III_und_Rinquelle_bei_Amden_SG.jpg?width=800"},
  {"n":"Caumasee (Lake Cauma)","la":46.82028,"lo":9.29583,"e":997,"co":"CH","region":"Graubünden","cat":"alpine-lake","themes":["swimmable","photogenic","family-friendly","car-accessible","hidden-gem"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":8,"td":"Jewel-blue forest lake at 997 m near Flims, sitting atop Europe's largest prehistoric rockslide. Fed by underground springs; water reaches 21 °C in summer. Enclosed by pines; no motor boats; beloved wild-swimming destination.","rs":"Uniquely turquoise lake formed on the Flims Rockslide debris; one of Switzerland's finest natural swimming lakes; secluded forest setting near Flims-Laax.","wl":"en","wt":"Caumasee","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Caumasee_Sommer08.jpg?width=800"},
  {"n":"Landwasser Viaduct","la":46.68083,"lo":9.67583,"e":900,"co":"CH","region":"Graubünden","cat":"bridge-engineering","themes":["unesco","photogenic","iconic","architecture","year-round"],"access":["train","car","foot"],"season":["spring","summer","autumn","winter"],"dur":1,"sc":10,"td":"Towering 65 m over the Landwasser gorge, this 1902 limestone railway viaduct curves directly into a cliff-face tunnel — symbol of the UNESCO Albula line and one of the world's most photographed railway structures.","rs":"Defining structure of the UNESCO-listed Albula Railway; exemplifies Swiss mountain railway engineering at its peak; instantly recognisable globally.","wl":"en","wt":"Landwasser Viaduct","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/RhB_Ge_4-4_III_UNESCO_Weltkulturerbe_auf_Landwasserviadukt.jpg?width=800"},
  {"n":"Salginatobel Bridge","la":46.98182,"lo":9.71773,"e":644,"co":"CH","region":"Graubünden","cat":"bridge-engineering","themes":["architecture","hidden-gem","historic"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":1,"sc":7,"td":"Slender 90 m reinforced-concrete arch bridge (1930) by Robert Maillart across the Salgina ravine near Schiers. An ASCE International Historic Civil Engineering Landmark; celebrated for structural efficiency and radical minimalism.","rs":"Masterwork of Robert Maillart; first concrete bridge declared an ASCE International Historic Civil Engineering Landmark; pilgrimage site for architects and engineers.","wl":"en","wt":"Salginatobel Bridge","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Salginatobel_Bridge_mg_4080.jpg?width=800"},
  {"n":"Swiss Tectonic Arena Sardona","la":46.917,"lo":9.25,"e":2849,"co":"CH","region":"Graubünden","cat":"geology-cave","themes":["unesco","hike-required","panoramic-view","summer-only","photogenic"],"access":["car","foot"],"season":["summer"],"dur":4,"sc":7,"td":"UNESCO natural World Heritage (2008) exposing the Glarus Overthrust — 250 Ma Verrucano visibly stacked on top of 35 Ma Flysch. The Tschingelhörner's Martinsloch (a 6×18 m rock window) frames a sunrise twice a year.","rs":"First geological thrust fault designated UNESCO Natural World Heritage; Martinsloch sunrise event is unique in the Alps; superb alpine tectonic trails in St Gallen–Graubünden border zone.","wl":"en","wt":"Glarus thrust","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Glarus_Thrust_Fault_in_Switzerland_2018.jpg?width=800"},
  {"n":"Saint John Abbey, Müstair","la":46.62917,"lo":10.44778,"e":1273,"co":"CH","region":"Graubünden","cat":"monastery-church","themes":["unesco","historic","architecture","year-round"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":9,"td":"Carolingian Benedictine convent in remote Val Müstair, founded c. 775 by Charlemagne. Its 9th-century frescoes are the finest cycle of Carolingian wall painting in existence. UNESCO World Heritage since 1983; still active convent.","rs":"Only Swiss UNESCO cultural site dedicated to early medieval art; finest Carolingian fresco cycle in the world; extraordinarily complete survival from the 8th–9th century.","wl":"en","wt":"Saint John Abbey, Müstair","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Benediktinerkloster_St._Johann.JPG?width=800"},
  {"n":"Albula Railway","la":46.6244,"lo":9.7444,"e":1815,"co":"CH","region":"Graubünden","cat":"scenic-railway","themes":["unesco","photogenic","iconic","year-round","panoramic-view"],"access":["train"],"season":["spring","summer","autumn","winter"],"dur":3.5,"sc":9,"td":"62 km UNESCO narrow-gauge railway climbing from Thusis to St Moritz through 55 tunnels, 196 bridges and the famous Landwasser Viaduct. Spiral loops and helicoidal tunnels conquer 1600 m of altitude difference.","rs":"One of Europe's most technically ambitious mountain railways; UNESCO World Heritage since 2008; includes the Landwasser Viaduct and engineering marvels near Bergün.","wl":"en","wt":"Albula railway line","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Albulabahn.jpg?width=800"},
  {"n":"Soglio","la":46.33333,"lo":9.53333,"e":1090,"co":"CH","region":"Graubünden","cat":"village","themes":["hidden-gem","historic","photogenic","car-accessible"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":8,"td":"Clifftop Bregaglia hamlet at 1090 m framed by chestnut forests and the jagged Bondasca peaks (Piz Badile, Sciora). Palazzo Salis gardens bloom with rhododendrons in June; revered by Segantini, Rilke, and Giacometti.","rs":"Most dramatically situated village in the Bregaglia valley; historic patrician Palazzo Salis; sweeping view to Piz Badile; beloved by artists; hidden gem of southern Graubünden.","wl":"en","wt":"Soglio, Switzerland","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Soglio_-_panoramio.jpg?width=800"},
  {"n":"Ruinaulta (Rhine Gorge)","la":46.80814,"lo":9.31495,"co":"CH","region":"Graubünden","cat":"waterfall-gorge","themes":["photogenic","panoramic-view","hike-required","unesco","car-accessible"],"access":["train","car","foot"],"season":["spring","summer","autumn"],"dur":3,"sc":9,"td":"Switzerland's 'Grand Canyon': a 14 km limestone gorge carved by the Anterior Rhine through the Flims Rockslide debris. White cliffs up to 350 m high; navigable by raft in summer; accessible by train along the gorge floor.","rs":"Most dramatic canyon in Switzerland; part of UNESCO Tectonic Arena Sardona; best experienced by white-water raft, gorge-floor trail, or scenic Rhaetian Railway.","wl":"en","wt":"Ruinaulta","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Il_Spir_panorama_20210614.jpg?width=800"},
  {"n":"Lake Sils","la":46.41667,"lo":9.73083,"e":1797,"co":"CH","region":"Engadin","cat":"alpine-lake","themes":["photogenic","panoramic-view","swimmable","year-round","car-accessible","iconic"],"access":["train","car","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":8,"td":"Windswept upper Engadin lake at 1797 m where Nietzsche wrote 'Thus Spoke Zarathustra'. Famous for summer kitesurfers, wild swimming, and a frozen shoreline in winter; backed by the Maloja wind gap and glaciated peaks.","rs":"Iconic Engadin lake with Nietzsche heritage; superb mountain backdrop; swimmable in summer, walkable frozen in winter; source of the Maloja wind phenomenon.","wl":"en","wt":"Lake Sils","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Lej_da_Segl.jpg?width=800"},
  {"n":"Tarasp Castle","la":46.77889,"lo":10.26167,"e":1499,"co":"CH","region":"Engadin","cat":"castle-fortress","themes":["historic","architecture","photogenic","car-accessible"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":8,"td":"Medieval hill castle rising dramatically from a rocky outcrop above the Lower Engadin Inn valley. Founded in the 11th century and lavishly restored 1907–16 by Dresden soap magnate Karl August Lingner. Guided tours in summer.","rs":"Finest medieval castle in Graubünden; dramatic rocky perch 200 m above the valley; Swiss cultural heritage site of national significance; Lower Engadin landmark.","wl":"en","wt":"Tarasp Castle","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/160618_Schloss_Tarasp_3.jpg?width=800"},
  {"n":"Morteratsch Glacier","la":46.40944,"lo":9.93167,"co":"CH","region":"Engadin","cat":"glacier","themes":["photogenic","hike-required","iconic","panoramic-view","summer-only"],"access":["train","foot"],"season":["spring","summer","autumn"],"dur":2.5,"sc":9,"td":"Largest glacier in the Bernina Range, reached by a 1.3 km level trail from Morteratsch station (1896 m). Annual marker poles document its dramatic 3+ km retreat since 1878; backed by the soaring Piz Bernina massif.","rs":"Third-largest glacier in the Eastern Alps; most vivid visual demonstration of climate change in Switzerland; easy train-to-trail access makes it accessible to all.","wl":"en","wt":"Morteratsch Glacier","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Morteratsch-_und_Persgletscher.jpg?width=800"},
  {"n":"Piz Nair","la":46.50625,"lo":9.78744,"e":3056,"co":"CH","region":"Engadin","cat":"mountain-summit","themes":["panoramic-view","cable-car","winter-sport","photogenic","iconic"],"access":["funicular","cable-car"],"season":["spring","summer","winter"],"dur":2,"sc":8,"td":"3056 m summit above St Moritz reached by funicular to Corviglia then cable car. Outstanding 360° panorama of the Upper Engadin lake chain; hosted 1948 Winter Olympics alpine events and four FIS World Championships.","rs":"Highest cable-car accessible summit above St Moritz; iconic Engadin panorama over five lakes and the Bernina massif; world-class ski racing heritage.","wl":"en","wt":"Piz Nair","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Piz-Nair.jpg?width=800"},
  {"n":"Swiss National Park","la":46.667,"lo":10.2,"co":"CH","region":"Engadin","cat":"national-park","themes":["year-round","hike-required","family-friendly","panoramic-view","iconic"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":5,"sc":9,"td":"Oldest national park in the Alps (est. 1914), covering 170 km² of strictly protected wilderness in the Lower Engadin. Ibex, chamois, red deer, bearded vultures, and eagle roam freely; 21 waymarked trails; visitor centre in Zernez.","rs":"Switzerland's only national park and oldest in central Europe; IUCN Category Ia; UNESCO Biosphere Reserve; exemplary rewilded alpine ecosystem.","wl":"en","wt":"Swiss National Park","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Swiss_National_Park_002.JPG?width=800"},
  {"n":"St. Moritz","la":46.49722,"lo":9.83778,"e":1822,"co":"CH","region":"Engadin","cat":"village","themes":["iconic","winter-sport","year-round","food-drink","panoramic-view"],"access":["train","car"],"season":["spring","summer","autumn","winter"],"dur":4,"sc":9,"td":"Glamorous Upper Engadin resort at 1822 m, twice Winter Olympics host (1928 & 1948) and self-styled 'birthplace of alpine tourism'. Famous for champagne climate, iced Cresta Run, and a glittering chain of lakes.","rs":"Switzerland's most iconic alpine resort; two Winter Olympics host; hub for Engadin lakes, high-altitude trails and world-class winter sports.","wl":"en","wt":"St. Moritz","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/StMoritz.jpg?width=800"},
  {"n":"Bernina Express","la":46.40889,"lo":10.01972,"e":2234,"co":"CH","region":"Engadin","cat":"scenic-railway","themes":["unesco","photogenic","iconic","panoramic-view","year-round"],"access":["train"],"season":["spring","summer","autumn","winter"],"dur":4,"sc":10,"td":"World's highest trans-Alpine UNESCO railway (2253 m) linking St Moritz to Tirano without rack-and-pinion. Passes turquoise Lago Bianco, Morteratsch glacier views, and descends into Mediterranean Valtellina in under 4 hours.","rs":"UNESCO World Heritage; highest altitude railway crossing of the Alps; operates year-round and combines arctic alpine and Mediterranean landscapes in one journey.","wl":"en","wt":"Bernina Express","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/RhB_ABe_4-4_III_56_and_51_Lago_Bianco.jpg?width=800"},
  {"n":"Bogn Engiadina Scuol","la":46.8,"lo":10.283,"e":1290,"co":"CH","region":"Engadin","cat":"spa-wellness","themes":["year-round","family-friendly","food-drink"],"access":["train","car"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":8,"td":"Switzerland's most celebrated alpine mineral-water spa at 1290 m in Lower Engadin, drawing on 20 natural mineral springs. Indoor-outdoor pools, Roman-Irish bathing ritual, and the medieval Romansh town of Scuol to explore.","rs":"Switzerland's premier destination spa; unique setting combining 20 mineral springs, traditional Engadin architecture, and a year-round mountain resort town.","wl":"en","wt":"Scuol","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Scuol_09.jpg?width=800"},
  {"n":"Diavolezza","la":46.41058,"lo":9.96714,"e":2973,"co":"CH","region":"Engadin","cat":"viewpoint-panorama","themes":["panoramic-view","cable-car","photogenic","winter-sport","year-round","iconic"],"access":["train","cable-car"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":9,"td":"Cable-car viewpoint at 2973 m above Val Bernina with breathtaking views of Piz Bernina (4049 m) and the Pers–Morteratsch glacier system. Classic ski terrain in winter; glacier-traverse hike in summer.","rs":"Premier panorama platform above the Upper Engadin; best glacier view in eastern Switzerland; ideal base for the famous Diavolezza–Morteratsch glacier traverse.","wl":"en","wt":"Diavolezza","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/CH_Diavolezza_Hut.jpg?width=800"},
  {"n":"Muottas Muragl","la":46.52167,"lo":9.9025,"e":2454,"co":"CH","region":"Engadin","cat":"viewpoint-panorama","themes":["panoramic-view","photogenic","year-round","family-friendly"],"access":["train","funicular"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":8,"td":"Terrace plateau at 2454 m above Samedan reached by funicular from Punt Muragl. Classic 'balcony of the Engadin' with the complete panorama of all Upper Engadin lakes, the Roseg valley, and Piz Bernina.","rs":"Definitive upper Engadin panorama viewpoint; accessible year-round by funicular; ideal family destination with restaurant, walks, and winter sledge run.","wl":"en","wt":"Muottas Muragl","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Muottas_Murag2.jpg?width=800"},
  {"n":"Guarda","la":46.7754,"lo":10.15254,"e":1653,"co":"CH","region":"Engadin","cat":"village","themes":["historic","hidden-gem","photogenic","hike-required"],"access":["train","car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":8,"td":"Beautifully preserved Engadin village at 1653 m with painted façades and sgraffito-decorated farmhouses. A Romansh cultural showcase and the childhood setting of Selina Chönz's classic 'A Bell for Ursli'. Car-free core.","rs":"Best-preserved traditional Engadin Romansh village; named Switzerland's most beautiful village; poster-perfect hillside above the Inn valley.","wl":"en","wt":"Guarda, Switzerland","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Guarda02.jpg?width=800"},
  {"n":"Ponte dei Salti, Lavertezzo","la":46.25,"lo":8.83333,"e":500,"co":"CH","region":"Ticino","cat":"bridge-engineering","themes":["photogenic","swimmable","iconic","car-accessible","summer-only"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":9,"td":"17th-century double-arched stone bridge spanning the crystal-clear emerald Verzasca river at Lavertezzo. Polished granite slabs and turquoise pools make it one of Switzerland's most photographed wild-swimming destinations.","rs":"Iconic double-arch Roman-era bridge over the translucent Verzasca; Switzerland's most famous natural swimming spot in summer; stunning turquoise-green water.","wl":"en","wt":"Lavertezzo","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Ponte_dei_Salti%2C_Lavertezzo.jpg?width=800"},
  {"n":"Castles of Bellinzona","la":46.19314,"lo":9.02242,"e":230,"co":"CH","region":"Ticino","cat":"castle-fortress","themes":["unesco","historic","architecture","photogenic","iconic","year-round","panoramic-view"],"access":["train","car","foot"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":10,"td":"Three medieval hilltop fortresses — Castelgrande, Montebello, and Sasso Corbaro — linked by curtain walls across the valley floor. UNESCO World Heritage since 2000; the most complete medieval defensive system in the Alps.","rs":"UNESCO cultural site; three complete hilltop castles in one town; Ticino's capital city; most significant medieval fortification ensemble in the Swiss Alps.","wl":"en","wt":"Castles of Bellinzona","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Castelli.JPG?width=800"},
  {"n":"Monte San Giorgio","la":45.91361,"lo":8.94972,"e":1097,"co":"CH","region":"Ticino","cat":"geology-cave","themes":["unesco","hike-required","panoramic-view","historic"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":3,"sc":9,"td":"UNESCO natural World Heritage (2003), a 1097 m forested pyramid between Lake Lugano arms. Triassic strata (240 Ma) yield the world's best Middle Triassic marine fossil record including Mixosaurus, Ceresiosaurus, and Ticinosuchus.","rs":"UNESCO natural site; premier Triassic fossil site in the world; 150-year scientific excavation record; fossil museum in Meride; serene hiking through managed forest.","wl":"en","wt":"Monte San Giorgio","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Lago_di_Lugano3.jpg?width=800"},
  {"n":"Madonna del Sasso","la":46.17528,"lo":8.79306,"e":355,"co":"CH","region":"Ticino","cat":"monastery-church","themes":["historic","photogenic","panoramic-view","iconic","year-round"],"access":["funicular","foot"],"season":["spring","summer","autumn","winter"],"dur":1.5,"sc":9,"td":"Franciscan pilgrimage sanctuary perched on a rocky promontory 170 m above Locarno since 1480. Panoramic terrace overlooks Lake Maggiore; rich collection of Renaissance paintings; reached by funicular in 3 minutes from the city.","rs":"Most visited sacred site in Ticino; landmark visible across Lake Maggiore; Renaissance art collection; funicular makes it accessible to all visitors.","wl":"en","wt":"Madonna del Sasso, Switzerland","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Madonna_del_Sasso_HDR.jpg?width=800"},
  {"n":"Monte Generoso","la":45.93125,"lo":9.02,"e":1701,"co":"CH","region":"Ticino","cat":"mountain-summit","themes":["panoramic-view","cogwheel-railway","photogenic","iconic","architecture","family-friendly"],"access":["cogwheel","foot"],"season":["spring","summer","autumn"],"dur":3,"sc":9,"td":"1701 m summit on the Swiss-Italian border above Lake Lugano reached by Europe's steepest historic cogwheel railway (1890) from Capolago. Mario Botta's 'Fiore di Pietra' flower-shaped restaurant (2017) crowns the summit.","rs":"Highest summit in the Ticino prealps; 360° panorama over four lakes; Botta's Fiore di Pietra is Switzerland's most celebrated contemporary summit building.","wl":"en","wt":"Monte Generoso","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Montegeneroso.JPG?width=800"},
  {"n":"Ascona","la":46.155,"lo":8.768,"e":196,"co":"CH","region":"Ticino","cat":"old-town","themes":["historic","photogenic","food-drink","year-round","car-accessible","panoramic-view"],"access":["car","boat","foot"],"season":["spring","summer","autumn","winter"],"dur":2.5,"sc":8,"td":"Ticino's oldest market town at 196 m, with a traffic-free lakefront piazza of pastel-arcaded cafés on Lake Maggiore. Historic Monte Verità anarchist-artistic colony (1900–1920); warmest average climate in Switzerland.","rs":"Mediterranean atmosphere on Lake Maggiore; Monte Verità cultural heritage; one of Switzerland's warmest towns; picture-perfect lakefront with year-round appeal.","wl":"en","wt":"Ascona","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Ascona_IMG_1646.jpg?width=800"},
  {"n":"Centovalli Railway","la":46.177,"lo":8.693,"co":"CH","region":"Ticino","cat":"scenic-railway","themes":["photogenic","panoramic-view","year-round","hidden-gem"],"access":["train"],"season":["spring","summer","autumn","winter"],"dur":2.5,"sc":8,"td":"52 km metre-gauge railway (1923) traversing the 'hundred valleys' between Locarno and Domodossola across dozens of viaducts over wooded gorges and waterfalls. One of Europe's most scenic yet little-known mountain railways.","rs":"Hidden gem of European scenic railways; traverses a remote landscape of gorges, stone villages, and waterfalls; connects Switzerland to Italy via an extraordinary route.","wl":"en","wt":"Centovalli railway","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/ABe_4-8_Intragna_240613_D34.jpg?width=800"},
  {"n":"Verzasca Dam (Contra Dam)","la":46.19667,"lo":8.84778,"e":470,"co":"CH","region":"Ticino","cat":"bridge-engineering","themes":["photogenic","iconic","year-round","architecture"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":1.5,"sc":9,"td":"220 m-high double-arch dam on the Verzasca river — the world's most famous bungee jump site from the 1995 James Bond film 'GoldenEye'. The 007 jump (220 m) is still commercially operated; spectacular walkway on the dam crest.","rs":"Globally iconic for the Bond GoldenEye bungee jump; 4th tallest dam in Switzerland; dramatic engineering in a narrow Ticino gorge; year-round visitor access.","wl":"en","wt":"Contra Dam","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/BarrageDeContra.JPG?width=800"},
  {"n":"Brissago Islands","la":46.13333,"lo":8.735,"e":200,"co":"CH","region":"Ticino","cat":"special-experience","themes":["photogenic","boat-accessible","family-friendly","summer-only"],"access":["boat"],"season":["spring","summer","autumn"],"dur":2,"sc":8,"td":"Two tiny subtropical islands in the Swiss part of Lake Maggiore, at 193 m the lowest point in Switzerland. San Pancrazio hosts a superb botanical garden with 1700 Mediterranean and subtropical plants; reached by regular boat service.","rs":"Switzerland's only subtropical island botanical garden at the country's lowest elevation; boat-access only adds to the experience; outstanding mild microclimate.","wl":"en","wt":"Brissago Islands","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Isoledibrissago.jpg?width=800"},
  {"n":"Monte San Salvatore","la":45.97703,"lo":8.94725,"e":912,"co":"CH","region":"Ticino","cat":"viewpoint-panorama","themes":["panoramic-view","photogenic","family-friendly","iconic"],"access":["funicular","foot"],"season":["spring","summer","autumn"],"dur":2.5,"sc":8,"td":"912 m rocky pyramid above Lugano dubbed the 'Rigi of Ticino'. Funicular from Paradiso reaches the summit in 12 minutes; 360° panorama over Lake Lugano, Lake Maggiore, and the Alpine chain; tiny chapel at the top.","rs":"Most emblematic viewpoint over Lugano; considered one of Switzerland's sunniest spots; funicular ride an easy family classic; summit chapel and panoramic restaurant.","wl":"en","wt":"Monte San Salvatore","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Picswiss_TI-16-02.jpg?width=800"},
  {"n":"Cardada / Cimetta","la":46.20083,"lo":8.79106,"e":1671,"co":"CH","region":"Ticino","cat":"viewpoint-panorama","themes":["panoramic-view","cable-car","photogenic","family-friendly","year-round"],"access":["funicular","cable-car"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":8,"td":"Above Locarno, a funicular from Orselina reaches Cardada plateau (1340 m) and a chairlift continues to Cimetta (1671 m). Prize-winning geodesic viewing platform; panorama stretches from Lake Maggiore to the Valais 4000 m peaks.","rs":"Best panoramic viewpoint above Locarno and Lake Maggiore; architecturally notable geodesic viewing platform; easily combined with Madonna del Sasso funicular.","wl":"en","wt":"Cimetta","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Cardada_Cimetta.jpg?width=800"},
  {"n":"Morcote","la":45.917,"lo":8.917,"e":272,"co":"CH","region":"Ticino","cat":"village","themes":["historic","photogenic","boat-accessible","year-round","architecture"],"access":["car","boat","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":8,"td":"'Pearl of Lake Lugano' at 272 m: a picturesque Renaissance-arcaded village on the Ceresio peninsula. Steep lanes wind up to the hilltop church of Santa Maria del Sasso; elaborate terraced rose garden; accessible by boat from Lugano.","rs":"Repeatedly awarded Switzerland's most beautiful village title; exceptional arcaded historic centre on the Lake Lugano shore; accessible by boat and road.","wl":"en","wt":"Morcote","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Morcote_Aerial.jpg?width=800"},
  {"n":"Gandria","la":45.997,"lo":9.014,"e":270,"co":"CH","region":"Ticino","cat":"village","themes":["historic","hidden-gem","photogenic","boat-accessible","hike-required"],"access":["boat","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":8,"td":"Tiny car-free fishing village on Lake Lugano's eastern shore, reachable only by boat from Lugano or on foot along the Olive Path through centuries-old terraced olive groves. Cobbled lanes, bougainvillea, and a smugglers' museum.","rs":"Only car-free village on Lake Lugano; perfectly preserved Ticinese fishing settlement; charming 30-min boat excursion from Lugano city; smugglers' museum across the bay.","wl":"en","wt":"Gandria","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Gandria.jpg?width=800"},
  {"n":"Foroglio Waterfall","la":46.37389,"lo":8.54806,"e":697,"co":"CH","region":"Ticino","cat":"waterfall-gorge","themes":["photogenic","car-accessible","summer-only","hidden-gem"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":7,"td":"108 m two-tier waterfall plunging into Val Bavona at Foroglio hamlet (697 m). The surrounding car-free stone hamlets have no mains electricity; reached by a short walk from the valley road. Best flow in spring and early summer.","rs":"Most dramatic waterfall in Ticino; set in a federally protected valley of pre-electricity stone hamlets; easy roadside access yet feels completely remote.","wl":"en","wt":"Val Bavona","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Cascata_di_Foroglio.jpg?width=800"},
  {"n":"Niesen","la":46.64611,"lo":7.6525,"e":2362,"co":"CH","region":"Bernese Oberland","cat":"funicular","themes":["panoramic-view","cable-car","photogenic","iconic","family-friendly"],"access":["funicular","train","foot"],"season":["spring","summer","autumn"],"dur":3,"sc":8,"td":"The 2,362 m 'Swiss Pyramid' above Lake Thun, climbed by the 1910 Niesenbahn funicular (max 68% gradient). Its 11,674-step service stairway is Guinness-listed as the world's longest staircase, opened to the public once a year for the Niesenlauf race.","rs":"Pyramidal silhouette that inspired Paul Klee; ride a 1910 funicular beside the Guinness world's longest staircase to a Lake Thun panorama.","wl":"en","wt":"Niesen","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Niesen2.jpg?width=800"},
  {"n":"St. Beatus Caves (Beatushöhlen)","la":46.68465,"lo":7.7823,"e":null,"co":"CH","region":"Bernese Oberland","cat":"geology-cave","themes":["family-friendly","historic","year-round","boat-accessible","car-accessible"],"access":["car","boat","foot"],"season":["spring","summer","autumn","winter"],"dur":1.5,"sc":7,"td":"Show-cave passage of about 1 km (with 87 m of height gain) in cliffs above Lake Thun, part of a 14 km explored system. Medieval legend links the cave to the Celtic monk St. Beatus, who reputedly drove a fire-breathing dragon into the lake.","rs":"Switzerland's best-known cliff-side show cave; dragon legend and Lake Thun arrival by boat make it one of the Bernese Oberland's most atmospheric stops.","wl":"de","wt":"St. Beatus-Höhlen","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/St._Beatus-H%C3%B6hlen_Eingang.jpg?width=800"},
  {"n":"Giessbach Falls","la":46.73529,"lo":8.02053,"e":null,"co":"CH","region":"Bernese Oberland","cat":"waterfall-gorge","themes":["iconic","historic","photogenic","boat-accessible","cable-car","family-friendly"],"access":["boat","funicular","car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":8,"td":"Fourteen named cascades dropping 500 m through forested cliffs into Lake Brienz. The 1879 Giessbachbahn — Switzerland's oldest operating funicular — links the lake pier to the Belle Époque Grandhotel above the lower falls.","rs":"14-step cascade over 500 m of vertical drop with Switzerland's oldest funicular (1879) climbing past the falls to a Belle Époque grand hotel.","wl":"de","wt":"Giessbach (Aare)","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/20080512Y078r_Giessbachfaelle.jpg?width=800"},
  {"n":"Niederhorn","la":46.71083,"lo":7.77333,"e":1963,"co":"CH","region":"Bernese Oberland","cat":"viewpoint-panorama","themes":["panoramic-view","cable-car","photogenic","family-friendly","summer-only","hidden-gem"],"access":["funicular","cable-car","boat","car","foot"],"season":["summer","autumn"],"dur":3,"sc":7,"td":"1,963 m ridge above Beatenberg with sweeping views over Lake Thun to the Eiger-Mönch-Jungfrau wall. Reached via the Thunersee–Beatenberg funicular and the Beatenberg–Niederhorn gondola; 75–100 reintroduced ibex (since 1949) roam the summit ridge.","rs":"Lake Thun's most rewarding panoramic peak; reliable wild-ibex sightings on the Güggis ridge; gentle gondola access from Beatenberg above the lake.","wl":"en","wt":"Niederhorn","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Niederhornview.jpg?width=800"},
  {"n":"Grimsel Hospice","la":46.5725,"lo":8.33361,"e":1980,"co":"CH","region":"Bernese Oberland","cat":"special-experience","themes":["historic","car-accessible","summer-only","panoramic-view","architecture"],"access":["car","foot"],"season":["summer","autumn"],"dur":2,"sc":7,"td":"Historic mountain hospice at 1,980 m on a peninsula in the Grimselsee reservoir, below the 2,164 m Grimsel Pass. A hospice has stood here since at least 1400; today's hotel sits between two KWO hydropower lakes in a glacier-shaped landscape.","rs":"Pilgrim hospice since the Middle Ages, reborn as a striking lakeside hotel between two hydropower reservoirs; gateway to KWO power-station tours and the Grimsel Pass.","wl":"en","wt":"Grimsel Pass","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Blick_auf_den_Grimselsee_und_den_Raeterichsbodensee_0981.jpg?width=800"},
  {"n":"Glacier Express","la":46.659,"lo":8.671,"e":2033,"co":"CH","region":"Central Switzerland","cat":"scenic-railway","themes":["unesco","iconic","photogenic","panoramic-view","year-round"],"access":["train"],"season":["spring","summer","autumn","winter"],"dur":8,"sc":10,"td":"World's slowest 'express' (291 km in ~8 hours) crossing 91 tunnels and 291 bridges between Zermatt and St. Moritz via the 2,033 m Oberalp Pass. Inaugurated 25 June 1930; year-round since the 1982 Furka Base Tunnel; UNESCO Albula/Bernina section.","rs":"World's most famous panorama train; Matterhorn to Bernina via UNESCO mountain railway; daily year-round on metre-gauge tracks.","wl":"en","wt":"Glacier Express","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/CH_Landwasser_2.jpg?width=800"},
  {"n":"Grosser Mythen","la":47.02972,"lo":8.68881,"e":1898,"co":"CH","region":"Central Switzerland","cat":"mountain-summit","themes":["panoramic-view","hike-required","summer-only","photogenic","iconic"],"access":["foot"],"season":["summer","autumn"],"dur":5,"sc":8,"td":"Conical 1,898 m exotic-tectonic 'Klippe' east of the town of Schwyz, reached only on foot via a steep zigzag trail from the Holzegg col (1,405 m). Summit panorama covers four cantons and the Lake Lucerne basin; trail open in summer only.","rs":"Most striking pyramid peak in Central Switzerland; hike-only summit above the cradle of the Confederacy with 360° Lake Lucerne and Glarus panoramas.","wl":"en","wt":"Grosser Mythen","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Mythen_Panorama.jpg?width=800"},
  {"n":"Rhône Glacier & Ice Grotto","la":46.572,"lo":8.37633,"e":2200,"co":"CH","region":"Valais","cat":"glacier","themes":["iconic","photogenic","summer-only","car-accessible","panoramic-view"],"access":["car","foot"],"season":["summer","autumn"],"dur":1.5,"sc":9,"td":"Source of the Rhône river, accessible from the Furka Pass road. Visitors enter a hand-carved blue ice grotto burrowed into the glacier each summer (~120 days). The glacier has lost about 60% of its volume since 1850 — a stark climate witness.","rs":"Walk inside Switzerland's most iconic ice cave at the source of the Rhône; one of the most accessible and most rapidly retreating glaciers in the Alps.","wl":"en","wt":"Rhône Glacier","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Ghiacciaiorhone.jpg?width=800"},
  {"n":"Abbey of Saint-Maurice d'Agaune","la":46.21936,"lo":7.00345,"e":414,"co":"CH","region":"Valais","cat":"monastery-church","themes":["historic","architecture","year-round","car-accessible"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":8,"td":"Active abbey founded in 515 AD by King Sigismund of Burgundy at the foot of the Dents du Midi. Famed for its laus perennis psalmody (from 522) and one of Western Europe's richest Early Christian treasuries, including the Ewer of Saint-Maurice.","rs":"Founded 515 AD; one of Europe's longest continuously active monastic communities; rich Early Christian treasury with the famous gold Ewer of Saint-Maurice.","wl":"en","wt":"Abbey of Saint-Maurice","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Kirche_Abtei_Saint-Maurice.jpg?width=800"},
  {"n":"Aletschwald (Aletsch Forest)","la":46.38667,"lo":8.01861,"e":null,"co":"CH","region":"Valais","cat":"national-park","themes":["unesco","photogenic","hike-required","summer-only","panoramic-view"],"access":["cable-car","foot"],"season":["summer","autumn"],"dur":3,"sc":8,"td":"Subalpine Swiss-pine and larch reserve protected since 1933 above the Great Aletsch Glacier (1,600–2,200 m). Part of UNESCO Jungfrau-Aletsch since 2001; trails from Riederalp link Pro Natura's Villa Cassel centre to glacier viewpoints.","rs":"Switzerland's oldest stone-pine reserve (1933) and one of its most atmospheric glacier-edge forests; UNESCO core zone with sweeping Aletsch panoramas.","wl":"de","wt":"Aletschwald","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Aletschwald_and_the_Aletsch_Glacier_by_Giles_Laurent.jpg?width=800"},
  {"n":"Furka Steam Railway (DFB)","la":46.56139,"lo":8.36194,"e":2160,"co":"CH","region":"Valais","cat":"scenic-railway","themes":["historic","photogenic","summer-only","panoramic-view","architecture"],"access":["train","car"],"season":["summer","autumn"],"dur":4,"sc":8,"td":"Volunteer-run heritage steam line over the Furka Pass between Realp (UR, 1,546 m) and Oberwald (VS, 1,366 m). 17.8 km of metre-gauge Abt rack and adhesion track (max 11.8%); reopened in stages 1992–2010 after the original line's 1981 closure.","rs":"Coal-fired Swiss heritage steam crossing the Alps in summer only; a meticulously restored 1925 alpine engineering route through stark glacier country.","wl":"en","wt":"Furka Steam Railway","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Mh_DFB_Dampfzug.jpeg?width=800"},
  {"n":"Chaplin's World, Vevey","la":46.47556,"lo":6.85139,"e":null,"co":"CH","region":"Vaud / Lake Geneva","cat":"museum-cultural","themes":["iconic","family-friendly","year-round","car-accessible","historic"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":8,"td":"Museum at the 1840 Manoir de Ban above Vevey, Charlie Chaplin's home from 6 January 1953 until his death in 1977. Opened 17 April 2016, the 4,000 m² visit combines restored manor rooms with reconstructed film sets, props, and a 14-ha lakeside park.","rs":"Chaplin's Lake Geneva home for 25 years, immersively reimagined: original manor and film-set museum on a 14-hectare estate above Vevey.","wl":"en","wt":"Manoir de Ban","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Manoir-de-Ban.jpg?width=800"},
  {"n":"Romainmôtier Priory","la":46.69333,"lo":6.46139,"e":660,"co":"CH","region":"Vaud / Lake Geneva","cat":"monastery-church","themes":["historic","architecture","year-round","car-accessible","hidden-gem"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":1.5,"sc":7,"td":"Cluniac priory church in a quiet Vaud valley with origins c. 450 AD under Romanus of Condat. The present Romanesque church (late 10th c., narthex c. 1100) was modelled on Cluny II — Switzerland's finest surviving Cluniac architecture.","rs":"Among Switzerland's oldest churches — a direct architectural descendant of Cluny II; on the Via Francigena pilgrim route in a serene Jura-foot setting.","wl":"en","wt":"Romainmôtier Priory","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Romainmotier_Abtei2.jpg?width=800"},
  {"n":"Maison Cailler, Broc","la":46.60667,"lo":7.09778,"e":718,"co":"CH","region":"Fribourg","cat":"museum-cultural","themes":["food-drink","family-friendly","year-round","car-accessible","historic","iconic"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":8,"td":"Visitor centre and working factory of Switzerland's oldest chocolate brand (founded 1819 by François-Louis Cailler). The 1898 Broc factory runs immersive multilingual tours ending in a tasting room. Reachable by the 'Chocolate Train' from Montreux.","rs":"Origin story of Swiss milk chocolate (1819); immersive factory experience in the heart of the Gruyères valley with direct rail link from Montreux.","wl":"en","wt":"Cailler","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Broc_Chocolaterie_Maison_Cailler-008.jpg?width=800"},
  {"n":"Fribourg Old Town","la":46.80611,"lo":7.16306,"e":581,"co":"CH","region":"Fribourg","cat":"old-town","themes":["historic","architecture","year-round","car-accessible","photogenic","family-friendly"],"access":["car","train","funicular","foot"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":8,"td":"Founded 1157 by Berthold IV of Zähringen on a tight Sarine river meander, with the medieval core perched 40 m above the gorge. Cathedral of St-Nicholas (74 m tower, Mehoffer windows), covered wooden bridge, and a wastewater-powered funicular.","rs":"Switzerland's best-preserved medieval old town on a dramatic river meander; bilingual heritage city; 13th-c. Gothic cathedral; world-rare wastewater funicular.","wl":"en","wt":"Fribourg","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Panorama_Fribourg_107.JPG?width=800"},
  {"n":"Estavayer-le-Lac","la":46.85,"lo":6.84722,"e":459,"co":"CH","region":"Fribourg","cat":"old-town","themes":["historic","architecture","car-accessible","boat-accessible","year-round","photogenic","hidden-gem"],"access":["car","train","boat","foot"],"season":["spring","summer","autumn"],"dur":2.5,"sc":7,"td":"Walled medieval town on Lake Neuchâtel's south shore, with 13th-c. Chenaux Castle, the Collegiate Church of Saint-Laurent, and the offbeat 19th-c. Frog Museum. The whole town is on the Swiss inventory of heritage sites of national importance.","rs":"Switzerland's 'town of roses' on Lake Neuchâtel; intact medieval walls, a 13th-c. castle, and the eccentric 19th-c. Frog Museum on its main square.","wl":"en","wt":"Estavayer-le-Lac","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Estavayer-le-Lac_old_city.jpg?width=800"},
  {"n":"Aarau Old Town","la":47.392,"lo":8.044,"e":381,"co":"CH","region":"Basel / Aargau","cat":"old-town","themes":["historic","architecture","year-round","car-accessible","hidden-gem","photogenic"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":7,"td":"Capital of canton Aargau and 'City of Beautiful Gables' — every old-town facade carries painted figurative gables. Briefly the first capital of unified Switzerland (Helvetic Republic, March–September 1798); compact medieval core on the Aare.","rs":"Switzerland's first national capital (1798) and only old town defined by hand-painted decorative gables; an under-visited cousin to Bern and Solothurn.","wl":"en","wt":"Aarau","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Aarauer_Giebel.jpg?width=800"},
  {"n":"Baden Old Town & Thermal Baths","la":47.47673,"lo":8.3102,"e":381,"co":"CH","region":"Basel / Aargau","cat":"spa-wellness","themes":["historic","year-round","car-accessible","architecture","food-drink","family-friendly"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":8,"td":"Switzerland's oldest known thermal site, used by the Romans as Aquae Helveticae. 21 mineral springs at 46.6 °C avg — the country's most mineralised waters. New Mario Botta–designed bath complex opened November 2021; medieval old town on the Limmat.","rs":"Roman thermal baths reborn under Mario Botta (2021); Switzerland's oldest hot springs and best-mineralised waters paired with a tightly preserved old town.","wl":"en","wt":"Baden, Aargau","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Baden_Altstadt_und_Industrie_DJI.jpg?width=800"},
  {"n":"Pavillon Le Corbusier","la":47.35635,"lo":8.55112,"e":null,"co":"CH","region":"Zürich","cat":"museum-cultural","themes":["architecture","year-round","iconic","historic","photogenic"],"access":["train","boat","foot"],"season":["spring","summer","autumn"],"dur":1,"sc":8,"td":"Le Corbusier's final building, posthumously inaugurated 15 July 1967 on the Zürichhorn lakeshore. A prefabricated steel pavilion in multicoloured enamel panels under a 'free-floating' 12 × 26 m roof; now run by Museum für Gestaltung.","rs":"Le Corbusier's last and only enamel/steel building; a Gesamtkunstwerk pavilion on Lake Zürich integrating his architecture, painting, and sculpture.","wl":"en","wt":"Pavillon Le Corbusier","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Centre_Le_Corbusier_2011-06-18_18-10-04.jpg?width=800"},
  {"n":"Heididorf, Maienfeld","la":47.01328,"lo":9.54514,"e":635,"co":"CH","region":"Eastern Switzerland","cat":"special-experience","themes":["family-friendly","historic","car-accessible","photogenic"],"access":["car","train","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":7,"td":"Reconstructed alpine hamlet above Maienfeld in the original setting of Johanna Spyri's 'Heidi' (1880–81). Open since 1998: Heidi's house, Alpine hut, museum, village shop, and a small animal park along walking trails through vineyards.","rs":"Walk through the Bündner Herrschaft landscape that inspired Heidi; reconstructed traditional houses make this Switzerland's most-loved family literary site.","wl":"de","wt":"Heididorf","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Heididorf_Heidihaus.jpeg?width=800"},
  {"n":"Pizol Five-Lakes Hike","la":46.95917,"lo":9.38667,"e":2844,"co":"CH","region":"Eastern Switzerland","cat":"viewpoint-panorama","themes":["panoramic-view","hike-required","cable-car","summer-only","photogenic","hidden-gem"],"access":["cable-car","train","foot"],"season":["summer","autumn"],"dur":5,"sc":8,"td":"Classic alpine 5-lake circuit (Wangsersee, Wildsee, Schottensee, Schwarzsee, Baschalvasee) at 2,174–2,368 m beneath the 2,844 m Pizol summit. Reached by gondola from Wangs or Bad Ragaz; the Pizol Glacier was officially declared extinct in 2019.","rs":"Eastern Switzerland's classic five-lake hike under the now-extinct Pizol Glacier; a poignant climate landmark with five turquoise tarns in one circuit.","wl":"en","wt":"Pizol","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Picswiss_SG-37-09.jpg?width=800"},
  {"n":"Werdenberg","la":47.16851,"lo":9.46165,"e":465,"co":"CH","region":"Eastern Switzerland","cat":"old-town","themes":["historic","architecture","hidden-gem","photogenic","year-round","car-accessible"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":1.5,"sc":7,"td":"Tiny medieval Städtli on the Werdenbergersee in canton St. Gallen with an intact group of 15th–17th-century timber-frame houses and the 1228 hilltop Werdenberg Castle. The whole settlement is a Swiss heritage site of national significance.","rs":"Among Switzerland's most intact medieval timber-frame ensembles; lakeside hilltop castle (1228); often called Switzerland's smallest Städtli.","wl":"en","wt":"Werdenberg Castle","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/St%C3%A4dtchen_Werdenberg.jpg?width=800"},
  {"n":"7132 Therme (Therme Vals)","la":46.617,"lo":9.183,"e":1252,"co":"CH","region":"Graubünden","cat":"spa-wellness","themes":["architecture","year-round","photogenic","hidden-gem"],"access":["car"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":9,"td":"Peter Zumthor's 1996 thermal-bath masterpiece in the remote Vals valley, clad in 60,000 slabs of locally quarried Valser quartzite. Pritzker laureate's most celebrated building; access since 2012 is restricted to guests of the adjoining 7132 Hotel.","rs":"Pritzker Prize-winning Peter Zumthor's quarry-inspired thermal baths; Switzerland's most-acclaimed contemporary architecture in a tiny Graubünden valley.","wl":"en","wt":"Therme Vals","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Therme_Vals_facade%2C_Vals%2C_Graub%C3%BCnden%2C_Switzerland_-_20051009.jpg?width=800"},
  {"n":"Caplutta Sogn Benedetg","la":46.73478,"lo":8.93967,"e":1277,"co":"CH","region":"Graubünden","cat":"monastery-church","themes":["architecture","hidden-gem","photogenic","historic"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":1,"sc":8,"td":"Peter Zumthor's wooden chapel above Sumvitg, built 1985–1989 after an avalanche destroyed the baroque chapel on the same site. Oval plan in larch shingles weathered silver-grey; a seminal work of late-20th-century sacred architecture.","rs":"Peter Zumthor's most accessible early masterwork; a tiny wooden chapel above an unspoiled Surselva village; quiet hike, profound architectural payoff.","wl":"en","wt":"Caplutta Sogn Benedetg","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Sogn_Benedetg1.jpg?width=800"},
  {"n":"Davos Schatzalp","la":46.80111,"lo":9.81389,"e":1860,"co":"CH","region":"Graubünden","cat":"special-experience","themes":["historic","architecture","cable-car","year-round","panoramic-view","photogenic"],"access":["train","funicular"],"season":["spring","summer","autumn","winter"],"dur":2.5,"sc":8,"td":"Art Nouveau hotel at 1,860 m, opened 1900 as a TB sanatorium and immortalised in Thomas Mann's 'The Magic Mountain' (1924). Reached by the 1899 Schatzalp-Bahn — Graubünden's first funicular; 3,500-species alpine garden in summer.","rs":"Thomas Mann's 'Magic Mountain' setting; ride a 1899 funicular to a Belle Époque sanatorium-turned-hotel above Davos with a 3,500-species alpine garden.","wl":"en","wt":"Berghotel Schatzalp","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Berghotel_Schatzalp.jpg?width=800"},
  {"n":"Juf (Avers)","la":46.44556,"lo":9.57917,"e":2126,"co":"CH","region":"Graubünden","cat":"village","themes":["hidden-gem","historic","photogenic","car-accessible"],"access":["car","foot"],"season":["summer","autumn"],"dur":1.5,"sc":7,"td":"Walser hamlet at 2,126 m at the head of the Avers Valley — the highest year-round inhabited settlement in Western Europe. 31 residents (2016) descended from Walser settlers (1292). Road-end village above the treeline; eight daily post buses.","rs":"Western Europe's highest year-round inhabited village; a 1292 Walser foundation of just ~30 inhabitants at the road's end above the treeline in Graubünden.","wl":"en","wt":"Juf","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Avers-Juf.jpg?width=800"},
  {"n":"Brusio Spiral Viaduct","la":46.25389,"lo":10.12778,"e":null,"co":"CH","region":"Engadin","cat":"bridge-engineering","themes":["unesco","iconic","photogenic","architecture","year-round"],"access":["train","car","foot"],"season":["spring","summer","autumn","winter"],"dur":1,"sc":9,"td":"Open-air helicoidal stone viaduct on the Bernina line, opened 1 July 1908. Nine 10 m spans curl through a full 360° loop with 50–70 m radius to keep the railway gradient under 7%. The Bernina Express crosses it; UNESCO World Heritage since 2008.","rs":"World's most photographed open-air railway spiral; 360° helicoid; key UNESCO landmark on the Bernina Express line; train and on-foot viewing both excellent.","wl":"en","wt":"Brusio spiral viaduct","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/RhB_ABe_4-4_III_Kreisviadukt_Brusio.jpg?width=800"},
  {"n":"Maloja Pass","la":46.40139,"lo":9.69583,"e":1815,"co":"CH","region":"Engadin","cat":"viewpoint-panorama","themes":["car-accessible","panoramic-view","photogenic","historic","year-round"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":1,"sc":7,"td":"Watershed pass at 1,815 m where the level Engadin lakes plateau drops abruptly into Val Bregaglia. Origin of the 'Maloja Snake' Foehn-cloud phenomenon and the landscape that defined Divisionist painter Giovanni Segantini's late career.","rs":"Most dramatic pass in the Engadin: a flat 1,815 m plateau plunges 800 m into Bregaglia in a few hairpins; Segantini terrain and a famous serpent-cloud phenomenon.","wl":"en","wt":"Maloja Pass","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Malojapass_B%C3%B6hringer_2018.jpg?width=800"},
  {"n":"Lago di Saoseo","la":46.398,"lo":10.126,"e":2028,"co":"CH","region":"Engadin","cat":"alpine-lake","themes":["photogenic","hike-required","hidden-gem","summer-only","swimmable"],"access":["foot"],"season":["summer","autumn"],"dur":4,"sc":8,"td":"Intensely blue spring-fed lake (570 m × 550 m, 17 m deep) at 2,028 m in Val da Camp above Poschiavo. Reached only on foot — a 2-hour walk from Alp Camp (permit-restricted minibus) or 5-hour circular from Sfazù on the Bernina Pass road.","rs":"Switzerland's most photographed turquoise hike-lake; car-free wilderness in the Bernina hinterland; a true pearl of the Poschiavo high country.","wl":"en","wt":"Lago di Saoseo","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Saoseo.jpg?width=800"},
  {"n":"Bosco Gurin","la":46.317,"lo":8.5,"e":1504,"co":"CH","region":"Ticino","cat":"village","themes":["hidden-gem","historic","photogenic","car-accessible","food-drink","winter-sport"],"access":["car","foot"],"season":["summer","autumn","winter"],"dur":2,"sc":7,"td":"Highest village in Ticino at 1,504 m and the canton's only German-speaking community. Settled in 1244 by Walser migrants from Val Formazza, with dark-timbered chalets, a Walser local museum (1936), and surrounding alpine pastures.","rs":"Ticino's highest and only Walser-German village; intact medieval timber architecture, a 1936 local museum, and a uniquely double cultural identity.","wl":"en","wt":"Bosco/Gurin","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/BoscoGurin_veduta.jpg?width=800"}
];

/* Helper: index POIs by category for fast filtering. */
const SWISS_POIS_BY_CAT = SWISS_POIS.reduce((m, p) => {
  (m[p.cat] = m[p.cat] || []).push(p); return m;
}, {});

/* Helper: index POIs by region. */
const SWISS_POIS_BY_REGION = SWISS_POIS.reduce((m, p) => {
  (m[p.region] = m[p.region] || []).push(p); return m;
}, {});

/* Helper: filter POIs by an array of themes (any-of match). */
function swissPoisWithThemes(themes) {
  const set = new Set(themes);
  return SWISS_POIS.filter(p => p.themes.some(t => set.has(t)));
}

/* Helper: top-N most notable POIs (score >= threshold). */
function swissPoisTop(n = 25, scoreFloor = 8) {
  return SWISS_POIS
    .filter(p => (p.sc || 0) >= scoreFloor)
    .slice()
    .sort((a, b) => (b.sc || 0) - (a.sc || 0))
    .slice(0, n);
}

if (typeof module !== 'undefined') {
  module.exports = { SWISS_POIS, SWISS_POIS_BY_CAT, SWISS_POIS_BY_REGION, swissPoisWithThemes, swissPoisTop };
}
/* ====== end   assets/js/swiss-pois.js ====== */
;
