const ITALY_POIS = [
  /* ── Alto Adige / Südtirol ────────────────────────────────────────── */
  {"n":"Lago di Braies (Pragser Wildsee)","la":46.69472,"lo":12.08444,"e":1496,"co":"IT","region":"Alto Adige / Südtirol","cat":"alpine-lake","themes":["unesco","iconic","photogenic","car-accessible","swimmable","boat-accessible","summer-only"],"access":["car","foot","boat"],"season":["spring","summer","autumn"],"dur":2,"sc":10,"td":"Emerald lake in the Prags Dolomites at 1,496 m, 3 km perimeter trail. Part of the Fanes-Sennes-Braies UNESCO World Heritage area. Rowing boats for hire; vehicle access restricted in peak summer since 2023 to combat overtourism.","rs":"The 'Pearl of the Alps' — impossibly turquoise water, rowing boats, and sheer limestone walls. At dawn, before the crowds, it is arguably the most beautiful lake in the Alps.","wl":"en","wt":"Pragser Wildsee","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Pragser_Wildsee_Seekofel_von_Bucht.jpg?width=800"},
  {"n":"Seceda","la":46.60056,"lo":11.72694,"e":2519,"co":"IT","region":"Alto Adige / Südtirol","cat":"viewpoint-panorama","themes":["iconic","photogenic","panoramic-view","cable-car","summer-only"],"access":["cable-car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":10,"td":"Sweeping ridgeline at 2,519 m in the Geisler/Odle Group above Ortisei, reached by a three-stage cable car from Ortisei (Val Gardena). The serrated Sass Rigais (3,025 m) towers behind the viewpoint platform; 360° panorama across the Dolomites.","rs":"The single most photographed Dolomite viewpoint. The knife-edge ridge, the Geisler pinnacles behind, and the pastoral Val Gardena below create the definitive Alto Adige composition.","wl":"de","wt":"Seceda","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Geisler_and_Sec%C3%ABda_from_Resciesa.JPG?width=800"},
  {"n":"Seiser Alm (Alpe di Siusi)","la":46.54111,"lo":11.64472,"e":1700,"co":"IT","region":"Alto Adige / Südtirol","cat":"viewpoint-panorama","themes":["unesco","iconic","photogenic","panoramic-view","cable-car","car-accessible","family-friendly","winter-sport","year-round"],"access":["car","cable-car","foot"],"season":["spring","summer","autumn","winter"],"dur":4,"sc":10,"td":"Europe's largest high-elevation alpine meadow, 52 km², at 1,680–2,350 m in the UNESCO Dolomites. Flanked by the Langkofel and Sciliar massifs. Cable car from Ortisei or Kastelruth; road access permitted only for guests (restricted otherwise).","rs":"A vast emerald plateau floating above the tree-line, ringed by the most photogenic Dolomite peaks. In flower season it is the archetypal Alpine panorama — zero effort required from the cable car.","wl":"en","wt":"Seiser Alm","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Saslonch_udu_da_Mont_de_Seuc.jpg?width=800"},
  {"n":"South Tyrol Museum of Archaeology — Ötzi the Iceman","la":46.49917,"lo":11.35278,"e":null,"co":"IT","region":"Alto Adige / Südtirol","cat":"museum-cultural","themes":["iconic","special-experience","year-round","family-friendly"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":10,"td":"Archaeological museum in Bolzano opened 1998 to house Ötzi, the 5,300-year-old Copper Age mummy discovered in the Ötztal Alps in 1991. Displayed at −6 °C in a climate-controlled chamber. Copper axe, bow, quiver, and complete kit on display.","rs":"The actual, real 5,300-year-old man — not a replica — stares back at you through refrigerated glass. The most remarkable preserved human body in the world, with more scientific secrets still being decoded.","wl":"en","wt":"South Tyrol Museum of Archaeology","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/BozenArchMuseum.jpg?width=800"},
  {"n":"Bolzano / Bozen — Old Town","la":46.5,"lo":11.35,"e":null,"co":"IT","region":"Alto Adige / Südtirol","cat":"old-town","themes":["iconic","historic","architecture","food-drink","year-round","family-friendly"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":9,"td":"Capital of South Tyrol at 262 m; medieval arcaded Via dei Portici, Gothic Duomo, and Waltherplatz square. Gateway to the Dolomites. Home of the South Tyrol Museum of Archaeology (Ötzi). Renowned Christmas market Nov–Jan; vibrant café culture.","rs":"The most liveable bilingual city in the Alps — Italian espresso culture, Austrian architectural elegance, and the Dolomites on the horizon. The compact old town rewards an afternoon's wandering.","wl":"en","wt":"Bolzano","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Bozen-Bolzano_from_the_Oswaldpromenade.jpg?width=800"},
  {"n":"Kronplatz / Plan de Corones & MMM Corones","la":46.73806,"lo":11.96,"e":2275,"co":"IT","region":"Alto Adige / Südtirol","cat":"viewpoint-panorama","themes":["panoramic-view","cable-car","winter-sport","year-round","special-experience","architecture"],"access":["cable-car"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":9,"td":"Flat-topped Dolomite mountain at 2,275 m above Bruneck, reached by gondola from three valleys. Summit hosts Zaha Hadid–designed MMM Corones (Messner Mountain Museum) with 360° panorama of 100+ Alpine peaks. Major ski resort in winter.","rs":"Summit-level contemporary architecture housing Messner's shrine to mountaineering, with one of the finest open panoramas in the Alps — Dolomites south, Austrian Alps north, in a single sweeping view.","wl":"en","wt":"Kronplatz","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Kronplatz_Suedseite.jpg?width=800"},
  {"n":"Lake Carezza (Karersee)","la":46.40917,"lo":11.575,"e":1519,"co":"IT","region":"Alto Adige / Südtirol","cat":"alpine-lake","themes":["iconic","photogenic","car-accessible","year-round","panoramic-view"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":1,"sc":9,"td":"Small Dolomite lake, 300 m long, fed by underground springs from the Latemar massif. Famous for dark-green mirror water reflecting the Latemar range. Accessible via SS241 road, 20 km south-east of Bolzano in Welschnofen municipality.","rs":"The colour-shifting reflections of the Latemar's limestone towers in the still water create a painting-like scene that inspired John Singer Sargent's famous 1914 watercolour.","wl":"en","wt":"Karersee","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Carezza_Lake.jpg?width=800"},
  {"n":"Lake Resia (Reschensee) — Sunken Bell Tower","la":46.80111,"lo":10.53111,"e":1498,"co":"IT","region":"Alto Adige / Südtirol","cat":"alpine-lake","themes":["iconic","photogenic","car-accessible","year-round","special-experience","historic"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":1,"sc":9,"td":"Artificial reservoir at 1,498 m in the upper Vinschgau, South Tyrol's largest lake (6.6 km²). The 14th-century bell tower of submerged Graun village protrudes from the water, a poignant reminder of the village flooded in 1950 to create the reservoir.","rs":"One of Europe's most haunting images: a lone medieval tower rising from a frigid mountain lake. In winter it can be reached on foot across the ice, making it surreal at any season.","wl":"en","wt":"Reschensee","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Reschensee_with_Graun_Church_tower_and_boat.jpg?width=800"},
  {"n":"Langkofel / Sassolungo","la":46.52472,"lo":11.73528,"e":3181,"co":"IT","region":"Alto Adige / Südtirol","cat":"mountain-summit","themes":["iconic","photogenic","panoramic-view","car-accessible","hike-required","summer-only"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":3,"sc":9,"td":"Highest peak of the Langkofel Group at 3,181 m, towering over Val Gardena. The sheer south-west wall rises 1,000 m above the Sella Pass. Normal route from Sella Pass (2,240 m) requires alpine experience; the surrounding Cirque is accessible to all.","rs":"The most imposing rock tower visible from the Seiser Alm. Its vertical south wall reflected in the alm ponds at sunset is the quintessential Dolomite image. The Cirque walk around the base is stunning.","wl":"en","wt":"Langkofel","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Saslonch_da_Mont_de_Seuc.jpg?width=800"},
  {"n":"MMM Firmian — Messner Mountain Museum at Sigmundskron Castle","la":46.48028,"lo":11.30528,"e":null,"co":"IT","region":"Alto Adige / Südtirol","cat":"museum-cultural","themes":["special-experience","historic","architecture","panoramic-view","car-accessible"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":9,"td":"Reinhold Messner's flagship mountain museum inside 10th-century Sigmundskron Castle near Bolzano. Opened 2006 across 17 levels of the ruined castle ruins. Covers geology, alpinism history, rock art, and Messner's own expeditions. Views of the Dolomites.","rs":"A medieval ruin reimagined as a meditation on man and mountain: Messner's personal artefacts, high-alpine films, and the castle's own dramatic silhouette make this the most atmospheric museum in South Tyrol.","wl":"en","wt":"Sigmundskron Castle","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Sigmundskron.jpg?width=800"},
  {"n":"Merano / Meran — Spa Town","la":46.66667,"lo":11.16667,"e":null,"co":"IT","region":"Alto Adige / Südtirol","cat":"old-town","themes":["spa-wellness","historic","architecture","food-drink","year-round","family-friendly"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":9,"td":"Spa resort at 325 m sheltered by the Texel Group; mild microclimate beloved by Habsburg aristocracy. Belle-époque Thermal Baths (Therme Meran), arcaded Lauben promenade, Gothic Castello Principesco. Gateway to Ötztal and Vinschgau valleys.","rs":"South Tyrol's most elegant town — empress Sisi convalesced here, and the healing waters still flow. The blend of Art Nouveau architecture, palm-lined promenades and mountain views is uniquely seductive.","wl":"en","wt":"Merano","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Meran,_Panorama_(Blick_vom_Pulverturm).jpg?width=800"},
  {"n":"Novacella Abbey (Kloster Neustift / Abbazia di Novacella)","la":46.7425,"lo":11.64833,"e":null,"co":"IT","region":"Alto Adige / Südtirol","cat":"monastery-church","themes":["historic","architecture","food-drink","year-round"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":1.5,"sc":9,"td":"Augustinian Canons' monastery at Vahrn near Brixen, founded 1142 by Blessed Hartmann. Baroque church, Romanesque round tower, exceptional Gothic cloister. The monastery's winery produces Müller-Thurgau, Kerner and Sylvaner under the Stiftskellerei label.","rs":"Eight centuries of monastic life, a world-class winery, and one of the finest Baroque church interiors in the Alps — Novacella is a three-in-one cultural experience unmatched in the region.","wl":"en","wt":"Novacella Abbey","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Neustift_Ansicht.jpg?width=800"},
  {"n":"Rosengarten / Catinaccio (King Laurin's Rose Garden)","la":46.46667,"lo":11.65,"e":3002,"co":"IT","region":"Alto Adige / Südtirol","cat":"mountain-summit","themes":["unesco","iconic","photogenic","panoramic-view","hike-required","special-experience","summer-only"],"access":["car","cable-car","foot"],"season":["spring","summer","autumn"],"dur":3,"sc":9,"td":"Massive dolomite massif, highest point Kesselkogel 3,002 m, on the South Tyrol / Trentino border. Famous for alpenglow (Enrosadira) at sunset, turning the pale limestone deep crimson-pink — explained by the legend of King Laurin and his Rose Garden.","rs":"Nowhere in the Alps glows like the Catinaccio at sunset. The mythical Enrosadira effect — the rocks burning red for 20 minutes — is the most celebrated alpine light show in the Dolomites.","wl":"en","wt":"Rosengarten group","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Schlern_-_Rosengarten_-_September.jpg?width=800"},
  {"n":"St. John in Ranui (San Giovanni in Ranui) — Funes Valley Chapel","la":46.62083,"lo":11.68556,"e":null,"co":"IT","region":"Alto Adige / Südtirol","cat":"monastery-church","themes":["iconic","photogenic","car-accessible","panoramic-view","summer-only"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":1,"sc":9,"td":"Small 17th-century Baroque chapel near Santa Maddalena in the Villnöß (Funes) valley, with the Geisler/Odle pinnacles rising 2,000 m directly behind. Considered the most photographed church in the Dolomites. Reached by road + short walk through meadows.","rs":"The photograph that defines the Dolomites: a lone white chapel in a green meadow with the vertical rock walls of the Geislergruppe soaring above. Nothing else competes for sheer visual drama.","wl":"de","wt":"Villnöß","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Villn%C3%B6%C3%9F_Johanniskapelle_mit_Geisler.jpg?width=800"},
  {"n":"Stelvio Pass (Stilfserjoch / Passo dello Stelvio)","la":46.52861,"lo":10.45278,"e":2757,"co":"IT","region":"Alto Adige / Südtirol","cat":"viewpoint-panorama","themes":["panoramic-view","car-accessible","iconic","summer-only","special-experience"],"access":["car","foot"],"season":["summer","autumn"],"dur":1,"sc":9,"td":"Second-highest paved pass in the Alps at 2,757 m on the South Tyrol / Lombardy border. 48 hairpin bends on the Bolzano side. Open roughly June–October; within Stelvio National Park. Top Gear 'greatest driving road' 2008.","rs":"The most dramatic road in the Alps. Driving the 48 hairpins with glacier views and the Ortler towering above is a bucket-list experience for motorcyclists, cyclists and drivers alike.","wl":"en","wt":"Stelvio Pass","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Stelvio_Pass_Bolzano_side_1.jpg?width=800"},
  {"n":"Tirol Castle (Schloss Tirol / Castel Tirolo)","la":46.69414,"lo":11.14481,"e":null,"co":"IT","region":"Alto Adige / Südtirol","cat":"castle-fortress","themes":["historic","architecture","panoramic-view","car-accessible"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":1.5,"sc":9,"td":"Medieval castle above Merano that gave the entire county — and modern nation — of Tyrol its name. Seat of the Counts of Tyrol from before 1100. Romanesque chapel, 12th-century keep; now houses the South Tyrol Museum of Cultural History. Vineyard setting.","rs":"The most historically significant castle in the Alps: the building that named a country. Standing where the Counts of Tyrol once ruled, above Merano and the Adige valley, is genuinely thrilling.","wl":"en","wt":"Tyrol Castle","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Tirol_Schloss_01.jpg?width=800"},
  {"n":"Trauttmansdorff Castle Gardens (Gärten von Schloss Trauttmansdorff)","la":46.66,"lo":11.185,"e":null,"co":"IT","region":"Alto Adige / Südtirol","cat":"castle-fortress","themes":["historic","architecture","family-friendly","photogenic","panoramic-view","spa-wellness"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":9,"td":"Romantic castle and 12-ha botanical gardens above Merano, open April–November. Empress Elisabeth (Sisi) convalesced here 1870–71; 80 themed garden worlds cascade down a cliff with Alpine and Mediterranean plants. Touriseum (tourism museum) inside.","rs":"Where Empress Sisi chose to heal. Tiered gardens with citrus, palms and local wildflowers descend toward Merano below the castle's Neo-Gothic towers — the finest garden experience in the Alps.","wl":"en","wt":"Trauttmansdorff Castle Gardens","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Botanischer_Garten_Meran_39.JPG?width=800"},
  {"n":"Bletterbach Gorge — Geopark","la":46.35783,"lo":11.43419,"e":null,"co":"IT","region":"Alto Adige / Südtirol","cat":"geology-cave","themes":["special-experience","hike-required","hidden-gem","family-friendly"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":3,"sc":8,"td":"8 km gorge near Aldein cutting 100 m through Permian–Triassic strata spanning 260 million years, with Permian reptile footprints. UNESCO World Heritage (Dolomites geopark). Guided 4 km hike into the canyon passes the 'canyon of the leaves' sections.","rs":"The 'Grand Canyon of the Dolomites' — a hidden gorge where the rock walls read like the pages of a 260-million-year geological textbook. Fossil footprints of giant Permian reptiles are visible in situ.","wl":"en","wt":"Bletterbach","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Bletterbach.JPG?width=800"},
  {"n":"Brixen / Bressanone","la":46.71667,"lo":11.65,"e":null,"co":"IT","region":"Alto Adige / Südtirol","cat":"old-town","themes":["historic","architecture","year-round","food-drink","family-friendly"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":8,"td":"Oldest city in South Tyrol (Roman Prihsna), 560 m. Prince-bishops' seat for 900 years — their Baroque palace and cathedral cloister with frescoes are highlights. Gothic arcaded centre, Romanesque baptistery. Gateway to Plose ski mountain.","rs":"A miniature episcopal capital with more medieval art per square metre than any other South Tyrolean town. The frescoed cloister of the Cathedral is one of the finest in the Alps.","wl":"en","wt":"Brixen","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Brixen_Dom_Mari%C3%A4_Himmelfahrt_(BD_14187_3_05-2015).jpg?width=800"},
  {"n":"Churburg (Castel Coira) — Private Armoury Castle","la":46.66358,"lo":10.58852,"e":null,"co":"IT","region":"Alto Adige / Südtirol","cat":"castle-fortress","themes":["historic","architecture","hidden-gem","car-accessible"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":1.5,"sc":8,"td":"13th-century castle in Schluderns (Vinschgau), owned by the Trapp family since 1368. Houses the finest private medieval armoury in Europe — 100+ suits of plate armour from the 14th–17th centuries, including the famous Matsch Gothic armour set.","rs":"An unassuming castle concealing what serious historians call the greatest private collection of medieval armour on earth. The guided tour through the armoury halls is extraordinary.","wl":"de","wt":"Churburg","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Churburg_Schluderns_01.jpg?width=800"},
  {"n":"Glurns / Glorenza — Smallest Walled Town in the Alps","la":46.66667,"lo":10.55,"e":null,"co":"IT","region":"Alto Adige / Südtirol","cat":"old-town","themes":["historic","architecture","hidden-gem","year-round"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":1.5,"sc":8,"td":"The smallest walled town in the Alps (882 inhabitants), at 907 m in the Vinschgau. Perfectly intact 16th-century curtain walls with three gated towers, a medieval arcaded main street, and a Romanesque church. A true time-capsule town.","rs":"Walking through the intact gate of Europe's smallest fortified town, into its silent medieval square, is like stepping into a film set — except it is entirely real and almost visitor-free.","wl":"en","wt":"Glurns","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Glurns_Glorenza_20220903_0006.jpg?width=800"},
  {"n":"Juval Castle (Castel Juval) — Messner Mountain Museum","la":46.6515,"lo":10.9681,"e":null,"co":"IT","region":"Alto Adige / Südtirol","cat":"castle-fortress","themes":["special-experience","historic","hike-required","hidden-gem"],"access":["foot"],"season":["spring","summer","autumn"],"dur":2,"sc":8,"td":"13th-century castle at c. 1,000 m at the entrance of the Schnalstal (Vinschgau), former summer home of Reinhold Messner until 2025. MMM Juval focuses on 'magic mountains' — Tibetan art, masks from five continents. Accessible only on foot (1 h) or shuttle.","rs":"The most atmospheric of Messner's six museums. The remote approach on foot through chestnut woods, the medieval tower, and Tibetan thangkas inside create a deeply memorable visit.","wl":"en","wt":"Juval Castle","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Schloss_Juval.jpg?width=800"},
  {"n":"Marienberg Abbey (Abtei Marienberg / Abbazia Monte Maria)","la":46.70667,"lo":10.51944,"e":1340,"co":"IT","region":"Alto Adige / Südtirol","cat":"monastery-church","themes":["historic","architecture","hidden-gem","panoramic-view","car-accessible"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":1.5,"sc":8,"td":"Benedictine abbey at 1,340 m above Burgeis in the Vinschgau — the highest Benedictine abbey in Europe, founded 1150. Romanesque crypt with remarkable 12th-century Byzantine frescoes; Baroque church above. Active monastic community; guided tours daily.","rs":"Europe's highest Benedictine abbey crowns a spur above the Vinschgau with the Ortler glacier glinting to the south. The crypt frescoes — barely known outside specialist circles — are among the Alps' finest Romanesque paintings.","wl":"en","wt":"Marienberg Abbey","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/AbteiMarienberg.jpg?width=800"},
  {"n":"Ortisei / St. Ulrich (Urtijëi)","la":46.56667,"lo":11.66667,"e":null,"co":"IT","region":"Alto Adige / Südtirol","cat":"village","themes":["iconic","cable-car","year-round","winter-sport","food-drink","family-friendly"],"access":["car","cable-car","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":8,"td":"Capital of the Ladin-speaking Val Gardena at 1,230 m, gateway to Seiser Alm and Seceda cable cars. Famous for centuries of wood-carving tradition; workshops still produce religious figurines sold worldwide. Elegant pedestrian centre with boutiques and cafés.","rs":"The most complete base for the western Dolomites — cable cars to Seiser Alm and Seceda depart the village, the Ladin culture is authentically maintained, and the val Gardena skiing circuit is world-class.","wl":"en","wt":"Ortisei","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Urtij%C3%ABi_cun_l_Sela_Y_Saslonch_da_Tlesura.jpg?width=800"},
  {"n":"Runkelstein Castle (Schloss Runkelstein / Castel Roncolo)","la":46.51722,"lo":11.35889,"e":null,"co":"IT","region":"Alto Adige / Südtirol","cat":"castle-fortress","themes":["historic","architecture","car-accessible","year-round"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":1.5,"sc":8,"td":"13th-century castle on a rock spur north of Bolzano with the most extensive cycle of secular medieval frescoes in Europe (c. 1390). Scenes from Arthurian romance, Tristan and Isolde, and heroic legend cover the Summer House walls. City of Bolzano owns it.","rs":"The medieval secular fresco cycle — knights, ladies, and Arthurian scenes painted in vivid colour — is unmatched anywhere in the Alps. A 20-minute drive from Bolzano's old town.","wl":"en","wt":"Runkelstein Castle","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/BozenRunkelstein.jpg?width=800"},
  {"n":"Schlern / Sciliar","la":46.515,"lo":11.57556,"e":2563,"co":"IT","region":"Alto Adige / Südtirol","cat":"mountain-summit","themes":["iconic","photogenic","panoramic-view","hike-required","summer-only"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":3,"sc":8,"td":"Plateau mountain massif with twin towers (Petz 2,564 m, Euringer 2,395 m) south of Seiser Alm in Sciliar-Catinaccio Natural Park. Symbol of South Tyrol — its profile features on Loacker wafer packaging. Rifugio Schlernhaus at 2,457 m.","rs":"South Tyrol's heraldic mountain. The hike from Völs or Seis along its dramatic rim to the Schlernhaus is one of the region's great ridge walks, with Seiser Alm spread below like a green carpet.","wl":"en","wt":"Schlern","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Schlern_-_Gflirer_Weiher.jpg?width=800"},
  {"n":"Stelvio National Park (Nationalpark Stilfserjoch) — Alto Adige Sector","la":46.50889,"lo":10.545,"e":null,"co":"IT","region":"Alto Adige / Südtirol","cat":"national-park","themes":["panoramic-view","hike-required","special-experience","car-accessible","summer-only"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":4,"sc":8,"td":"Italy's second largest national park (135,000 ha), est. 1935, encompassing the Ortler massif (3,905 m, highest peak entirely in South Tyrol) and the Stelvio Pass. The South Tyrol sector includes the Sulden/Solda valley with the Ortler glacier and ibex populations.","rs":"The wildest corner of South Tyrol: golden eagles, ibex herds on moraines, and the Ortler's hanging glaciers. The Sulden valley provides easy access to one of the most dramatic high-alpine landscapes in the Eastern Alps.","wl":"en","wt":"Stelvio National Park","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/L%27Ortler.jpg?width=800"},
  {"n":"Vipiteno / Sterzing","la":46.88333,"lo":11.43333,"e":null,"co":"IT","region":"Alto Adige / Südtirol","cat":"old-town","themes":["historic","architecture","year-round","hidden-gem"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":1.5,"sc":8,"td":"Most northerly town in Italy at 950 m in the Wipptal, at the foot of the Brenner Pass. Perfectly preserved 15th-century arcaded main street, the Zwölferturm (12 o'clock tower), and the Stadtplatz lined with painted Gothic and Renaissance façades.","rs":"The best-preserved medieval town in South Tyrol, little changed since the silver-mining boom of the 1400s. Its gorgeous pedestrian Stadtplatz is arguably the finest in the region.","wl":"en","wt":"Vipiteno","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Sterzing-Zwoelferturm2.jpg?width=800"},
  {"n":"Antholzer See (Lago di Anterselva)","la":46.88583,"lo":12.16611,"e":1642,"co":"IT","region":"Alto Adige / Südtirol","cat":"alpine-lake","themes":["photogenic","car-accessible","swimmable","summer-only","panoramic-view","hidden-gem"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":1.5,"sc":7,"td":"Alpine lake at 1,642 m in the Antholzertal (Pustertal), 2.7 km perimeter, max depth 38 m. World Biathlon Cup venue at nearby Ruhpolding-replica shooting range. Turquoise water surrounded by dense conifer forest and high Dolomite peaks.","rs":"A quieter, lesser-known cousin of Braies. The combination of biathlon heritage, crystal water and surrounding peaks makes it a superb, crowd-free alternative.","wl":"en","wt":"Antholzer See","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Lago_di_Anterselva.jpg?width=800"},
  {"n":"Bruneck / Brunico","la":46.8,"lo":11.93333,"e":null,"co":"IT","region":"Alto Adige / Südtirol","cat":"village","themes":["historic","family-friendly","year-round","food-drink"],"access":["car","train"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":7,"td":"Main town of the Pustertal at 838 m; dominated by the 14th-century Bishop's Castle (MMM Ripa — Messner Mountain Museum on mountain peoples). Lively pedestrian Via Bastioni. Hub for Kronplatz ski resort and gateway to the Ahrntal and Antholzertal.","rs":"The commercial capital of the Pustertal combines medieval old town character with the Messner Museum's fascinating ethnographic collection. A practical base for the eastern Dolomites.","wl":"en","wt":"Bruneck","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/I-Bruneck_008.jpg?width=800"},
  {"n":"Burg Taufers (Castello di Tures)","la":46.9232,"lo":11.9485,"e":957,"co":"IT","region":"Alto Adige / Südtirol","cat":"castle-fortress","themes":["historic","architecture","car-accessible","photogenic"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":1.5,"sc":7,"td":"Large medieval castle at 957 m above Sand in Taufers (Pustertal), built 1225–1535 by the lords of Taufers. One of the best-preserved fortresses in South Tyrol with original Gothic chapel, knight's hall, dungeon and panoramic towers. Guided tours available.","rs":"The dominant hilltop fortress of the Ahrntal gateway combines a genuine medieval interior — original chapel frescoes, torture chamber and all — with superb views over the Pustertal.","wl":"de","wt":"Burg Taufers","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Burg_Taufers01arch_2011-01-03.jpg?width=800"},
  {"n":"Castelrotto / Kastelruth","la":46.56667,"lo":11.56667,"e":null,"co":"IT","region":"Alto Adige / Südtirol","cat":"village","themes":["photogenic","car-accessible","year-round","family-friendly","panoramic-view"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":1.5,"sc":7,"td":"Picturesque Ladin village at 1,060 m on a sunny plateau above the Eisack valley, with a distinctive church tower visible for miles. Upper gateway to the Seiser Alm cable car. Famous for the Kastelruther Spatzen folk-music group. Charming market square.","rs":"The perfect alpine village archetype — a church spire above red-geranium windowboxes with the Schlern massif looming behind. The gondola to Seiser Alm leaves from just below the village.","wl":"en","wt":"Castelrotto","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Kastelruth_mit_Kirche_Sankt_Peter_und_Paul.jpg?width=800"},
  {"n":"Earth Pyramids of Renon (Rittner Erdpyramiden)","la":46.5525,"lo":11.47028,"e":null,"co":"IT","region":"Alto Adige / Südtirol","cat":"geology-cave","themes":["photogenic","panoramic-view","cable-car","car-accessible","family-friendly","hidden-gem"],"access":["cable-car","car","foot"],"season":["spring","summer","autumn"],"dur":1.5,"sc":7,"td":"Natural hoodoo formations of glacial moraine on the Ritten/Renon plateau above Bolzano, 15–20 m pillars each capped by a protective boulder. Three main groups at Lengmoos, Mittelberg, and Unterinn. Reached by cable car from Bolzano then vintage Rittner Bahn tram.","rs":"The most accessible geological wonder in South Tyrol: a forest of slender earth towers, each balancing a glacial boulder like a hat, with the Dolomites as a backdrop. The vintage tram adds a charming extra dimension.","wl":"en","wt":"Earth pyramids of Renon","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/RittnerErdpyramiden.jpg?width=800"},
  {"n":"Kalterer See (Lago di Caldaro)","la":46.3775,"lo":11.2625,"e":216,"co":"IT","region":"Alto Adige / Südtirol","cat":"alpine-lake","themes":["swimmable","car-accessible","family-friendly","food-drink","year-round"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":7,"td":"Shallowest and warmest Alpine lake, surface 1.4 km², max depth 5.6 m, at 216 m in the heart of the Südtiroler Weinstraße wine road. Water reaches 28 °C in summer. Beach lidos, pedalo hire; surrounded by Gewürztraminer and Lagrein vineyards.","rs":"The warmest swimming lake in the Alps, set amid vineyard terraces where local Vernatsch wine flows freely. A relaxed summer afternoon of lake and lido backed by wine-tasting.","wl":"en","wt":"Kalterer See","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/KaltererSeePanoVonAltenburg.jpg?width=800"},
  {"n":"Kaltern / Caldaro — Südtiroler Weinstraße (South Tyrolean Wine Road)","la":46.41667,"lo":11.25,"e":null,"co":"IT","region":"Alto Adige / Südtirol","cat":"wine-region","themes":["food-drink","car-accessible","year-round","swimmable","family-friendly"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":7,"td":"Centre of the 73 km Südtiroler Weinstraße wine route at 425 m. Kaltern's winery cooperative (one of 14 on the route) produces DOC Lago di Caldaro Schiava and Gewürztraminer. Combined with the warm Kalterer See bathing lake, it is South Tyrol's premier wine-and-swim destination.","rs":"Sipping Gewürztraminer at a family cantina above the warmest lake in the Alps, with vineyard terraces cascading to the water's edge — the most Epicurean afternoon in South Tyrol.","wl":"en","wt":"Kaltern an der Weinstraße","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/KalternMarktplatzPano.jpg?width=800"},
  {"n":"Klausen / Chiusa","la":46.63333,"lo":11.56667,"e":null,"co":"IT","region":"Alto Adige / Südtirol","cat":"village","themes":["historic","architecture","photogenic","hidden-gem","year-round"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":1.5,"sc":7,"td":"One of the 'Most Beautiful Villages in Italy' (Borghi più belli d'Italia), at 523 m in the Eisacktal. Medieval lanes, painted façades, and the dramatic cliff-top Säben Abbey directly above the town. Former artists' colony in the 19th century.","rs":"An intimate medieval town where a Benedictine monastery perches on a sheer cliff 300 m above, reached by a footpath through terraced vineyards. One of the most dramatic ecclesiastical settings in the Alps.","wl":"en","wt":"Klausen, South Tyrol","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Chiusa_-_Klausen.jpg?width=800"},
  {"n":"Latemar","la":46.36667,"lo":11.56667,"e":2842,"co":"IT","region":"Alto Adige / Südtirol","cat":"mountain-summit","themes":["photogenic","panoramic-view","hike-required","summer-only"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":7,"td":"Compact dolomite massif at 2,842 m on the South Tyrol / Trentino border, best known as the jagged backdrop to Lake Carezza. The Latemar Klettersteig (Via Ferrata) circuit provides accessible ridge adventure. Geological geopark site.","rs":"The saw-toothed skyline that makes Lake Carezza one of the world's most photographed lakes. From the summit circuit the views over the Eggental and the Seiser Alm plateau are superb.","wl":"en","wt":"Latemar","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Latemar_01.jpg?width=800"},
  {"n":"Plose","la":46.69556,"lo":11.73333,"e":2562,"co":"IT","region":"Alto Adige / Südtirol","cat":"viewpoint-panorama","themes":["panoramic-view","cable-car","winter-sport","year-round","family-friendly"],"access":["cable-car","car","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":7,"td":"Mountain massif at 2,562 m above Brixen/Bressanone, reached by cable car from Brixen Milland. Broad summit plateau with panorama of Dolomites and central Alps. Ski resort in winter; easy summer hikes and mountain-biking trails.","rs":"Brixen's 'home mountain' gives effortless access to a wide Dolomite panorama without the crowds of more famous peaks. A local gem combining a relaxed summit with diverse trails.","wl":"en","wt":"Plose","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Plose.jpg?width=800"},
  {"n":"Säben Abbey (Kloster Säben / Monastero di Sabiona)","la":46.64639,"lo":11.56833,"e":null,"co":"IT","region":"Alto Adige / Südtirol","cat":"monastery-church","themes":["historic","architecture","hike-required","photogenic","panoramic-view"],"access":["foot"],"season":["spring","summer","autumn"],"dur":1,"sc":7,"td":"Benedictine nunnery on a sheer 300 m cliff above Klausen, 7th-century episcopal see of Sabiona. Accessible only on foot via a 30-min vineyard path. Church complex with Romanesque holy-water basin and pilgrimage chapel. Nuns left in 2021 after 335 years.","rs":"Few places in the Alps command such a theatrical setting — a white cluster of chapel towers perched impossibly on a cliff above a medieval town. The short hike through the vines is part of the magic.","wl":"en","wt":"Saben Abbey","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Kloster_Saben.jpg?width=800"},
  {"n":"Toblach / Dobbiaco","la":46.73333,"lo":12.21667,"e":null,"co":"IT","region":"Alto Adige / Südtirol","cat":"village","themes":["historic","car-accessible","year-round","family-friendly"],"access":["car","train"],"season":["spring","summer","autumn","winter"],"dur":1.5,"sc":7,"td":"Resort village at 1,256 m at the junction of the Pustertal and Höhlensteintal, gateway to the Tre Cime road. Mahler composed his 9th Symphony here. Historic pilgrimage church of St. John the Baptist; cross-country skiing mecca in winter.","rs":"The most convenient base for the Tre Cime — the toll road starts 15 km south. The village itself is pleasantly unspoilt, with easy access to the high Dolomite valleys on three sides.","wl":"en","wt":"Toblach","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Dobbiaco.JPG?width=800"},

  /* ── Veneto ────────────────────────────────────────── */
  {"n":"Cortina d'Ampezzo","la":46.54028,"lo":12.13611,"e":1224,"co":"IT","region":"Veneto","cat":"village","themes":["iconic","year-round","winter-sport","family-friendly","cable-car","panoramic-view"],"access":["car","train"],"season":["spring","summer","autumn","winter"],"dur":4,"sc":10,"td":"Italy's most glamorous alpine resort (1224 m) at the heart of the Ampezzo Dolomites UNESCO site. Twice Winter Olympics host (1956, 2026). Surrounded by Tofane, Cristallo, Sorapiss and Faloria; gateway to six iconic Dolomite attractions.","rs":"Cortina combines world-class skiing and hiking, chic Corso Italia shopping and the densest concentration of Dolomite giants of any resort — the essential Veneto Alps base.","wl":"en","wt":"Cortina d'Ampezzo","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Faloria_Cortina_d%27Ampezzo_10.jpg?width=800"},
  {"n":"Lago di Sorapis","la":46.52056,"lo":12.22333,"e":1925,"co":"IT","region":"Veneto","cat":"alpine-lake","themes":["photogenic","iconic","hike-required","summer-only","panoramic-view"],"access":["foot"],"season":["summer","autumn"],"dur":5,"sc":10,"td":"Turquoise glacial lake at 1925 m beneath the Sorapiss massif, reachable only on foot from Passo Tre Croci (10.5 km return, 430 m ascent with fixed cables). Its vivid colour comes from dolomite rock flour suspended in glacial meltwater.","rs":"Arguably the most photogenic alpine lake in the Dolomites — the impossible turquoise water framed by grey Dolomite pinnacles has become one of Italy's most-shared hiking destinations.","wl":"en","wt":"Lake Sorapiss","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Lago_di_Sorapis_1.jpg?width=800"},
  {"n":"Marmolada","la":46.43472,"lo":11.85083,"e":3343,"co":"IT","region":"Veneto","cat":"glacier","themes":["unesco","iconic","panoramic-view","cable-car","historic","winter-sport","photogenic"],"access":["cable-car"],"season":["summer","winter"],"dur":3,"sc":10,"td":"Queen of the Dolomites and highest Dolomite peak (3343 m, Punta Penia). The only large Dolomite glacier clothes its north face. Cable car from Malga Ciapela (Province of Belluno) rises to Punta Rocca (3265 m) with a 360° panorama across five regions.","rs":"The shrinking Marmolada glacier carries haunting WWI history and the supreme Dolomite panorama in a single cable-car ride — unmissable as both a scenic and historical experience.","wl":"en","wt":"Marmolada","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Marmolata,_3343m.jpg?width=800"},
  {"n":"Tre Cime di Lavaredo","la":46.617,"lo":12.3,"e":2999,"co":"IT","region":"Veneto","cat":"viewpoint-panorama","themes":["unesco","iconic","photogenic","panoramic-view","hike-required","car-accessible","summer-only"],"access":["car","foot"],"season":["summer","autumn"],"dur":4,"sc":10,"td":"Three iconic Dolomite spires (Cima Grande 2999 m) in the Sexten Dolomites UNESCO World Heritage site. The 10 km circuit from Rifugio Auronzo (car-accessible toll road) via Rifugio Lavaredo and Locatelli is the most visited hike in the Italian Alps.","rs":"The unmistakable silhouette of the Drei Zinnen defines the Dolomites worldwide. Sunrise north-face shots from Rifugio Locatelli are among the most photographed alpine images on earth.","wl":"en","wt":"Tre Cime di Lavaredo","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/2019_Tre_Cime.jpg?width=800"},
  {"n":"Cadini di Misurina Viewpoint","la":46.59,"lo":12.25,"e":2100,"co":"IT","region":"Veneto","cat":"viewpoint-panorama","themes":["photogenic","iconic","hike-required","panoramic-view","car-accessible"],"access":["car","foot"],"season":["summer","autumn"],"dur":2,"sc":9,"td":"Rocky outcrop at ~2100 m reached via a 3.2 km loop from Rifugio Auronzo (toll road from Misurina). The spires of the Cadini di Misurina frame the Tre Cime beyond sheer cliffs — the most shared photographic composition in the eastern Dolomites.","rs":"The supreme secondory viewpoint of the Dolomites: a sub-two-hour stroll from a car park delivers a breathtaking layered spire view that rivals anything achieved by a full mountain ascent.","wl":"en","wt":"Cadini di Misurina","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Cadini_di_Misurina_Lavaredo_4.jpg?width=800"},
  {"n":"Cinque Torri","la":46.51016,"lo":12.05207,"e":2361,"co":"IT","region":"Veneto","cat":"viewpoint-panorama","themes":["photogenic","panoramic-view","historic","cable-car","summer-only"],"access":["car","cable-car","foot"],"season":["summer","autumn"],"dur":3,"sc":9,"td":"Five Dolomite rock towers reaching 2361 m southwest of Cortina, accessible by gondola from Pocol or a short hike. The plateau preserves a fully restored open-air WWI museum with trenches, shelters and gun emplacements on the former Italian-Austrian front.","rs":"Spectacular photogenic towers with 360° Dolomite panoramas and an immersive WWI walk-through — one of the most rewarding and accessible half-day excursions anywhere near Cortina.","wl":"en","wt":"Cinque Torri","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Cortina_(50162425826).jpg?width=800"},
  {"n":"Lagazuoi","la":46.52972,"lo":12.00306,"e":2752,"co":"IT","region":"Veneto","cat":"viewpoint-panorama","themes":["panoramic-view","historic","cable-car","photogenic","winter-sport"],"access":["cable-car","foot"],"season":["summer","winter"],"dur":4,"sc":9,"td":"Mountain at 2835 m above Passo Falzarego served by cable car to Rifugio Lagazuoi (2752 m). Contains ~1 km of WWI mine-warfare tunnels open as a self-guided museum. The summit panorama encompasses Marmolada, Tofane, Pelmo and the Dolomites of Cortina.","rs":"A seven-minute cable-car ride plus descent through Italian WWI tunnels carved into living rock — Lagazuoi delivers Dolomites history and panorama in a uniquely immersive combination.","wl":"en","wt":"Lagazuoi","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Lagazuoi_cable_car_2.jpg?width=800"},
  {"n":"Lake Misurina","la":46.58194,"lo":12.25389,"e":1754,"co":"IT","region":"Veneto","cat":"alpine-lake","themes":["iconic","photogenic","car-accessible","family-friendly","year-round"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":9,"td":"Largest natural lake of the Cadore at 1754 m, mirroring the Tre Cime group to the north. Hosted 1956 Olympic speed skating on natural ice. The 2.6 km paved lakeside path is accessible year-round; the road to Rifugio Auronzo departs from here.","rs":"Drive-up accessibility combined with epic Dolomite reflections at sunrise makes Misurina the quintessential car-accessible lake stop on any eastern Dolomites itinerary.","wl":"en","wt":"Lake Misurina","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Lago_di_misurina.jpg?width=800"},
  {"n":"Monte Civetta","la":46.38,"lo":12.05333,"e":3220,"co":"IT","region":"Veneto","cat":"mountain-summit","themes":["iconic","panoramic-view","hike-required","summer-only"],"access":["cable-car","foot"],"season":["summer"],"dur":8,"sc":8,"td":"Dominant 3220 m peak in the Province of Belluno with a legendary 1000 m northwest face first climbed at grade VI in 1925 by Emil Solleder. One of the 'great walls of the Alps'. A cable car from Alleghe (979 m) reaches 1620 m; the summit demands experienced alpinism.","rs":"The Civetta north wall is one of the defining images of Dolomite alpinism; even from the Alleghe cable car the sheer scale of the face — and its reflection in the lake — is overwhelming.","wl":"en","wt":"Monte Civetta","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Monte_Civetta_Caprile.jpg?width=800"},
  {"n":"Monte Grappa Military Memorial","la":45.87333,"lo":11.79917,"e":1775,"co":"IT","region":"Veneto","cat":"museum-cultural","themes":["historic","panoramic-view","car-accessible"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":3,"sc":8,"td":"Summit of Monte Grappa (1775 m, Venetian Prealps) crowned by the Sacrario Militare (1935): five concentric stone circles containing the remains of 22,950 Italian and Austro-Hungarian WWI dead. The mountain was the last line of Italian defence after Caporetto (1917).","rs":"Monte Grappa's summit ossuary — accessible by road — distils the tragedy of the Alpine Front with awesome solemnity; the panorama from Venetian plain to Dolomites is one of the finest viewpoints in Veneto.","wl":"en","wt":"Monte Grappa","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Monte_Grappa_2025.jpg?width=800"},
  {"n":"Monte Pelmo","la":46.41972,"lo":12.13472,"e":3168,"co":"IT","region":"Veneto","cat":"mountain-summit","themes":["iconic","hike-required","summer-only","panoramic-view"],"access":["foot"],"season":["summer"],"dur":8,"sc":8,"td":"Solitary 3168 m Dolomite throne nicknamed 'God's armchair' in the Province of Belluno. First major Dolomite peak climbed (John Ball, 1857). 220-million-year-old dinosaur footprints are preserved on its western flank at around 2400 m.","rs":"Pelmo's isolated block silhouette dominates the Zoldo valley horizon — one of the most distinctive shapes in the Dolomites, rewarding fit hikers with genuine solitude and prehistoric wonder.","wl":"en","wt":"Monte Pelmo","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Monte_Pelmo_2.jpg?width=800"},
  {"n":"Passo Falzarego","la":46.51889,"lo":12.00944,"e":2105,"co":"IT","region":"Veneto","cat":"viewpoint-panorama","themes":["panoramic-view","car-accessible","photogenic","historic","year-round"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":8,"td":"Major Dolomite pass at 2105 m on the Great Dolomites Road (SS48) linking Cortina d'Ampezzo and Agordo. Base station of the Lagazuoi cable car. Views embrace Lagazuoi, Sass de Stria, Tofane and Averau; scene of fierce WWI combat between 1915 and 1918.","rs":"One of the great Dolomite pass panoramas — free to drive year-round, with the Lagazuoi cable car right at the pass and a WWI landscape stretching in every direction.","wl":"en","wt":"Falzarego Pass","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Passo_Falzarego_SR48.jpg?width=800"},
  {"n":"Passo Giau","la":46.4825,"lo":12.05389,"e":2236,"co":"IT","region":"Veneto","cat":"viewpoint-panorama","themes":["panoramic-view","car-accessible","photogenic","summer-only"],"access":["car","foot"],"season":["summer","autumn"],"dur":2,"sc":8,"td":"High Dolomite pass at 2236 m between Cortina and Selva di Cadore, set in sweeping alpine meadows. 360° panorama encompasses Ra Gusela, Marmolada, Nuvolau, Averau and the Cortina basin. One of the Maratona dles Dolomites classic cols.","rs":"Passo Giau's wide-open plateau and unobstructed 360° horizon make it the most cinematically beautiful scenic drive in Veneto — unforgettable at dawn when alpenglow hits the surrounding spires.","wl":"en","wt":"Giau Pass","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Passo_di_Giau.jpg?width=800"},
  {"n":"Strada delle 52 Gallerie","la":45.779,"lo":11.228,"e":1216,"co":"IT","region":"Veneto","cat":"special-experience","themes":["historic","hike-required","special-experience","summer-only"],"access":["foot"],"season":["summer","autumn"],"dur":5,"sc":8,"td":"6.5 km WWI military mule road on Monte Pasubio (Province of Vicenza), pierced by 52 numbered tunnels excavated from solid rock in 1917. Tunnel 19 (320 m) spirals inside a rock tower with four helical hairpin bends. Climbs 750 m from Bocchetta Campiglia to Porte del Pasubio.","rs":"Walking through 52 hand-carved WWI tunnels spiralling up a mountain is one of the most extraordinary hiking experiences in the Alps — no other trail in Italy equals its combination of history, geology and dramatic engineering.","wl":"en","wt":"Strada delle 52_Gallerie","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Inizio_strada_52_gallerie.jpg?width=800"},
  {"n":"Tofane","la":46.533,"lo":12.05,"e":3244,"co":"IT","region":"Veneto","cat":"mountain-summit","themes":["cable-car","panoramic-view","winter-sport","iconic","photogenic"],"access":["cable-car","foot"],"season":["summer","winter"],"dur":3,"sc":8,"td":"Three-peak massif west of Cortina — Tofana di Mezzo (3244 m) is the third highest Dolomite summit. The Freccia nel Cielo three-stage cable car from Cortina reaches near the Tofana di Mezzo summit. Host of alpine ski events at the 1956 and 2026 Winter Olympics.","rs":"The Freccia nel Cielo delivers one of the most breathtaking Dolomites panoramas without requiring mountain experience — and the Tofane dominate every postcard view of Cortina.","wl":"en","wt":"Tofane","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Die_Tofane_im_Herbst_2021.jpg?width=800"},
  {"n":"Vajont Dam","la":46.26722,"lo":12.32889,"e":null,"co":"IT","region":"Veneto","cat":"bridge-engineering","themes":["historic","special-experience","car-accessible"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":3,"sc":8,"td":"262 m double-arch arch dam — one of the world's tallest — in the Vajont gorge above Longarone (Province of Belluno). On 9 October 1963 a megatsunami generated by a landslide overtopped the dam by 250 m, destroying Longarone and killing up to 2500 people.","rs":"Europe's most sobering engineering-disaster memorial: the intact dam wall looms above the silted lake while the ghost village of Erto stands unchanged — a haunting lesson in hubris that still demands to be seen.","wl":"en","wt":"Vajont Dam","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/VajontDiga.jpg?width=800"},
  {"n":"Asiago","la":45.867,"lo":11.517,"e":1001,"co":"IT","region":"Veneto","cat":"village","themes":["historic","year-round","winter-sport","car-accessible","panoramic-view","food-drink"],"access":["car"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":7,"td":"Main town of the Altopiano dei Sette Comuni plateau (1001 m, Province of Vicenza). Pivotal WWI battleground (Battle of Asiago, 1916); home to the Asiago DOP cheese and the University of Padua Astrophysical Observatory. Major winter-ski and summer-hiking destination.","rs":"Asiago blends WWI history, alpine scenery, world-famous cheese and professional star-gazing on one beautiful plateau — a uniquely multi-layered destination reachable from Vicenza in 90 minutes.","wl":"en","wt":"Asiago","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Asiago_-_2615694751.jpg?width=800"},
  {"n":"Belluno","la":46.14028,"lo":12.21667,"e":null,"co":"IT","region":"Veneto","cat":"old-town","themes":["historic","architecture","year-round","car-accessible"],"access":["car","train"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":7,"td":"Provincial capital of the Dolomites at 390 m on a limestone bluff above the confluence of the Piave and Ardo rivers. The historic centre features Venetian palaces, the 18th-century Duomo, Palazzo dei Rettori and sweeping views northward to the Dolomite foothills.","rs":"Belluno is the most graceful small city in the Dolomites — its Venetian-era streetscape, excellent regional restaurants and relaxed pace make it the most civilised base for exploring the whole province.","wl":"en","wt":"Belluno","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Belluno_5042.jpg?width=800"},
  {"n":"Croda da Lago","la":46.483,"lo":12.1,"e":2715,"co":"IT","region":"Veneto","cat":"viewpoint-panorama","themes":["hike-required","hidden-gem","panoramic-view","photogenic","summer-only"],"access":["foot"],"season":["summer","autumn"],"dur":5,"sc":7,"td":"Compact Dolomite ridge (Cima d'Ambrizzola 2715 m) east of Passo Giau. The classic circuit visits Lago Federa (2046 m), a turquoise lake cradled under pale cliffs. Rifugio Palmieri sits directly on the lake shore with a panorama of Pelmo, Civetta and Marmolada.","rs":"Croda da Lago's Lago Federa circuit is the Dolomites' best-kept secret near Cortina — pristine lake, dramatic spire scenery and a fraction of the crowds found at more famous destinations.","wl":"en","wt":"Croda da Lago","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Croda_da_Lago_nord.jpg?width=800"},
  {"n":"Feltre","la":46.01861,"lo":11.91,"e":null,"co":"IT","region":"Veneto","cat":"old-town","themes":["historic","architecture","year-round","car-accessible"],"access":["car","train"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":7,"td":"Beautifully preserved medieval hill town at 325 m in the southern Province of Belluno. The walled Città Alta contains Renaissance frescoed palaces, a 16th-century cathedral and the Piazza Maggiore virtually unchanged since Venetian rule. Gateway to Dolomiti Bellunesi NP.","rs":"Feltre is one of Italy's most underrated Renaissance towns — its frescoed façades, city walls and pedestrianised historic core are almost tourist-free compared to any other Dolomite gateway.","wl":"en","wt":"Feltre","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/PanoramaFeltre.jpg?width=800"},
  {"n":"Lake Alleghe","la":46.406,"lo":12.015,"e":979,"co":"IT","region":"Veneto","cat":"alpine-lake","themes":["photogenic","car-accessible","family-friendly","year-round","panoramic-view"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":7,"td":"Natural lake at 979 m formed by a catastrophic 1771 landslide that dammed the Cordevole river, killing 49 people. The village of Alleghe occupies a peninsula; Monte Civetta's immense north wall towers overhead. Cable car to the Civetta ski area departs from town.","rs":"Lake Alleghe delivers the iconic Civetta north-face reflection from an easy lakeside promenade — the combination of a medieval lakeside village, alpine scenery and cable-car access is hard to beat.","wl":"en","wt":"Lake Alleghe","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Alleghe_vista_dall%27alto.jpg?width=800"},
  {"n":"Museo Grande Guerra Marmolada","la":46.43,"lo":11.87167,"e":3069,"co":"IT","region":"Veneto","cat":"museum-cultural","themes":["historic","cable-car","panoramic-view","special-experience"],"access":["cable-car"],"season":["summer"],"dur":3,"sc":7,"td":"WWI museum at Punta Serauta (3069 m) on the Veneto flank of Marmolada, reached by cable car from Malga Ciapela (Rocca Pietore, Province of Belluno). Commemorates the 'White War' on the glacier — in 1916 Austro-Hungarian troops built an underground 'ice city' in the glacier.","rs":"The only high-altitude glacier museum in the Dolomites combines a panoramic cable-car ascent at 3069 m with profoundly moving WWI relics preserved in and around the rapidly retreating Marmolada glacier.","wl":"en","wt":"Marmolada Glacier","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Marmolada_glacier.jpg?width=800"},
  {"n":"Serrai di Sottoguda","la":46.4433,"lo":11.9,"e":1300,"co":"IT","region":"Veneto","cat":"waterfall-gorge","themes":["special-experience","car-accessible","family-friendly","photogenic","summer-only"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":7,"td":"Narrow limestone gorge at the foot of Marmolada near Sottoguda (Rocca Pietore, Province of Belluno). The flat 2 km path follows the Pettorina torrent between rock walls up to 200 m high that close to barely 2 m apart, with waterfalls and natural ice sculptures in winter.","rs":"The Serrai di Sottoguda is the most dramatic gorge in the Veneto Dolomites — a flat, family-friendly walk through sheer walls beneath the Marmolada massif that requires no climbing at all.","wl":"it","wt":"Serrai di Sottoguda","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Serrai_di_Sottoguda.jpg?width=800"},
  {"n":"Auronzo di Cadore","la":46.55,"lo":12.433,"e":862,"co":"IT","region":"Veneto","cat":"village","themes":["car-accessible","family-friendly","year-round","photogenic"],"access":["car"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":6,"td":"Mountain resort at 862 m on Lake Santa Caterina in the Cadore Dolomites (Province of Belluno). Includes the municipality of Misurina. The toll road from town to Rifugio Auronzo (2320 m) is the only vehicle access point for the Tre Cime circuit.","rs":"Auronzo is the essential staging-post for Tre Cime visitors and a pleasant lakeside resort in its own right — the drive up to Rifugio Auronzo through switchbacks is one of the great Dolomite approach roads.","wl":"en","wt":"Auronzo di Cadore","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/2019_Auronzo_di_Cadore.jpg?width=800"},
  {"n":"Castello di Andraz","la":46.4833,"lo":11.96,"e":1400,"co":"IT","region":"Veneto","cat":"castle-fortress","themes":["historic","architecture","hidden-gem","car-accessible","panoramic-view"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":6,"td":"Ruined medieval castle at ~1400 m in Livinallongo del Col di Lana (Province of Belluno), perched on a rocky spur above the Col di Lana WWI battlefields. Originally a bishops' fortress guarding the route to the Passo Falzarego; partially restored and open seasonally.","rs":"Castello di Andraz is a strikingly positioned Dolomite castle standing sentinel above one of WWI's most contested valleys — the combination of medieval ruins and Dolomite panorama is unique in the Veneto Alps.","wl":"it","wt":"Castello di Andraz","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Castello_di_Andraz.jpg?width=800"},
  {"n":"Cibiana di Cadore","la":46.383,"lo":12.283,"e":1025,"co":"IT","region":"Veneto","cat":"village","themes":["hidden-gem","architecture","car-accessible"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":6,"td":"Tiny hamlet at 1025 m in the Cadore Dolomites, celebrated since the 1980s as the 'village of murals' — over 80 large-format paintings on house walls depict Cadore traditions, alpine craftsmen and Dolomite legends by Italian and international artists.","rs":"Cibiana is an open-air gallery hidden in the forest — its murals create a surreal and deeply moving encounter with Cadore folk culture in a genuinely remote and car-accessible mountain village.","wl":"en","wt":"Cibiana di Cadore","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Cibiana_di_Cadore_2.jpg?width=800"},
  {"n":"Forte Verena","la":45.93056,"lo":11.41306,"e":2019,"co":"IT","region":"Veneto","cat":"castle-fortress","themes":["historic","hike-required","panoramic-view","summer-only"],"access":["foot"],"season":["summer","autumn"],"dur":5,"sc":6,"td":"Italian WWI fort at 2019 m on Monte Verena (Asiago Plateau, Province of Vicenza). At 03:55 on 24 May 1915 it fired Italy's first shots of WWI. Destroyed by a Skoda 305 mm shell in June 1915, its shattered domes and gun casemates survive as a monument.","rs":"A pilgrimage to the exact spot where Italy entered WWI — the ruined Forte Verena on the Asiago plateau delivers haunting atmosphere and a commanding view of the former front lines across Val d'Assa.","wl":"en","wt":"Forte Verena","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Forte_Verena_abc14.jpg?width=800"},
  {"n":"Lago del Mis","la":46.2,"lo":12.1033,"e":650,"co":"IT","region":"Veneto","cat":"alpine-lake","themes":["hidden-gem","family-friendly","car-accessible","swimmable","panoramic-view"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":6,"td":"Emerald-green reservoir at ~650 m within the Dolomiti Bellunesi National Park, created by damming the Mis torrent. Enclosed by forested limestone gorges; the flat lakeside trail through old-growth woodland is one of the park's most family-friendly walks.","rs":"A hidden gem inside the national park — vivid green water backed by white limestone walls and ancient forest makes Lago del Mis one of the most serene and uncrowded lakes in the Veneto Alps.","wl":"it","wt":"Lago del Mis","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Lago_del_Mis.jpg?width=800"},
  {"n":"Lago di Santa Croce","la":46.1057,"lo":12.3358,"e":386,"co":"IT","region":"Veneto","cat":"alpine-lake","themes":["car-accessible","family-friendly","swimmable","special-experience","year-round"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":6,"td":"Semi-natural lake at 386 m in the Alpago basin (Province of Belluno), enlarged by a 1930s dam to 7.2 km². Strong thermal winds funnel through surrounding mountains making it one of Veneto's premier kitesurfing and windsurfing venues.","rs":"The consistent Alpago winds, warm summer water and dramatic Pre-Alps backdrop make Lago di Santa Croce the go-to watersports lake of eastern Veneto — equally spectacular for lakeside cyclists.","wl":"en","wt":"Lago di Santa Croce","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Lago_di_Santa_Croce_2025.jpg?width=800"},
  {"n":"Pieve di Cadore","la":46.433,"lo":12.367,"e":878,"co":"IT","region":"Veneto","cat":"village","themes":["historic","car-accessible","architecture"],"access":["car"],"season":["spring","summer","autumn"],"dur":2,"sc":6,"td":"Historic mountain town at 878 m on Lake Pieve di Cadore, birthplace of Renaissance painter Titian (c. 1490). Features the Palazzo della Magnifica Comunità (1447), a merloned medieval tower, the Museo Cadorino and Titian's preserved birthplace house-museum.","rs":"Birthplace of Titian and historic capital of the Cadore — the compact old town and the museum-house where the world's greatest Venetian painter was born make Pieve an essential cultural stop on the Dolomite route.","wl":"en","wt":"Pieve di Cadore","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Pieve_di_Cadore%2C_Febbraio_2023_%281%29.jpg?width=800"},
  {"n":"San Vito di Cadore","la":46.45,"lo":12.217,"e":1011,"co":"IT","region":"Veneto","cat":"village","themes":["car-accessible","panoramic-view","year-round","family-friendly"],"access":["car"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":5,"td":"Compact Dolomite village at 1011 m on the SS51 Alemagna road between Belluno and Cortina (Province of Belluno). Stands directly beneath Monte Antelao (3264 m), the second highest Dolomite peak. A year-round resort with ski and hiking facilities.","rs":"San Vito sits at the crossroads of some of the finest Dolomite scenery — the direct view of Antelao from the village piazza is one of the most dramatic mountain backdrops of any inhabited place in Veneto.","wl":"en","wt":"San Vito di Cadore","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/S._Vito_di_Cadore_PLM.JPG?width=800"},
  {"n":"Zumelle Castle","la":46.03625,"lo":12.08167,"e":null,"co":"IT","region":"Veneto","cat":"castle-fortress","themes":["historic","architecture","hidden-gem","car-accessible"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":5,"td":"Well-preserved medieval castle at Tiago (Borgo Valbelluna, Province of Belluno) with origins in the Roman period. Rebuilt in 1311 by Rizzardo IV da Camino. Adjacent to the early medieval church of San Donato. Currently owned by the commune of Mel and open to visitors.","rs":"Zumelle is the most complete and atmospheric medieval castle in the Province of Belluno — its Roman-to-Venetian history, adjacent Lombard church and panoramic hilltop position make it a rewarding detour from the Belluno valley.","wl":"en","wt":"Zumelle Castle","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/CastelloZumelle.jpg?width=800"},

  /* ── Lombardia ────────────────────────────────────────── */
  {"n":"Bellagio","la":45.98333,"lo":9.25,"e":229,"co":"IT","region":"Lombardia","cat":"village","themes":["iconic","photogenic","car-accessible","boat-accessible","year-round","historic","food-drink"],"access":["car","boat","foot"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":10,"td":"The 'Pearl of Lake Como', poised at the promontory tip where the lake's three arms converge. Silk boutiques, geranium-draped stepped alleys, a lakeside promenade, Villa Serbelloni gardens and the best three-way Alpine panorama on Lario.","rs":"Standing here you see three arms of Lake Como simultaneously — Como, Lecco and Colico — with snow-capped Alps in every direction. No other lake village in Italy can match it.","wl":"en","wt":"Bellagio (Italian region)","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Sentiero_del_Viandante_DSC_6340_(14020554463).jpg?width=800"},
  {"n":"Bergamo Alta (Città Alta)","la":45.70278,"lo":9.66111,"e":377,"co":"IT","region":"Lombardia","cat":"old-town","themes":["unesco","iconic","photogenic","panoramic-view","historic","architecture","food-drink","cable-car"],"access":["car","funicular","foot"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":10,"td":"UNESCO World Heritage upper city (Città Alta) encircled by 6 km of immaculately preserved 16th-century Venetian walls. Piazza Vecchia, Romanesque Basilica di Santa Maria Maggiore, Colleoni Chapel and the historic funicular from lower Bergamo.","rs":"The most beautiful fortified hill city in northern Italy — walking through the Venetian gates feels like entering a living Renaissance painting suspended above the Po Valley with the Alps as backdrop.","wl":"en","wt":"Bergamo","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/The_Upper_City_of_Bergamo._View_from_Via_al_Castello._Italy.jpg?width=800"},
  {"n":"Lago di Como","la":46.0,"lo":9.26667,"e":198,"co":"IT","region":"Lombardia","cat":"alpine-lake","themes":["iconic","photogenic","car-accessible","boat-accessible","year-round","swimmable"],"access":["car","train","boat","foot"],"season":["spring","summer","autumn","winter"],"dur":4,"sc":10,"td":"Italy's deepest lake (425 m) and deepest in Europe, Y-shaped glacial masterpiece at the Alpine foothills, 46 km long. Ringed by belle époque villas, lemon groves and Jurassic limestone peaks. Aristocratic retreat since Julius Caesar.","rs":"The quintessential Italian lake: historic villa gardens, clifftop villages, shimmering reflections and some of Europe's most cinematic water-to-mountain scenery in one place.","wl":"en","wt":"Lake Como","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Lago_di_Como_panorama.jpg?width=800"},
  {"n":"Sirmione","la":45.46944,"lo":10.60611,"e":66,"co":"IT","region":"Lombardia","cat":"old-town","themes":["iconic","photogenic","car-accessible","boat-accessible","year-round","historic","spa-wellness","swimmable"],"access":["car","boat","foot"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":10,"td":"Enchanting walled medieval peninsula jutting 4 km into southern Lake Garda, crowned by the moated 13th-century Scaligeri castle. Roman ruins (Grotte di Catullo, 1st c. BC) and sulphurous thermal springs still flowing at the Terme di Sirmione.","rs":"Few places on earth combine a moated castle rising from open water, actual Roman villa ruins and a working thermal spa in a single car-free medieval peninsula — pure magic in all seasons.","wl":"en","wt":"Sirmione","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Italy_-_Sirmione.jpg?width=800"},
  {"n":"Tirano & Bernina Express","la":46.21639,"lo":10.16889,"e":441,"co":"IT","region":"Lombardia","cat":"scenic-railway","themes":["unesco","iconic","special-experience","panoramic-view","year-round","family-friendly"],"access":["car","train"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":10,"td":"Italian terminus of the UNESCO Rhaetian Railway. The red Bernina Express climbs from Tirano's medieval streets (441 m) to St Moritz (1,775 m) in 4 hrs without rack-and-pinion, via 55 tunnels, 196 bridges and the 2,253 m Ospizio Bernina.","rs":"Boarding the Bernina Express at Tirano is one of the world's greatest rail journeys: a 4-hour ascent from Italian vineyards to Swiss glaciers entirely on adhesion, on a UNESCO-listed metre-gauge line.","wl":"en","wt":"Bernina Express","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/RhB_ABe_4-4_III_56_and_51_Lago_Bianco.jpg?width=800"},
  {"n":"Bormio","la":46.46925,"lo":10.37217,"e":1225,"co":"IT","region":"Lombardia","cat":"spa-wellness","themes":["iconic","year-round","winter-sport","spa-wellness","historic","panoramic-view","food-drink"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":9,"td":"Medieval Valtellina alpine town at 1,225 m, gateway to Stelvio NP and FIS World Cup ski races. Thermal baths — Bagni Vecchi (Roman era, mentioned by Pliny the Elder in AD 77) — still steam beside the historic centro storico with frescoed Renaissance palaces.","rs":"Only in Bormio can you ski a World Cup downhill slope, soak in 2,000-year-old Roman sulphurous springs and stroll a perfectly preserved medieval trading town — all in a single afternoon in the Alps.","wl":"en","wt":"Bormio","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/BORMIO_panoramica.jpg?width=800"},
  {"n":"Monte Isola","la":45.71667,"lo":10.08333,"e":275,"co":"IT","region":"Lombardia","cat":"village","themes":["iconic","photogenic","boat-accessible","year-round","family-friendly","special-experience","swimmable"],"access":["boat","foot"],"season":["spring","summer","autumn"],"dur":4,"sc":9,"td":"Largest lake island in southern and central Europe (4.5 km²), rising to 600 m above Lake Iseo. Entirely car-free, with 1,800 residents, 15th–17th century churches, active fishing fleet, olive groves and the site of Christo's 2016 Floating Piers installation.","rs":"No cars, no noise — just cobbled fishing villages, olive terraces and mountain paths. The island feels profoundly timeless, and circumnavigation by hired bike is one of the Alps' great afternoon rides.","wl":"en","wt":"Monte Isola","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Panorama_di_Montisola_da_Sulzano_(Foto_Luca_Giarelli).jpg?width=800"},
  {"n":"Stelvio National Park (Lombardia side)","la":46.52583,"lo":10.45389,"e":2757,"co":"IT","region":"Lombardia","cat":"national-park","themes":["panoramic-view","photogenic","car-accessible","hike-required","summer-only","special-experience"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":4,"sc":9,"td":"Italy's largest national park (130,734 ha), rising to 3,905 m (Ortler). Italian Lombardia access via the iconic Stelvio Pass (2,757 m, 48 hairpin bends) from Bormio. Glaciers, ibex, golden eagles and the Ortler-Cevedale massif. 2025: 20,000 dinosaur footprints discovered.","rs":"The Stelvio Pass road is one of the greatest Alpine drives on earth — 48 hairpin bends to 2,757 m with ibex grazing the verges, glaciers overhead and the full Ortler massif on the horizon.","wl":"en","wt":"Stelvio National Park","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Zaybach_K%C3%B6nigspitze_Zebr%C3%B9_Ortler.jpg?width=800"},
  {"n":"Villa Carlotta","la":45.98639,"lo":9.23092,"e":200,"co":"IT","region":"Lombardia","cat":"museum-cultural","themes":["photogenic","car-accessible","boat-accessible","year-round","historic","architecture","family-friendly"],"access":["car","boat","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":9,"td":"Baroque-neoclassical villa and botanical garden on the Tremezzina shore, completed 1745. Houses Canova and Thorvaldsen sculptures. World-famous April rhododendron and azalea bloom; 70,000 plants across 8 ha of terraced lakeside gardens.","rs":"Italy's finest lakeside botanical garden — cascading terraces of azaleas and rhododendrons backed by Alpine peaks with the lake below. April bloom is one of Italy's greatest floral spectacles.","wl":"en","wt":"Villa Carlotta","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Tremezzo_-_Villa_Carlotta.jpg?width=800"},
  {"n":"Villa del Balbianello","la":45.97528,"lo":9.20611,"e":210,"co":"IT","region":"Lombardia","cat":"special-experience","themes":["iconic","photogenic","boat-accessible","year-round","historic","architecture","special-experience"],"access":["boat","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":9,"td":"Loggia-crowned 18th-century villa on a wooded headland near Lenno, owned by FAI (Italian National Trust), reached by boat or lakeside trail. Elaborate terraced gardens. Film location for Casino Royale (2006) and Star Wars Episode II.","rs":"One of the world's most romantic villa gardens, jutting into Lake Como on its own wooded peninsula — more fairy-tale than any film set could construct, and a real James Bond location.","wl":"en","wt":"Villa del Balbianello","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/06VillaBalbianello.jpg?width=800"},
  {"n":"Chiavenna","la":46.31667,"lo":9.4,"e":333,"co":"IT","region":"Lombardia","cat":"old-town","themes":["hidden-gem","historic","food-drink","car-accessible","year-round","special-experience"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":8,"td":"Alpine crossroads at the head of Lake Como where the Mera meets the Liro beneath sheer rock faces. Famous for crotti — natural wine cellars in granite boulders that exhale year-round 6–8 °C air — plus a Renaissance collegiate church, sacral garden and Lombard baptistery.","rs":"The crotti of Chiavenna are unique: ancient rock fissures used as natural refrigerators and wine cellars since the Middle Ages, now turned into atmospheric restaurants serving bresaola and local wines.","wl":"en","wt":"Chiavenna","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/2013-08-07_10-14-36_Italy_Lombardia_Chiavenna_Chiavenna.JPG?width=800"},
  {"n":"Como","la":45.81667,"lo":9.08333,"e":201,"co":"IT","region":"Lombardia","cat":"old-town","themes":["iconic","car-accessible","boat-accessible","year-round","historic","architecture","family-friendly","cable-car"],"access":["car","train","boat","foot","funicular"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":8,"td":"Provincial silk capital with a magnificent late-Gothic cathedral (Duomo), Roman walls, Art Nouveau lakefront villas, the Volta Museum (birthplace of the battery) and the 1894 Como–Brunate funicular ascending 500 m to panoramic Brunate.","rs":"The lake's historic gateway city: stroll from Roman amphitheatre to medieval cathedral to Art Nouveau lakefront in an hour, then ride Europe's most scenic funicular up the cliff.","wl":"en","wt":"Como","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Como_and_its_lake.jpg?width=800"},
  {"n":"Lago d'Iseo & Iseo Town","la":45.65861,"lo":10.05361,"e":186,"co":"IT","region":"Lombardia","cat":"alpine-lake","themes":["photogenic","car-accessible","boat-accessible","year-round","swimmable","family-friendly","food-drink"],"access":["car","train","boat","foot"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":8,"td":"The 'secret lake' — Italy's fourth-largest, ringed by steep forested mountains and home to Monte Isola. Iseo town has a medieval tower, Venetian palaces and lakeside promenade. Part of the UNESCO MAB Biosphere Reserve. Superior local fish cuisine.","rs":"Far less touristed than Como or Garda, Iseo packs more geographic drama per square kilometre — fjord-like depths, an enormous car-free island and a genuine local feel that Como lost decades ago.","wl":"en","wt":"Iseo, Lombardy","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Iseo1.jpg?width=800"},
  {"n":"Tremosine sul Garda & Strada della Forra","la":45.76667,"lo":10.76667,"e":414,"co":"IT","region":"Lombardia","cat":"viewpoint-panorama","themes":["photogenic","panoramic-view","car-accessible","year-round","special-experience","hidden-gem"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":8,"td":"Plateau commune 414 m above Garda, accessed via the Strada della Forra — 6 km of road carved through sheer limestone gorge, declared by BBC Top Gear 'the most beautiful road in the world'. Member of I Borghi più Belli d'Italia.","rs":"The Strada della Forra is a vertiginous slot-canyon drive dropping from alpine meadows to the lake in 10 breathtaking minutes — a genuine once-in-a-lifetime road with the lake shimmering below.","wl":"en","wt":"Tremosine sul Garda","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Tremosine_-_Panorama.jpg?width=800"},
  {"n":"Varenna","la":46.01667,"lo":9.28333,"e":220,"co":"IT","region":"Lombardia","cat":"village","themes":["photogenic","car-accessible","boat-accessible","year-round","historic","swimmable"],"access":["car","train","boat","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":8,"td":"Amber-and-terracotta medieval fishing village clinging to Lake Como's eastern shore, reachable by ferry or train. The romantic Passerella lakefront walkway, clifftop Castello di Vezio and botanical gardens of Villa Monastero enchant every visitor.","rs":"Arguably Como's most authentically beautiful village — narrower and quieter than Bellagio, car-free waterfront lanes and jaw-dropping ferry arrival views straight off a film poster.","wl":"en","wt":"Varenna","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Varenna_and_mountain_from_ferry.jpg?width=800"},
  {"n":"Vittoriale degli Italiani, Gardone Riviera","la":45.61667,"lo":10.56667,"e":71,"co":"IT","region":"Lombardia","cat":"special-experience","themes":["photogenic","car-accessible","boat-accessible","year-round","historic","architecture","special-experience"],"access":["car","boat","foot"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":8,"td":"Eccentric hillside estate of poet Gabriele D'Annunzio in Gardone Riviera — a 'monumental citadel' with a cruiser hull embedded in a hillside, amphitheatre, 1918 torpedo boat, biplane, mausoleum and surreal frescoed rooms, set in elaborate gardens.","rs":"The Vittoriale defies all categories: part patriotic shrine, part surrealist museum, part operatic folly — Italy's most theatrically bizarre cultural estate, all overlooking Lake Garda.","wl":"en","wt":"Vittoriale degli Italiani","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Vittoriale_il_complesso_monumentale.jpg?width=800"},
  {"n":"Brunate","la":45.817,"lo":9.1,"e":715,"co":"IT","region":"Lombardia","cat":"viewpoint-panorama","themes":["panoramic-view","photogenic","cable-car","year-round","family-friendly","hidden-gem"],"access":["funicular","foot","car"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":7,"td":"Car-free hillside village 715 m above Como, reached in 7 minutes by the historic 1894 funicular (55% gradient). Belle époque villas, Art Nouveau lighthouse and the most panoramic lake-to-Alps view on Lake Como's entire western arm.","rs":"At sunset, the entire Y of Lake Como glows gold from this perch: city lights, ferries, villas and snow-tipped Alps all visible at once. The funicular ride itself is half the fun.","wl":"en","wt":"Brunate","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Panorama_dalla_Lucciola.jpg?width=800"},
  {"n":"Cernobbio & Villa d'Este","la":45.83806,"lo":9.07583,"e":202,"co":"IT","region":"Lombardia","cat":"special-experience","themes":["iconic","photogenic","car-accessible","boat-accessible","year-round","historic","architecture","spa-wellness"],"access":["car","train","boat","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":7,"td":"Elegant lakeside town 5 km from Como, dominated by Villa d'Este — a 16th-century cardinal's palace converted to an iconic 5-star hotel in 1873. Cypress-lined formal gardens with floating dock, mosaic paths and a storied guest list from Churchill to Hitchcock.","rs":"Villa d'Este is one of the world's great hotels — even just visiting for coffee on the floating dock or lunch in the gardens puts you inside 500 years of aristocratic lake history.","wl":"en","wt":"Cernobbio","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Cernobbio,_panorama_della_riva.jpg?width=800"},
  {"n":"Lecco","la":45.85,"lo":9.4,"e":214,"co":"IT","region":"Lombardia","cat":"old-town","themes":["photogenic","car-accessible","boat-accessible","year-round","historic","panoramic-view","hike-required"],"access":["car","train","boat","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":7,"td":"City at the foot of Lake Como's eastern arm, birthplace and setting of Manzoni's 'I Promessi Sposi' (1827). Backed by the Grigne needles and the serrated Resegone, it is the world capital of pre-Alpine rock climbing with routes up to 6c on limestone above the lake.","rs":"Manzoni's lake is rawer and more Alpine than Como-Bellagio — the Resegone ridge looms directly overhead and world-class rock climbers from across Europe converge on the Grigne massif every weekend.","wl":"en","wt":"Lecco","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Malgrate%2C_LC_-_Lecco%2C_LC_v_W.jpg?width=800"},
  {"n":"Limone sul Garda","la":45.80833,"lo":10.7875,"e":69,"co":"IT","region":"Lombardia","cat":"village","themes":["photogenic","car-accessible","boat-accessible","year-round","swimmable","food-drink"],"access":["car","boat","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":7,"td":"Most picturesque village on the Brescia shore of Lake Garda: terraced limonaia gardens squeezed between cliff and water, colourful harbour and Art Nouveau waterfront. Goethe described the lemon groves rapturously in 1786.","rs":"Goethe wrote rapturously about the lemon groves in 1786 and they look exactly the same today — a cerulean lake, white-pillared lemon terraces and sheer limestone cliff make this lake's most photogenic town.","wl":"en","wt":"Limone sul Garda","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Limone_sul_garda_visto_dal_battello.jpg?width=800"},
  {"n":"Livigno","la":46.53333,"lo":10.13333,"e":1816,"co":"IT","region":"Lombardia","cat":"special-experience","themes":["special-experience","winter-sport","summer-only","panoramic-view","car-accessible","family-friendly"],"access":["car","foot","cable-car"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":7,"td":"'Little Tibet' — isolated EU customs-free valley at 1,816 m in Province of Sondrio, the highest duty-free zone in Europe. 115 km of winter ski runs, Europe's highest dedicated summer cycling track, no VAT on fuel, wine, spirits or luxury goods.","rs":"Italy's highest and cheapest resort: tax-free petrol, whisky and ski gear at altitude — plus some of the Alps' most enjoyable high-alpine skiing and a summer cycling programme rivalling anything in Switzerland.","wl":"en","wt":"Livigno","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Livigno5_wiki.jpg?width=800"},
  {"n":"Madesimo","la":46.42816,"lo":9.34386,"e":1550,"co":"IT","region":"Lombardia","cat":"village","themes":["hidden-gem","winter-sport","panoramic-view","hike-required","car-accessible"],"access":["car","foot","cable-car"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":7,"td":"High-Alpine village in Val Spluga (1,550 m), Province of Sondrio. Gateway to the historic Splügen Pass (2,113 m). Beloved for the legendary Canalone del Truogolo piste (1,000 m vertical), summer via ferrata, granite peaks and Valchiavenna solitude.","rs":"Hidden gem of the Lombard Alps: a small, uncrowded resort with one of Italy's finest ski descents, dramatic granite spires and complete freedom from the crowds that overwhelm Livigno and Bormio.","wl":"en","wt":"Madesimo","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Madesimo_in_Summer.JPG?width=800"},
  {"n":"Piramidi di Zone","la":45.76667,"lo":10.11667,"e":684,"co":"IT","region":"Lombardia","cat":"geology-cave","themes":["hidden-gem","photogenic","hike-required","panoramic-view","family-friendly"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":7,"td":"Geological hoodoos (earth pyramids) above Lake Iseo: glacial moraine shaped by erosion into dozens of stone columns 10–40 m tall, each capped by a protective boulder. Best viewed in autumn mist. Village of Zone, Province of Brescia.","rs":"Italy's answer to Renon's earth pyramids — entirely overlooked by most visitors, yet just 30 min from Iseo. The columns glow amber at sunset above a blue lake backdrop. Almost no crowds.","wl":"en","wt":"Zone, Lombardy","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Piramidi_di_Zone6.JPG?width=800"},
  {"n":"Sacro Monte di Ossuccio","la":45.9748,"lo":9.17728,"e":425,"co":"IT","region":"Lombardia","cat":"monastery-church","themes":["unesco","photogenic","hike-required","historic","architecture","panoramic-view"],"access":["car","boat","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":7,"td":"UNESCO-listed pilgrimage path above Lake Como's western shore: 14 baroque chapels (1635–1710) winding through chestnut forest to the Sanctuary of the Madonna del Soccorso, housing 230 life-size terracotta figures by top 17th-century sculptors.","rs":"The only UNESCO Sacro Monte directly on a major lake — the chapel trail offers extraordinary Como views, high-quality baroque art and total tranquility, yet only a 20-min drive from the crowds.","wl":"en","wt":"Sacro Monte di Ossuccio","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Tremezzina_-_sacro_monte_della_Beata_Vergine_del_Soccorso_-_202209111359.jpg?width=800"},
  {"n":"Salò","la":45.6,"lo":10.53333,"e":65,"co":"IT","region":"Lombardia","cat":"old-town","themes":["photogenic","car-accessible","boat-accessible","year-round","historic","food-drink"],"access":["car","boat","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":7,"td":"Elegant resort on the broad Golfo di Salò, last capital of Mussolini's Italian Social Republic (1943–45). Renaissance cathedral, Palazzo della Magnifica Patria, finest lake promenade on western Garda, and superb local fish restaurants. Province of Brescia.","rs":"Salò balances turbulent 20th-century history with the most gracious lake promenade on western Garda — great restaurants, historic Renaissance architecture and an uncrowded broad bay beloved by sailors.","wl":"en","wt":"Salò","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Golfo_di_Sal%C3%B2.JPG?width=800"},
  {"n":"Cascate dell'Acquafraggia","la":46.32516,"lo":9.43129,"e":380,"co":"IT","region":"Lombardia","cat":"waterfall-gorge","themes":["hidden-gem","photogenic","hike-required","panoramic-view"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":1,"sc":6,"td":"Twin waterfalls above Piuro in Valchiavenna, sketched by Leonardo da Vinci in the Codex Atlanticus (c. 1490). The Acquafraggia torrent plunges down polished granite cliffs in two parallel streams — one of the most dramatic double waterfalls in the Italian Alps.","rs":"A hidden gem Leonardo da Vinci drew in 1490 that looks exactly the same today: twin granite cascades roaring through a regional nature reserve with almost no visitors even in summer.","wl":"it","wt":"Acquafraggia","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Cascate_Acquafraggia.jpg?width=800"},
  {"n":"Madonna del Ghisallo","la":45.92833,"lo":9.26667,"e":754,"co":"IT","region":"Lombardia","cat":"monastery-church","themes":["hidden-gem","panoramic-view","photogenic","historic","special-experience","hike-required"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":1,"sc":6,"td":"Mountain pass chapel at 754 m, declared patron sanctuary of all cyclists worldwide by Pope Pius XII in 1949. Famous Tour de Lombardia climbs pass here. Inside: Coppi and Bartali's jerseys, Merckx's bike, eternal flame for fallen riders. Cycling museum next door.","rs":"A hidden cycling holy grail above Lake Como — a tiny chapel crammed with champions' relics on a spectacular ridge where the three lake arms are all visible at once. Moving for any cyclist.","wl":"en","wt":"Madonna del Ghisallo","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Magreglio_Santuario_di_Madonna_di_Ghisallo_Esterno_Facciata_3.jpg?width=800"},
  {"n":"Riserva Naturale Torbiere del Sebino","la":45.65028,"lo":10.03333,"e":185,"co":"IT","region":"Lombardia","cat":"national-park","themes":["hidden-gem","family-friendly","year-round","photogenic"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":6,"td":"Rare peat-bog nature reserve (350 ha) between Lake Iseo and Provaglio d'Iseo — relic of post-glacial marshland with floating peat islands, rare orchids, 200+ bird species and a summer spectacle of lotus flowers. Accessible boardwalk trails.","rs":"One of Italy's most biodiverse wetlands and a genuine hidden gem: lotus blooms in July, kingfishers year-round and surreal floating peat islands right next to vineyards and the lake.","wl":"it","wt":"Torbiere del Sebino","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Torbiere_del_Sebino_percorso_sud_5.jpg?width=800"},

  /* ── Trentino ────────────────────────────────────────── */
  {"n":"Castello del Buonconsiglio","la":46.07361,"lo":11.12333,"e":194,"co":"IT","region":"Trentino","cat":"castle-fortress","themes":["historic","architecture","year-round","iconic"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":10,"td":"Trento's great castle-palace complex, seat of the prince-bishops from the 13th century. Its Gothic Castelvecchio and Renaissance Palazzo Magno house the 15th-century 'Cycle of the Months' frescoes — a masterpiece of secular medieval art.","rs":"Trentino's greatest castle; the Cycle of the Months frescoes are among the finest medieval secular paintings in Europe; defines Trento's unique heritage.","wl":"en","wt":"Buonconsiglio Castle","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/20110727_Trento_Buonconsiglio_Castle_6609.jpg?width=800"},
  {"n":"Lago di Molveno","la":46.12556,"lo":10.96111,"e":864,"co":"IT","region":"Trentino","cat":"alpine-lake","themes":["photogenic","car-accessible","swimmable","family-friendly","iconic"],"access":["car","foot","boat","cable-car"],"season":["spring","summer","autumn"],"dur":3,"sc":10,"td":"Jewel-blue lake voted Italy's most beautiful by Legambiente, cradled at the foot of the Brenta Dolomites UNESCO massif. The Grostè cable car from Molveno village lifts visitors directly into the via ferrata network above.","rs":"Voted Italy's most beautiful lake; the Brenta Dolomites wall rising directly from its shore is one of the most dramatic alpine lake backdrops in Europe.","wl":"en","wt":"Lake Molveno","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Molveno_vor_Brentagruppe.jpg?width=800"},
  {"n":"Lago di Tovel","la":46.26155,"lo":10.948,"e":1178,"co":"IT","region":"Trentino","cat":"alpine-lake","themes":["unesco","photogenic","car-accessible","family-friendly","hidden-gem"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":10,"td":"Historic alpine lake once famous for turning blood-red each summer due to algae. Set in the Adamello Brenta Natural Park, ringed by spruce forests and dolomitic cliffs. A Ramsar-listed wetland of international importance at 1178 m.","rs":"The only lake in the world known to have turned red; Ramsar wetland; dramatic Brenta Dolomites backdrop; most celebrated lake in the Adamello Brenta park.","wl":"en","wt":"Lago di Tovel","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Lago_di_Tovel_02.jpg?width=800"},
  {"n":"Pale di San Martino","la":46.26667,"lo":11.86667,"e":2581,"co":"IT","region":"Trentino","cat":"national-park","themes":["unesco","cable-car","panoramic-view","hike-required","photogenic","iconic"],"access":["cable-car","foot"],"season":["summer","autumn"],"dur":5,"sc":10,"td":"The largest massif in the Dolomites (~240 km²), its high plateau a lunar limestone wilderness at 2500–2800 m. UNESCO World Heritage. Cable car from San Martino di Castrozza to Rifugio Rosetta (2581 m) gives access to the otherworldly plateau.","rs":"UNESCO-listed; the vast dolomite plateau is a staggering moonscape unlike anywhere else in Europe; cable car delivers you from lush valley to bare rock in 10 minutes.","wl":"en","wt":"Pale di San Martino","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Pale_di_san_martino_tramonto.jpg?width=800"},
  {"n":"Sass Pordoi","la":46.50151,"lo":11.80659,"e":2950,"co":"IT","region":"Trentino","cat":"viewpoint-panorama","themes":["unesco","cable-car","panoramic-view","car-accessible","iconic"],"access":["car","cable-car"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":10,"td":"The 'Terrace of the Dolomites' — a cable car from the Pordoi Pass (2239 m, Trentino/Canazei side) ascends to a flat plateau at 2950 m with an unobstructed 360° view of Sella, Marmolada, Cimon della Pala, and the entire Dolomites. UNESCO WHS.","rs":"Easiest access to a genuine 2950 m Dolomites summit; 360° panorama rated among Europe's best; cable car from the Pordoi Pass; UNESCO Dolomites WHS.","wl":"en","wt":"Sass Pordoi","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Sass_Pordoi.JPG?width=800"},
  {"n":"Trento","la":46.067,"lo":11.117,"e":null,"co":"IT","region":"Trentino","cat":"old-town","themes":["historic","architecture","food-drink","year-round","iconic"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":4,"sc":10,"td":"Elegant Alpine city on the Adige, venue of the Council of Trent (1545–1563). Its Renaissance piazza, Cathedral of San Vigilio, Roman remains, and the Castello del Buonconsiglio make it one of Italy's finest historic cities.","rs":"The intellectual capital of the Alps; Council of Trent heritage, superb Renaissance architecture, excellent food scene, and perfect access to all Trentino passes.","wl":"en","wt":"Trento","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Trento_Piazza_del_Duomo_Fontana_del_Nettuno_05.jpg?width=800"},
  {"n":"Cascata di Nardis","la":46.16862,"lo":10.7144,"e":893,"co":"IT","region":"Trentino","cat":"waterfall-gorge","themes":["photogenic","car-accessible","family-friendly","iconic"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":9,"td":"One of Italy's most spectacular accessible waterfalls, dropping ~130 m in twin parallel ribbons off pink Adamello granite at the entrance to Val Genova. Located in the Adamello Brenta Natural Park near Carisolo, Val Rendena.","rs":"Trentino's most dramatic waterfall; twin 130 m drops against pink granite in a natural park; superb photo opportunity and short, easy walk from the car park.","wl":"it","wt":"Cascata di Nardis","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Nardis_Waterfalls.jpg?width=800"},
  {"n":"Cimon della Pala","la":46.28611,"lo":11.82111,"e":3184,"co":"IT","region":"Trentino","cat":"mountain-summit","themes":["unesco","panoramic-view","photogenic","iconic","hike-required"],"access":["cable-car","foot"],"season":["summer","autumn"],"dur":6,"sc":9,"td":"Called 'the Matterhorn of the Dolomites', this slender spire at 3184 m dominates the skyline above San Martino di Castrozza. Its profile, best seen from the Rolle Pass, is one of the most photographed peaks in Italy. UNESCO Dolomites WHS.","rs":"The most iconic mountain silhouette in the eastern Dolomites; appears on the coat-of-arms of the Guardia di Finanza; UNESCO WHS; electric from the Rolle Pass.","wl":"en","wt":"Cimon della Pala","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/CimonDellaPala2.JPG?width=800"},
  {"n":"Madonna di Campiglio","la":46.23194,"lo":10.82611,"e":1522,"co":"IT","region":"Trentino","cat":"village","themes":["winter-sport","cable-car","iconic","panoramic-view","year-round"],"access":["car","cable-car","foot"],"season":["spring","summer","autumn","winter"],"dur":4,"sc":9,"td":"Trentino's most glamorous mountain resort at 1522 m, gateway to the UNESCO Brenta Dolomites. Hosts ski World Cup races and Ferrari/F1 media events in January. In summer a superb hub for via ferratas, mountain biking, and hiking.","rs":"Premier alpine resort of Trentino; UNESCO Brenta gateway; F1 and Ferrari events; ski World Cup; 150 km of pistes; world-class via ferratas in summer.","wl":"en","wt":"Madonna di Campiglio","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Madonna_di_Campiglio.JPG?width=800"},
  {"n":"Riva del Garda","la":45.883,"lo":10.85,"e":70,"co":"IT","region":"Trentino","cat":"old-town","themes":["historic","family-friendly","car-accessible","year-round","iconic"],"access":["car","boat","foot"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":9,"td":"Ancient lakeside town at the northern tip of Lake Garda where the Alps meet the Mediterranean. Medieval Torre Apponale, Rocca fortress, lakefront promenade, world-class windsurfing and kitesurfing, and a mild climate year-round.","rs":"Trentino's most visited destination; medieval history, Alpine drama, and Lake Garda's mild climate combine perfectly; world-class windsurfing; all-season appeal.","wl":"en","wt":"Riva del Garda","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Riva_del_Garda_02.jpg?width=800"},
  {"n":"Carè Alto","la":46.10789,"lo":10.596,"e":3465,"co":"IT","region":"Trentino","cat":"mountain-summit","themes":["hike-required","panoramic-view","photogenic","summer-only","special-experience"],"access":["foot"],"season":["summer","autumn"],"dur":8,"sc":8,"td":"The highest summit in the Adamello massif (3465 m), roof of the Adamello Brenta Natural Park. A demanding multi-day glacier approach via Rifugio Carè Alto (2669 m). Dramatic views over the retreating Adamello glaciers and the entire Trentino Alps.","rs":"Highest accessible peak in Trentino's western alps; the Adamello glaciers are rapidly retreating — a rare and important sight; superb summit panorama over five regions.","wl":"en","wt":"Carè Alto","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Cima_car%C3%A8_alto.jpg?width=800"},
  {"n":"Cascate del Varone","la":45.91142,"lo":10.83433,"e":200,"co":"IT","region":"Trentino","cat":"waterfall-gorge","themes":["family-friendly","car-accessible","year-round","photogenic"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":1,"sc":8,"td":"Twin waterfalls dropping 98 m into a narrow limestone gorge carved over 20 000 years, walkable via a lit tunnel path. Just 3 km from Riva del Garda. Franz Kafka and Thomas Mann are among its celebrated historic visitors.","rs":"Unique gorge waterfall walk with two viewing platforms; historically visited by Kafka and Thomas Mann; just 3 km from Riva del Garda; open all year.","wl":"en","wt":"Cascate del Varone","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/GrottaCascataVarone.jpg?width=800"},
  {"n":"Castel Beseno","la":45.93096,"lo":11.10981,"e":480,"co":"IT","region":"Trentino","cat":"castle-fortress","themes":["historic","architecture","car-accessible","panoramic-view"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":8,"td":"The largest castle complex in Trentino-Alto Adige, commanding the entire Vallagarina from its rocky hilltop in Besenello. First documented in the 12th century; its massive walls, bastions, and frescoed rooms now form a provincial museum.","rs":"Trentino's largest fortress — bigger even than Buonconsiglio; exceptional hilltop panorama over the Adige valley; remarkable medieval and Renaissance remains.","wl":"it","wt":"Castel Beseno","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Calliano-Castel_Beseno_from_Folgaria-southeast.jpg?width=800"},
  {"n":"Castel Toblino","la":46.05513,"lo":10.96742,"e":245,"co":"IT","region":"Trentino","cat":"castle-fortress","themes":["historic","photogenic","car-accessible","architecture"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":1,"sc":8,"td":"Fairy-tale 12th-century castle on an islet in the sapphire Lago di Toblino, reached by a narrow causeway. A summer retreat of the Trento prince-bishops and the Council of Trent legates; today a restaurant and event venue.","rs":"Italy's most romantically situated lake castle; instantly photogenic from every angle; on the main Trento–Riva del Garda road; unique even by Trentino standards.","wl":"it","wt":"Castel Toblino","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Castel_Toblino_02.jpg?width=800"},
  {"n":"Castello di Arco","la":45.917,"lo":10.883,"e":91,"co":"IT","region":"Trentino","cat":"castle-fortress","themes":["historic","panoramic-view","car-accessible","photogenic","special-experience"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":8,"td":"Dramatic 10th-century ruined castle perched on a sheer limestone crag 100 m above Arco. The town is a world-class rock-climbing destination hosting the Rock Master World Cup. Precious 14th-century frescoes survive inside the keep.","rs":"Most photogenic hilltop castle in southern Trentino; Arco is a global rock-climbing mecca and subtropical microclimate town; accessible, historic, spectacular.","wl":"en","wt":"Castello di Arco","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Arco%2C_Italy.jpg?width=800"},
  {"n":"Cima Brenta","la":46.15361,"lo":10.85583,"e":3155,"co":"IT","region":"Trentino","cat":"mountain-summit","themes":["unesco","hike-required","panoramic-view","photogenic","iconic"],"access":["cable-car","foot"],"season":["summer","autumn"],"dur":7,"sc":8,"td":"Second-highest peak (3155 m) of the UNESCO Brenta Dolomites and one of the most celebrated rock faces in the Alps. The Bocchette Alte via ferrata traverses its north ridge — an airy, cable-assisted route above Rifugio Brentei.","rs":"UNESCO Brenta Dolomites; the Bocchette Alte via ferrata on its flanks is one of the Alps' great high-mountain routes — airy, spectacular, and uniquely Dolomitic.","wl":"en","wt":"Cima Brenta","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Cima_Brenta.jpg?width=800"},
  {"n":"Cima Tosa","la":46.15722,"lo":10.87111,"e":3173,"co":"IT","region":"Trentino","cat":"mountain-summit","themes":["unesco","hike-required","panoramic-view","iconic","photogenic"],"access":["cable-car","foot"],"season":["summer","autumn"],"dur":7,"sc":8,"td":"Highest summit of the Brenta Dolomites (3173 m) and UNESCO World Heritage Site. Accessed via the legendary Bocchette Alte via ferrata, one of the most spectacular exposed ridge routes in the Alps. Towering above Rifugio Brentei.","rs":"Highest peak of the UNESCO Brenta group; the Bocchette Alte via ferrata traversing its flanks is among the Alps' finest and most exhilarating routes.","wl":"en","wt":"Cima Tosa","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Dolomiti_di_Brenta.jpg?width=800"},
  {"n":"Lago di Tenno","la":45.93806,"lo":10.81583,"e":570,"co":"IT","region":"Trentino","cat":"alpine-lake","themes":["photogenic","hidden-gem","car-accessible","swimmable","family-friendly"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":8,"td":"Emerald-turquoise alpine lake at 570 m formed by a medieval landslide around AD 1100. A tiny island appears in its southern basin when water levels drop. Protected as a biotope by the Province of Trento, near Riva del Garda.","rs":"One of the most photogenic small lakes in the Alps; striking turquoise colour, tiny island, medieval hamlet of Tenno above; perfectly combined with Riva del Garda.","wl":"en","wt":"Lago di Tenno","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Lago_di_Tenno_Italien_2.jpg?width=800"},
  {"n":"MUSE – Museo delle Scienze","la":46.064,"lo":11.12,"e":null,"co":"IT","region":"Trentino","cat":"museum-cultural","themes":["architecture","family-friendly","year-round","special-experience"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":8,"td":"Renzo Piano-designed science museum (2013) in Trento's Le Albere district. Its tiered glass building houses 12 000 m² of exhibits on Alpine biodiversity, climate change, evolution, and the natural history of Trentino.","rs":"Italy's most architecturally striking science museum by Renzo Piano; world-class exhibits on Alpine nature and climate; essential rainy-day destination in Trento.","wl":"en","wt":"MUSE - Museo delle Scienze","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/MuSe_esterno_1.JPG?width=800"},
  {"n":"San Martino di Castrozza","la":46.267,"lo":11.8,"e":1487,"co":"IT","region":"Trentino","cat":"village","themes":["winter-sport","cable-car","year-round","panoramic-view","family-friendly"],"access":["car","cable-car","foot"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":8,"td":"Classic alpine resort at 1487 m framed on three sides by the soaring towers of the Pale di San Martino. Inside the Paneveggio–Pale di San Martino Natural Park. Cable cars, via ferratas, ski slopes, and legendary Dolomite scenery.","rs":"Most theatrically situated resort in Trentino — ringed by Dolomite spires; natural park setting; first-class cable cars to the Pale plateau; all-season appeal.","wl":"en","wt":"San Martino di Castrozza","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Pale_San_Martino_2.jpg?width=800"},
  {"n":"Strada del Ponale","la":45.882,"lo":10.825,"e":70,"co":"IT","region":"Trentino","cat":"special-experience","themes":["photogenic","panoramic-view","car-accessible","special-experience","historic"],"access":["foot","car"],"season":["spring","summer","autumn"],"dur":2,"sc":8,"td":"A 19th-century military road cut into the sheer western cliff of Monte Rocchetta above Riva del Garda, now a walking and cycling route with dizzying views of turquoise Lake Garda. The classic 'above-Garda' cliff experience in Trentino.","rs":"One of Europe's finest cliff cycling/walking routes; 19th-century engineering marvel; jaw-dropping views directly above Lake Garda; free, car-free, and unmissable.","wl":"it","wt":"Strada del Ponale","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Strada_del_Ponale_-_5.jpg?width=800"},
  {"n":"Cascate di Vallesinella","la":46.204,"lo":10.802,"e":1513,"co":"IT","region":"Trentino","cat":"waterfall-gorge","themes":["family-friendly","photogenic","car-accessible","hike-required"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":3,"sc":7,"td":"Two-tiered waterfall cascade plunging through ancient spruce forest inside the Adamello Brenta Natural Park. Easily reached on a 3 km walk from Madonna di Campiglio. The upper falls drop 30 m in a spectacular rocky gorge.","rs":"Most accessible waterfall series near Madonna di Campiglio; ideal family hike through primeval spruce forest; spectacular in spring snowmelt and early summer.","wl":"it","wt":"Cascate di Vallesinella","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Cascate_di_Vallesinella_alte_05.jpg?width=800"},
  {"n":"Castel Thun","la":46.27369,"lo":11.09031,"e":620,"co":"IT","region":"Trentino","cat":"castle-fortress","themes":["historic","architecture","car-accessible","panoramic-view"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":7,"td":"One of Trentino's most imposing and best-preserved medieval castles, crowning a hilltop in Val di Non since 1267. The Thun family seat features a Moorish-style Spanish gateway, frescoed bishop's chamber, and sweeping apple-orchard views.","rs":"Best-preserved medieval castle in Trentino; original 16th–17th-century furnishings intact; the 'Spanish' gateway is unique in the Alps; splendid Val di Non views.","wl":"it","wt":"Castel Thun","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Castel_Thun.JPG?width=800"},
  {"n":"Forte Belvedere Lavarone","la":45.927,"lo":11.307,"e":1185,"co":"IT","region":"Trentino","cat":"castle-fortress","themes":["historic","special-experience","car-accessible"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":7,"td":"Austrian WWI fortress (Werk Gschwendt) built 1911–1914 on the Altopiano di Lavarone to defend the Italian frontier. Open-air museum with preserved tunnels, gun emplacements, and an audiovisual reconstruction of mountain trench warfare.","rs":"Among the best-preserved WWI Austrian forts in Italy; atmospheric tunnels, panoramic plateau location, and excellent interpretive displays on the 'White War' in the Alps.","wl":"it","wt":"Forte Belvedere-Gschwendt","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Lavarone-Forte_Belvedere-Gschwendt-from_east.jpg?width=800"},
  {"n":"Lago di Caldonazzo","la":46.012,"lo":11.244,"e":449,"co":"IT","region":"Trentino","cat":"alpine-lake","themes":["swimmable","car-accessible","family-friendly","year-round"],"access":["car","foot","boat"],"season":["spring","summer","autumn"],"dur":2,"sc":7,"td":"Trentino's largest lake (5.4 km²) and premier swimming destination at 449 m in the sunny Valsugana valley. Warm, clear waters with sandy beaches, windsurfing, and boat hire. Easily paired with nearby Levico Terme spa and the Valsugana cycling route.","rs":"Trentino's biggest and warmest swimming lake; ideal family summer destination paired with Levico Terme spa; the Valsugana cycling route passes its northern shore.","wl":"en","wt":"Lake Caldonazzo","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Lake_Caldonazzo_before_the_storm.jpg?width=800"},
  {"n":"Levico Terme","la":46.017,"lo":11.3,"e":520,"co":"IT","region":"Trentino","cat":"spa-wellness","themes":["spa-wellness","family-friendly","car-accessible","swimmable","year-round"],"access":["car","train","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":7,"td":"Elegant Belle Époque spa town at 520 m in the Valsugana valley, famed for its arsenic-iron thermal waters. The Art Nouveau Grand Hotel, lush thermal park, and Lake Levico beachfront provide a refined counterpoint to the surrounding mountains.","rs":"Trentino's premier spa town; Belle Époque architecture, mineral thermal waters, Lake Levico swimming, and a genteel atmosphere rare in the Alps.","wl":"en","wt":"Levico Terme","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Levico_Terme_from_near_Tenna_by_Slaunger_2013-07-16_cropped.jpg?width=800"},
  {"n":"Paganella","la":46.17028,"lo":11.02611,"e":2125,"co":"IT","region":"Trentino","cat":"viewpoint-panorama","themes":["cable-car","panoramic-view","car-accessible","photogenic","winter-sport"],"access":["car","cable-car","foot"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":7,"td":"A gondola from Andalo or Fai della Paganella rises to a broad plateau at 2125 m with one of Trentino's most sweeping 360° panoramas: Brenta Dolomites to the west, Adamello glaciers to the south-west, and the Po plain shimmering far below.","rs":"Best easily accessible panoramic viewpoint above the Brenta Dolomites/Molveno area; gondola access; 360° view from Dolomites to the Po; excellent family skiing in winter.","wl":"en","wt":"Paganella","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Andalo_Paganella.jpg?width=800"},

  /* ── Piemonte ────────────────────────────────────────── */
  {"n":"Borromean Islands","la":45.90778,"lo":8.53861,"e":null,"co":"IT","region":"Piemonte","cat":"special-experience","themes":["iconic","historic","architecture","photogenic","family-friendly","boat-accessible","year-round"],"access":["boat","foot"],"season":["spring","summer","autumn"],"dur":4,"sc":10,"td":"Three baroque jewel-islands on Lago Maggiore owned by the Borromeo family since 1450: Isola Bella (10-terrace palace garden), Isola Madre (English park), Isola dei Pescatori (medieval fishing village).","rs":"Ferry from Stresa, Baveno or Verbania (seasonal). Buy combined ticket for Bella + Madre. Allow 4h for all three. Spring tulip festival on Isola Madre.","wl":"en","wt":"Borromean Islands","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/GolfoBorromeoFeb202026.jpg?width=800"},
  {"n":"Orta San Giulio","la":45.79778,"lo":8.4197,"e":295,"co":"IT","region":"Piemonte","cat":"village","themes":["iconic","photogenic","historic","architecture","family-friendly","year-round","boat-accessible"],"access":["car","foot","boat"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":10,"td":"Italy's most romantic village: medieval borgo on a peninsula on Lake Orta. Car-free historic centre with Renaissance palazzos and arcaded streets. One of I Borghi più belli d'Italia.","rs":"Park outside and walk in. Boats to Isola San Giulio depart every 15 min. Excellent restaurants on the piazza. Combine with the Sacro Monte hill above the village.","wl":"en","wt":"Orta San Giulio","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/OrtaSanGiulioAug132024_03.jpg?width=800"},
  {"n":"Sacra di San Michele","la":45.09803,"lo":7.34349,"e":960,"co":"IT","region":"Piemonte","cat":"monastery-church","themes":["iconic","historic","architecture","photogenic","panoramic-view","year-round"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":10,"td":"10th-c. cliff abbey (960m) above Val di Susa, perched on Monte Pirchiriano. Romanesque-Gothic design; inspired Umberto Eco's The Name of the Rose. The symbolic monument of the Piedmont region.","rs":"Allow 2h. Climb 150 'Staircase of the Dead' steps carved into the rock. Guided tours available. Spectacular views over Val di Susa.","wl":"en","wt":"Sacra di San Michele","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Sacra_di_San_Michele07.jpg?width=800"},
  {"n":"Sacro Monte di Varallo","la":45.81861,"lo":8.25472,"e":600,"co":"IT","region":"Piemonte","cat":"monastery-church","themes":["unesco","iconic","historic","architecture","photogenic","panoramic-view","year-round"],"access":["car","cable-car","foot"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":10,"td":"The oldest Sacro Monte (1491), UNESCO WHS. 45 chapels with 800+ life-size painted statues recreating Christ's life, set on a rocky terrace above Varallo Sesia. Masterpieces by Ferrari and Morazzone.","rs":"Plan 3h for the full chapel circuit. Cable car ascent from Varallo town. Basilica open daily. Arguably the most dramatic of all nine Sacri Monti.","wl":"en","wt":"Sacro Monte di Varallo","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Sacro_Monte_Varallo_4.JPG?width=800"},
  {"n":"Fort of Exilles","la":45.0983,"lo":6.9319,"e":1050,"co":"IT","region":"Piemonte","cat":"castle-fortress","themes":["historic","photogenic","panoramic-view","year-round","architecture"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":9,"td":"Savoy Alpine fortress in the Susa Valley, storied jail of the Man in the Iron Mask. Multiple historic layers from medieval to 19th-c.; now houses the Museo Nazionale della Montagna on a dramatic rocky spur.","rs":"Open Tue–Sun April–October; guided tours in Italian/English. Allow 2h. Car park below with a steep walk up. Combine with Susa Roman ruins (20km east).","wl":"en","wt":"Fort of Exilles","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/DSCF2335_Exilles.jpg?width=800"},
  {"n":"Forte di Fenestrelle","la":45.03005,"lo":7.05953,"e":1186,"co":"IT","region":"Piemonte","cat":"castle-fortress","themes":["iconic","historic","special-experience","photogenic","panoramic-view"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":4,"sc":9,"td":"Europe's largest Alpine fortification: 130ha of Savoy ramparts (1728–1850) spanning 1,183–1,786m, linked by 3,996 covered steps. World Monuments Fund watch-list. Val Chisone, Province of Turin.","rs":"Guided tours only — book at fortefenestrelle.it. Allow 4h; some tours include the 4,000-step staircase. Open April–October; winter by appointment.","wl":"en","wt":"Fenestrelle Fort","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Fenestrelle_-_Forte_di_Fenestrelle_-_2024-09-02_16-57-15_001.jpg?width=800"},
  {"n":"Isola San Giulio","la":45.79619,"lo":8.39974,"e":295,"co":"IT","region":"Piemonte","cat":"monastery-church","themes":["iconic","historic","architecture","photogenic","boat-accessible","special-experience"],"access":["boat","foot"],"season":["spring","summer","autumn","winter"],"dur":1,"sc":9,"td":"Tiny island (275m long) in Lake Orta reachable only by boat. The 5th-c. Basilica di San Giulio holds early Christian art and relics. A Benedictine monastery since 1976; the meditative 'Way of Silence' circles the shore.","rs":"Boats every 10–15 min from Orta San Giulio (small fee). Monastery church open to visitors; no cars, shops or noise. Combine with Orta village and Sacro Monte.","wl":"en","wt":"San Giulio Island","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/OrtaSanGiulioAug132024_02.jpg?width=800"},
  {"n":"Sacro Monte di Orta","la":45.79778,"lo":8.41111,"e":396,"co":"IT","region":"Piemonte","cat":"monastery-church","themes":["unesco","historic","architecture","photogenic","panoramic-view","year-round"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":9,"td":"UNESCO Sacro Monte (1583) dedicated to St Francis of Assisi: 20 chapels on the San Nicolao hill above Lake Orta. Mannerist and Baroque frescoes; the woodland was designed as an ornamental garden.","rs":"Walk or drive to the top; combine with Orta San Giulio village and the lake. Free entry to grounds; chapels open during daylight hours year-round.","wl":"en","wt":"Sacro Monte di Orta","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/OrtaSanGiulioAug132024_05.jpg?width=800"},
  {"n":"Saluzzo","la":44.65,"lo":7.483,"e":395,"co":"IT","region":"Piemonte","cat":"old-town","themes":["historic","architecture","photogenic","year-round","food-drink"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":9,"td":"Former capital of the Marquisate of Saluzzo (1142–1548). The hillside old town retains Gothic-Renaissance streetscapes, the medieval Castiglia fortress, ducal palazzi and court art. Birthplace of Silvio Pellico.","rs":"Explore the upper borgo on foot (mostly car-free). Visit Casa Cavassa museum. Castello della Manta is 5km south. Saturday market. TCI Bandiera Arancione town.","wl":"en","wt":"Saluzzo","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Saluzzo_veduta.jpg?width=800"},
  {"n":"Susa — Roman Monuments","la":45.13333,"lo":7.05,"e":503,"co":"IT","region":"Piemonte","cat":"museum-cultural","themes":["historic","architecture","year-round","car-accessible"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":9,"td":"Ancient Segusio, capital of the Alpes Cottiae Roman province. Exceptional cluster of monuments: Arch of Augustus (8 BC), amphitheatre ruins, Porta Savoia, and the 11th-c. Cathedral of San Giusto.","rs":"All Roman monuments free and walkable from the centre. Combine with Forte di Exilles (20km west). The Arch of Augustus is most photogenic at golden hour.","wl":"en","wt":"Susa, Piedmont","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Susa_anfiteatro.jpg?width=800"},
  {"n":"Vigezzina–Centovalli Railway","la":46.1139,"lo":8.2939,"e":272,"co":"IT","region":"Piemonte","cat":"scenic-railway","themes":["photogenic","panoramic-view","special-experience","family-friendly","year-round"],"access":["train"],"season":["spring","summer","autumn","winter"],"dur":4,"sc":9,"td":"Narrow-gauge railway (1923) from Domodossola to Locarno through the Val Vigezzo and Swiss Centovalli: 52km threading gorges, viaducts, 83 bridges and mountain villages. One of Europe's great scenic train rides.","rs":"6 departures daily from Domodossola; ~2h each way. Eurail/Interrail valid. Alight at Santa Maria Maggiore to explore. Day return to Locarno easily possible.","wl":"en","wt":"Domodossola–Locarno railway line","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/ABe_4-8_Intragna_240613_D34.jpg?width=800"},
  {"n":"Alagna Valsesia","la":45.85389,"lo":7.93722,"e":1191,"co":"IT","region":"Piemonte","cat":"village","themes":["photogenic","panoramic-view","winter-sport","special-experience","year-round"],"access":["car","foot","cable-car"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":8,"td":"Walser village (1,191m) at Monte Rosa's foot in Valsesia; gateway to the 4,634m massif. World-class freeride off-piste skiing; the Monte Rosa Ski area links to Zermatt and Cervinia across the border.","rs":"Road access from Varallo. Cable car to Punta Indren (3,260m); ski down to Gressoney (AO). Walser Ethnographic Museum in village. Best for mountaineers and freeride skiers.","wl":"en","wt":"Alagna Valsesia","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Alagna_Valsesia,_Monte_Rosa,_Via_dei_Walser.jpg?width=800"},
  {"n":"Castello della Manta","la":44.61444,"lo":7.48278,"e":500,"co":"IT","region":"Piemonte","cat":"castle-fortress","themes":["historic","architecture","photogenic","hidden-gem"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":8,"td":"Late 14th-c. castle at Manta near Saluzzo containing Piedmont's finest Gothic secular frescoes: the Fountain of Youth and the Nine Heroes — remarkable in detail and colour. FAI National Trust property.","rs":"Open Tue–Sun; FAI admission fee. Allow 1.5–2h. English and French guided tours on request. Combine with Saluzzo town (5km north).","wl":"en","wt":"Castello della Manta","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Saluzzo-Castello_della_Manta.jpg?width=800"},
  {"n":"Macugnaga","la":45.96667,"lo":7.96667,"e":1327,"co":"IT","region":"Piemonte","cat":"village","themes":["photogenic","panoramic-view","winter-sport","hidden-gem","year-round"],"access":["car","foot","cable-car"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":8,"td":"Walser village (1,327m) below Monte Rosa's awe-inspiring 3,000m east face — the most dramatic Alpine wall in the Alps. Cable car to Passo del Moro (2,820m) with glacier views. Traditional wooden architecture.","rs":"Drive from Domodossola via SS549. Cable car to Passo del Moro in summer. Museo Walser open July–August. Superb mountaineering base; cross-country skiing in winter.","wl":"en","wt":"Macugnaga","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Macugnaga_Borca.jpg?width=800"},
  {"n":"Mottarone","la":45.88028,"lo":8.45111,"e":1492,"co":"IT","region":"Piemonte","cat":"viewpoint-panorama","themes":["panoramic-view","photogenic","cable-car","year-round","family-friendly","winter-sport"],"access":["cogwheel","cable-car","car"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":8,"td":"1,492m summit between Lago Maggiore and Lake Orta offering a 360° panorama: seven lakes and the Alpine chain from Monte Viso to the Matterhorn. Ski in winter, hike in summer, Alpinia garden en route.","rs":"Take the Stresa cable car (seasonal) or drive via SS229. Ski slopes in winter. Visit the Alpinia Botanical Garden at Gignese on the ascent road. Restaurant at summit.","wl":"en","wt":"Mottarone","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/MottaroneFeb202026_02.jpg?width=800"},
  {"n":"Parco Naturale Alpi Marittime","la":44.18333,"lo":7.33333,"e":null,"co":"IT","region":"Piemonte","cat":"national-park","themes":["photogenic","panoramic-view","hike-required","summer-only","hidden-gem"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":4,"sc":8,"td":"Southern Alpine nature reserve in Cuneo province, bordering the French Mercantour. Habitat of ibex, chamois, wolves and bearded vultures. Includes high-altitude lakes, glaciers and Terme di Valdieri thermal spa.","rs":"Best June–September. Drive to Terme di Valdieri from Cuneo. Ibex viewing near Lago della Rovina. Thermal spa at Valdieri open in summer. Trails well-marked.","wl":"en","wt":"Maritime Alps Natural Park","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Vallone_Lourousa_da_Colle_Chiapous.jpg?width=800"},
  {"n":"Sacro Monte Calvario di Domodossola","la":46.10556,"lo":8.28694,"e":302,"co":"IT","region":"Piemonte","cat":"monastery-church","themes":["unesco","historic","architecture","panoramic-view","year-round"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":1,"sc":8,"td":"UNESCO Sacred Mount Calvary (1657) on Mattarella Hill above Domodossola: 15 chapels along the Via Crucis. Gateway to the Ossola valleys and departure point of the Vigezzina scenic railway.","rs":"15-min walk from Domodossola centre. Combine with the town's Saturday market and the Vigezzina railway departure for a full day in Ossola.","wl":"en","wt":"Sacred Mount Calvary of Domodossola","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Domodossola_-_Sacro_monte_Calvario_di_Domodossola_-_2023-09-18_20-47-03_001.jpg?width=800"},
  {"n":"Sacro Monte di Ghiffa","la":45.96361,"lo":8.615,"e":635,"co":"IT","region":"Piemonte","cat":"monastery-church","themes":["unesco","historic","architecture","panoramic-view","hidden-gem","year-round"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":1,"sc":8,"td":"UNESCO Sacro Monte (1591) dedicated to the Holy Trinity, on a wooded hill above Ghiffa overlooking Lago Maggiore. Three chapels and a porticoed Via Crucis with frescoes; serene forest setting.","rs":"Drive or walk from Ghiffa lakeside (ferry stop). Free entry. Peaceful and uncrowded alternative to the busier Borromean Islands circuit.","wl":"en","wt":"Sacro Monte di Ghiffa","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Porticato_Via_Crucis_e_cappella_di_San_Giovanni_Battista_-_Sacro_Monte_di_Ghiffa_-_UNESCO_patrimonio_mondiale_dell%27umanit%C3%A0_%282003%29.jpg?width=800"},
  {"n":"Stresa","la":45.88361,"lo":8.53944,"e":200,"co":"IT","region":"Piemonte","cat":"village","themes":["iconic","photogenic","panoramic-view","family-friendly","year-round","cable-car","historic"],"access":["car","train","boat"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":8,"td":"Belle Époque lakefront resort on Lago Maggiore; departure point for Borromean Islands ferries and Mottarone cable car. Grand hotels line the flower-bordered promenade. Hemingway set A Farewell to Arms here.","rs":"Cable car to Mottarone from Stresa Lido. Ferries to Borromean Islands every 30 min (spring–autumn). Villa Pallavicino gardens (entry fee) worth an hour.","wl":"en","wt":"Stresa","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Stresa_Levo.jpg?width=800"},
  {"n":"Val Grande National Park","la":46.03,"lo":8.45,"e":null,"co":"IT","region":"Piemonte","cat":"national-park","themes":["hike-required","hidden-gem","photogenic","special-experience"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":4,"sc":8,"td":"Italy's largest true wilderness: 15,000ha of untamed Piedmontese Alps in VCO, with primeval forests, high ridges and almost no trails. Rugged WWII partisan history; Europe's wildest national park.","rs":"Enter via Cicogna or Intragna. Serious hiking only — carry map and emergency kit. Guided treks via park authority. No facilities inside; sleep in rifugi. Best spring or autumn.","wl":"en","wt":"Val Grande National Park","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Parco_Val_Grande_seen_from_Pian_Cavallone.jpg?width=800"},
  {"n":"Villa Taranto Botanical Gardens","la":45.925,"lo":8.56,"e":200,"co":"IT","region":"Piemonte","cat":"special-experience","themes":["photogenic","family-friendly","year-round","car-accessible","boat-accessible"],"access":["car","boat","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":8,"td":"Outstanding botanical gardens (16ha) in Pallanza/Verbania on Lago Maggiore. Created 1931–1938 by Scottish officer Neil McEacharn: 20,000+ plant species, world-famous tulip and dahlia seasonal displays.","rs":"Open April–October (entry fee). Ferry from Stresa or Baveno to Pallanza. Allow 2h. Gift shop and café on site. Best in May (tulips) or September (dahlias).","wl":"en","wt":"Giardini Botanici Villa Taranto","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Botanical_gardens,_Villa_Taranto.jpg?width=800"},
  {"n":"Lago di Mergozzo","la":45.95556,"lo":8.46667,"e":193,"co":"IT","region":"Piemonte","cat":"alpine-lake","themes":["swimmable","photogenic","family-friendly","hidden-gem","year-round"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":1,"sc":7,"td":"Italy's cleanest swimming lake: a tiny glacially carved gem (2km long) in VCO province, spring-fed with no motorboat traffic. The historic village of Mergozzo sits on the north shore.","rs":"Free swimming; park in Mergozzo village. Peaceful 5km lakeside walk. Dramatically quieter and cleaner than nearby Lago Maggiore. Bring a picnic.","wl":"en","wt":"Lago di Mergozzo","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Aerial_image_of_Lago_di_Mergozzo_(view_from_the_south).jpg?width=800"},
  {"n":"Sacro Monte di Belmonte","la":45.36667,"lo":7.63139,"e":822,"co":"IT","region":"Piemonte","cat":"monastery-church","themes":["unesco","historic","architecture","panoramic-view","hidden-gem","year-round"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":1,"sc":7,"td":"UNESCO Sacro Monte (1712) on the Belmonte hill above Valperga in Canavese. Eight chapels of the Passion with panoramic views over the Turin plain and the pre-Alpine Canavese foothills.","rs":"Short drive from Ivrea or Turin. Free entry; open year-round. Small café in summer. Best on a clear day for views of the plain and Alps.","wl":"en","wt":"Sacro Monte di Belmonte","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Sacro_Monte_Belmonte_panorama.jpg?width=800"},
  {"n":"Sacro Monte di Crea","la":45.09472,"lo":8.26972,"e":438,"co":"IT","region":"Piemonte","cat":"monastery-church","themes":["unesco","historic","architecture","year-round","panoramic-view"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":7,"td":"UNESCO Sacro Monte around one of Italy's oldest Marian sanctuaries (c.350 AD). 23 chapels in a wooded 34ha nature park, with paintings by Il Moncalvo. On the highest hill of Basso Monferrato.","rs":"Drive through the park; good parking at top. Best in spring for wildflowers. Combine with Casale Monferrato. Restaurant within the park grounds.","wl":"en","wt":"Sacro Monte di Crea","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Sacro_Monte_di_Crea_1.jpg?width=800"},
  {"n":"Sestriere","la":44.95,"lo":6.88333,"e":2035,"co":"IT","region":"Piemonte","cat":"village","themes":["winter-sport","photogenic","year-round","panoramic-view","car-accessible"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":1,"sc":7,"td":"Italy's highest purpose-built ski resort (2,035m), designed in the 1930s by the Agnelli/FIAT family. Part of the Via Lattea (400km pistes). Hosted 2006 Winter Olympics; sweeping views to Monte Viso.","rs":"Year-round access by road from Cesana or Pinerolo. Ski season Nov–Apr; mountain biking and hiking summer. Good base for Cottian Alps high-altitude routes.","wl":"en","wt":"Sestriere","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Sestriere_2017.jpg?width=800"},

  /* ── Valle d'Aosta ────────────────────────────────────────── */
  {"n":"Aosta — Augusta Praetoria","la":45.73333,"lo":7.31667,"e":583,"co":"IT","region":"Valle d'Aosta","cat":"old-town","themes":["historic","architecture","year-round","family-friendly","car-accessible","iconic"],"access":["car","train"],"season":["spring","summer","autumn","winter"],"dur":5,"sc":10,"td":"Roman colony founded 25 BC as Augusta Praetoria Salassorum. Among the finest Roman remains in Alpine Europe: intact Porta Praetoria gate, Arch of Augustus (25 BC), Roman Theatre north wall and city walls.","rs":"The 'Rome of the Alps': the Arch of Augustus still spans the ancient Via delle Gallie. The Roman Theatre's 22 m north wall is the best-preserved theatre façade in northern Italy.","wl":"en","wt":"Aosta","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Aosta_and_mountains.jpg?width=800"},
  {"n":"Forte di Bard","la":45.60889,"lo":7.74583,"e":400,"co":"IT","region":"Valle d'Aosta","cat":"castle-fortress","themes":["iconic","historic","architecture","car-accessible","family-friendly","special-experience"],"access":["car"],"season":["spring","summer","autumn","winter"],"dur":4,"sc":10,"td":"Massive 19th-century Savoyard fortress commanding the narrow Bard gorge, rebuilt after Napoleon's 1800 siege. Houses the Alps Museum and contemporary art gallery; location used for Avengers: Age of Ultron filming.","rs":"Napoleon's Grande Armée was held up here for two weeks in May 1800. Three fortress tiers linked by panoramic gondola lifts. Italy's most-visited alpine fortress with sheer gorge-side ramparts.","wl":"en","wt":"Fort Bard","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Forte_di_Bard.jpg?width=800"},
  {"n":"Gran Paradiso","la":45.51444,"lo":7.26972,"e":4061,"co":"IT","region":"Valle d'Aosta","cat":"mountain-summit","themes":["iconic","hike-required","panoramic-view","photogenic"],"access":["foot"],"season":["summer"],"dur":3,"sc":10,"td":"Italy's only 4,000 m+ peak entirely within its territory (4,061 m), in Gran Paradiso NP. The easiest Italian four-thousander, with a Madonna statue at the rocky true summit (4,058 m).","rs":"Ascent from Refuge Frédéric Chabod or Victor Emmanuel II hut. Alpine ibex are routinely seen on approach slopes. Summit view encompasses Mont Blanc, Matterhorn and Monte Rosa.","wl":"en","wt":"Gran Paradiso","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Gran_Paradiso.jpg?width=800"},
  {"n":"Gran Paradiso National Park","la":45.50278,"lo":7.31,"e":null,"co":"IT","region":"Valle d'Aosta","cat":"national-park","themes":["iconic","year-round","family-friendly","panoramic-view","photogenic"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":5,"sc":10,"td":"Italy's first national park (est. 1922), protecting 703 km² of Graian Alps with ~4,000 Alpine ibex, chamois, marmots, golden eagles, 57 glaciers and 724 km of marked trails across Aosta Valley and Piedmont.","rs":"Created on Victor Emmanuel II's royal hunting reserve. The Alpine ibex was saved from extinction here. Today ibex walk fearlessly past hikers — one of Europe's great wildlife encounters.","wl":"en","wt":"Gran Paradiso National Park","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Gran_Paradiso_Panorama.jpg?width=800"},
  {"n":"Matterhorn / Monte Cervino","la":45.97639,"lo":7.65861,"e":4478,"co":"IT","region":"Valle d'Aosta","cat":"mountain-summit","themes":["iconic","photogenic","panoramic-view","hike-required"],"access":["foot"],"season":["summer"],"dur":2,"sc":10,"td":"The world's most recognisable mountain pyramid at 4,478 m straddles the Italy–Switzerland border. The Italian south face towers above Breuil-Cervinia with a character quite distinct from the Swiss Zermatt view.","rs":"The Italian Leone and Furggen ridges are serious alpine routes. First ascent of the Italian ridge was in 1865. The south face view from Cervinia is unmistakably dramatic.","wl":"en","wt":"Matterhorn","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Matterhorn_from_Domh%C3%BCtte_-_2.jpg?width=800"},
  {"n":"Skyway Monte Bianco","la":45.81583,"lo":6.95639,"e":3466,"co":"IT","region":"Valle d'Aosta","cat":"viewpoint-panorama","themes":["iconic","cable-car","panoramic-view","photogenic","year-round","family-friendly"],"access":["cable-car"],"season":["spring","summer","autumn","winter"],"dur":4,"sc":10,"td":"World's most expensive cable car (€138 m, 2015), twin revolving cabins from Entrèves (1,300 m) to Pointe Helbronner (3,466 m). Each 80-seat cabin rotates 360° during ascent for Mont Blanc massif panoramas.","rs":"Cabin rotates one full revolution per segment so every seat gets the view. Top platform straddles the France–Italy border above the Vallée Blanche glacial sea.","wl":"en","wt":"Skyway Monte Bianco","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Skyway_Monte_Bianco.jpg?width=800"},
  {"n":"Cogne","la":45.60806,"lo":7.35556,"e":1534,"co":"IT","region":"Valle d'Aosta","cat":"village","themes":["year-round","family-friendly","car-accessible","panoramic-view"],"access":["car"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":9,"td":"Charming gateway village to Gran Paradiso NP at 1,534 m, renowned for Italy's premier Nordic skiing (80 km groomed piste), traditional Cogne lace craft and the protected Prati di Sant'Orso meadow.","rs":"The Prati di Sant'Orso meadow is a legally protected 'Wonder of Italy'. In summer, ibex and chamois descend from the peaks to drink at the village edge. Lace-making tradition since the 13th century.","wl":"en","wt":"Cogne","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/CogneAugust072023_06.jpg?width=800"},
  {"n":"Fénis Castle","la":45.73737,"lo":7.48955,"e":null,"co":"IT","region":"Valle d'Aosta","cat":"castle-fortress","themes":["iconic","historic","architecture","car-accessible","photogenic"],"access":["car"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":9,"td":"The most-photographed castle in Aosta Valley: 14th-century concentric fortification with five corner towers, double battlemented walls, and a courtyard with frescoes by the school of Giacomo Jaquerio.","rs":"Built 1320–1420 by the Challant family. Inner courtyard frescoes depict wise men, saints and prophets with Old French proverb inscriptions — among the finest medieval Alpine painting cycles.","wl":"en","wt":"Fénis Castle","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/CastelloDiF%C3%A9nisJuly292023_06.jpg?width=800"},
  {"n":"Pointe Helbronner","la":45.84583,"lo":6.93167,"e":3462,"co":"IT","region":"Valle d'Aosta","cat":"viewpoint-panorama","themes":["iconic","cable-car","panoramic-view","photogenic","year-round"],"access":["cable-car"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":9,"td":"Franco-Italian border summit at 3,462 m, top station of Skyway Monte Bianco. Sweeping 360° panorama over the Vallée Blanche glacial sea, Aiguille du Midi, Matterhorn, Monte Rosa and Gran Paradiso.","rs":"Connects via Vallée Blanche Aerial Tramway to Aiguille du Midi — start of the legendary 24 km Vallée Blanche ski descent to Chamonix. Adjacent Refuge Torino for overnight stays.","wl":"en","wt":"Pointe Helbronner","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Punta_Helbronner.JPG?width=800"},
  {"n":"QC Terme Pré-Saint-Didier","la":45.767,"lo":6.983,"e":1004,"co":"IT","region":"Valle d'Aosta","cat":"spa-wellness","themes":["iconic","spa-wellness","panoramic-view","year-round","family-friendly"],"access":["car"],"season":["spring","summer","autumn","winter"],"dur":4,"sc":9,"td":"Italy's most spectacular mountain thermal spa at 1,004 m with open-air heated pools, steam grottos and panoramic relaxation terraces overlooking Mont Blanc and the Valdigne valley.","rs":"Outdoor pools at 36 °C in full view of Mont Blanc, even during winter snowfall. Evening full-moon bathing sessions create a magical atmosphere. Advance booking essential.","wl":"en","wt":"Pré-Saint-Didier","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Pre-Saint-Didier_%28AO%29_Thermes.jpg?width=800"},
  {"n":"Breuil-Cervinia","la":45.935,"lo":7.631,"e":2050,"co":"IT","region":"Valle d'Aosta","cat":"village","themes":["iconic","winter-sport","year-round","cable-car","panoramic-view"],"access":["car"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":8,"td":"High-altitude Italian ski resort at 2,050 m at the foot of the Matterhorn, sharing a vast ski area with Swiss Zermatt via the Plateau Rosa glacier with summer skiing available until July.","rs":"One of Europe's highest resort villages. The Theodul Pass link to Zermatt makes this a unique cross-border ski domain. The Italian Matterhorn perspective here is uniquely dramatic.","wl":"en","wt":"Breuil-Cervinia","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/CervinoAug252023_03.jpg?width=800"},
  {"n":"Cascate di Lillaz","la":45.598,"lo":7.381,"e":1612,"co":"IT","region":"Valle d'Aosta","cat":"waterfall-gorge","themes":["photogenic","family-friendly","hike-required"],"access":["foot"],"season":["spring","summer","autumn"],"dur":2,"sc":8,"td":"Three-tiered cascade in Gran Paradiso NP plunging through a rocky gorge near the hamlet of Lillaz, Cogne. Thunderous in early summer snowmelt; a series of wooden footbridges cross the gorge at each tier.","rs":"Easy 20-min signed nature trail from Lillaz car park. Peak water volume in June–July from snowmelt. The upper gorge has vertical rock walls draped in spray — photogenic in any light.","wl":"it","wt":"Cascate di Lillaz","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Cascate_di_Lillaz.jpg?width=800"},
  {"n":"Castel Savoia","la":45.786,"lo":7.829,"e":1702,"co":"IT","region":"Valle d'Aosta","cat":"castle-fortress","themes":["historic","architecture","hidden-gem","panoramic-view"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":8,"td":"Romantic late 19th-century neo-Gothic royal castle in Gressoney-Saint-Jean, built as the mountain retreat of Queen Margherita of Savoy, with terraced botanical gardens offering Monte Rosa panoramas.","rs":"Queen Margherita — first woman to summit Monte Rosa (1893) — had this fairy-tale castle built nearby. The alpine botanical park contains rare species beside spectacular Monte Rosa vistas.","wl":"it","wt":"Castel Savoia","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Gressoney-Saint-Jean_-_Castel_Savoia_-_2025-09-10_23-37-32_001.jpg?width=800"},
  {"n":"Courmayeur","la":45.783,"lo":6.967,"e":1224,"co":"IT","region":"Valle d'Aosta","cat":"village","themes":["iconic","year-round","family-friendly","car-accessible","winter-sport","panoramic-view"],"access":["car"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":8,"td":"Italy's premier Mont Blanc resort village at 1,224 m, with a pedestrian historic centre of alpine-chic boutiques, gourmet restaurants and direct access to the Skyway Monte Bianco cable car.","rs":"Southern portal of the Mont Blanc Tunnel (to Chamonix). The Via Roma is one of the Alps' most elegant resort streets. Start of the Tour du Mont Blanc long-distance circuit.","wl":"en","wt":"Courmayeur","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/CourmayeurAug052024_01.jpg?width=800"},
  {"n":"Lago Blu","la":45.928,"lo":7.635,"e":2045,"co":"IT","region":"Valle d'Aosta","cat":"alpine-lake","themes":["photogenic","panoramic-view","iconic","car-accessible"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":8,"td":"Small glacial lake in the Valtournenche valley at 2,045 m, celebrated for its crystal-clear water reflecting the Matterhorn's Italian south face — one of the Alps' most iconic mirror-image photographs.","rs":"Accessible by a short walk from the SS46 road ascending to Breuil-Cervinia. Best shot at dawn in calm weather when the Matterhorn reflection is perfectly still.","wl":"en","wt":"Lago Blu (Valtournenche)","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Lago_Blu_-_Matterhorn.jpg?width=800"},
  {"n":"Plateau Rosa","la":45.93348,"lo":7.70994,"e":3480,"co":"IT","region":"Valle d'Aosta","cat":"glacier","themes":["winter-sport","year-round","cable-car","panoramic-view","photogenic"],"access":["cable-car"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":8,"td":"High-altitude glacier plateau at ~3,480 m between Italian Testa Grigia and Swiss Klein Matterhorn, offering summer skiing, stunning close Matterhorn views and a cross-border link into Zermatt.","rs":"Summer skiing while the valleys swelter below. Since 2023 the Zermatt–Cervinia ski link was reopened via Testa Grigia. One of Europe's only year-round ski areas above 3,400 m.","wl":"en","wt":"Plateau Rosa","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Plateau_Rosa.jpg?width=800"},
  {"n":"Valnontey & Paradisia Alpine Garden","la":45.602,"lo":7.342,"e":1666,"co":"IT","region":"Valle d'Aosta","cat":"national-park","themes":["family-friendly","hike-required","hidden-gem","photogenic"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":4,"sc":8,"td":"Alpine valley hamlet south of Cogne at 1,666 m with the Paradisia Botanical Garden (900+ alpine species at 1,700 m, open June–Sept) and the main trailhead for the Gran Paradiso summit via Refuge Victor Emmanuel II.","rs":"Paradisia is one of Italy's highest botanical gardens. Valnontey valley is prime ibex habitat — they regularly descend to the valley floor. The Tor des Géants race passes through here.","wl":"it","wt":"Giardino Botanico Alpino Paradisia","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Giardino_Botanico_Alpino_Paradisia_abc2.JPG?width=800"},
  {"n":"Castello di Saint-Pierre","la":45.713,"lo":7.214,"e":null,"co":"IT","region":"Valle d'Aosta","cat":"castle-fortress","themes":["historic","architecture","car-accessible","panoramic-view"],"access":["car"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":7,"td":"Striking medieval castle perched on a rocky pinnacle above the Dora Baltea valley near Aymavilles, today housing the Aosta Valley Regional Museum of Natural Sciences with geology and alpine fauna collections.","rs":"One of the most photogenic castles visible from the A5 motorway main corridor. The Natural Sciences Museum inside documents the region's alpine geology, glaciers and endemic flora and fauna.","wl":"it","wt":"Castello di Saint-Pierre","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Castello_di_Saint-Pierre_%282%29.jpg?width=800"},
  {"n":"Gressoney-La-Trinité","la":45.83333,"lo":7.83333,"e":1635,"co":"IT","region":"Valle d'Aosta","cat":"village","themes":["hidden-gem","historic","family-friendly","year-round","panoramic-view"],"access":["car"],"season":["spring","summer","autumn","winter"],"dur":3,"sc":7,"td":"Authentic Walser village at 1,635 m at the foot of Monte Rosa, preserving 12th-century Germanic alpine culture with traditional Speicher log granaries, Walser dialect (Titsch) and folk festivals.","rs":"One of Italy's most intact Walser communities. Traditional costumes are worn at festivals; the Titsch dialect is still spoken. Gateway to Monterosa Ski and the Punta Indren glacier.","wl":"en","wt":"Gressoney-La-Trinité","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/GressoneyLT_veduta.jpg?width=800"},
  {"n":"Issogne Castle","la":45.65495,"lo":7.68587,"e":365,"co":"IT","region":"Valle d'Aosta","cat":"castle-fortress","themes":["historic","architecture","car-accessible"],"access":["car"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":7,"td":"Late Gothic palace-castle in lower Aosta Valley, c. 1490, featuring a celebrated pomegranate-tree fountain and the Alps' finest cycle of medieval everyday-life frescoes in the arcaded courtyard portico.","rs":"Giorgio di Challant's frescoes depict butchers, spice merchants, tavern keepers and market stalls in vivid detail — an unmatched window into 15th-century alpine commercial life.","wl":"en","wt":"Issogne Castle","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/IssogneJuly292023_01.jpg?width=800"},
  {"n":"Italian Val Ferret","la":45.869,"lo":7.058,"e":1587,"co":"IT","region":"Valle d'Aosta","cat":"viewpoint-panorama","themes":["photogenic","panoramic-view","hike-required","year-round"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":5,"sc":7,"td":"Glacier-carved valley NE of Courmayeur, flanked by the Grandes Jorasses (4,208 m) north face. The Tour du Mont Blanc trail follows the valley floor past Planpincieux to the Grand Col Ferret into Switzerland.","rs":"The Planpincieux Glacier above the road is actively monitored for rapid movement — it has triggered emergency road closures. Plan de la Gola road-end is the Swiss border trailhead.","wl":"en","wt":"Val Ferret","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Mont_Blanc_depuis_Val_Ferret.jpg?width=800"},
  {"n":"Pont d'Aël","la":45.67667,"lo":7.22231,"e":950,"co":"IT","region":"Valle d'Aosta","cat":"bridge-engineering","themes":["historic","hidden-gem","architecture","hike-required"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2,"sc":7,"td":"Roman aqueduct bridge built c. 3 BC over the Cogne torrent gorge near Aymavilles, unique double structure: lower enclosed water channel with upper service walkway — both can be entered on guided visits.","rs":"One of the best-preserved pieces of Roman alpine engineering. The 50 m-high aqueduct gallery is walkable. Constructed without explosives by drilling the rock — a feat still impressive today.","wl":"en","wt":"Pont d'Aël","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/01_Pont_d%27A%C3%ABl%2C_Aosta_Valley%2C_Italy._Bridge_Arch.jpg?width=800"},
  {"n":"Val Veny & Lago Combal","la":45.799,"lo":6.872,"e":1961,"co":"IT","region":"Valle d'Aosta","cat":"alpine-lake","themes":["photogenic","panoramic-view","hike-required","hidden-gem"],"access":["car","foot"],"season":["summer","autumn"],"dur":4,"sc":7,"td":"Glacial valley on the south flank of Mont Blanc featuring emerald Lago Combal (1,961 m), the Miage Glacier snout and sheer alpine walls. The Tour du Mont Blanc trail crosses the flat glacial plain.","rs":"Italian ibex roam freely on the Combal plain. The Miage Glacier tongue almost reaches the valley floor. Rarely crowded despite the proximity to Courmayeur — a true alpine gem.","wl":"en","wt":"Val Veny","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Val_Veny.jpg?width=800"},
  {"n":"Verrès Castle","la":45.67,"lo":7.6958,"e":null,"co":"IT","region":"Valle d'Aosta","cat":"castle-fortress","themes":["historic","architecture","car-accessible","photogenic"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":2,"sc":7,"td":"Austere 14th-century military fortress on a 70 m rocky promontory, a single monolithic cube 30 m per side built by Yblet de Challant in 1390 to guard the Val d'Ayas approach. One of the Alps' purest military castles.","rs":"Unlike the decorative Challant residences, Verrès was designed purely for war — no windows, no decoration, total dominance of the gorge below. The interior reveals a surprisingly sophisticated layout.","wl":"en","wt":"Verrès Castle","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/CastelloDiVerresJuly292023_04.jpg?width=800"},
  {"n":"Lago Goillet","la":45.93604,"lo":7.66686,"e":2560,"co":"IT","region":"Valle d'Aosta","cat":"alpine-lake","themes":["hidden-gem","photogenic","panoramic-view"],"access":["foot"],"season":["summer","autumn"],"dur":3,"sc":6,"td":"Glacial reservoir at ~2,560 m in the Plan Maison area above Breuil-Cervinia, offering an uncrowded Matterhorn south-face panorama far above the tourist bustle of the resort village.","rs":"A hidden gem reached on foot from the Plan Maison ski area or via summer trail from Cervinia. The Matterhorn dominates the skyline with no resort infrastructure in view.","wl":"it","wt":"Lago Goillet","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Lago_Goillet_2022.jpg?width=800"},

  /* ── Friuli Venezia Giulia ────────────────────────────────────────── */
  {"n":"Aquileia","la":45.76972,"lo":13.37119,"e":5,"co":"IT","region":"Friuli Venezia Giulia","cat":"museum-cultural","themes":["unesco","historic","architecture","car-accessible","year-round","family-friendly"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":2.5,"sc":10,"td":"Roman colony founded 181 BC; one of the empire's five largest cities and a UNESCO World Heritage Site. The 4th-century basilica floor contains the largest early-Christian mosaic in the Western world — over 700 m² of narrative floor art.","rs":"Walk the Roman forum ruins, enter the basilica for the breathtaking floor mosaics (allow 45 min), then tour the Museo Archeologico Nazionale's amber, glass and portrait busts from the 2nd-century AD harbour city.","wl":"en","wt":"Aquileia","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Basilica_Patriarcale_%28Aquileia%29_-_Exterior.jpg?width=800"},
  {"n":"Cividale del Friuli","la":46.1,"lo":13.433,"e":135,"co":"IT","region":"Friuli Venezia Giulia","cat":"old-town","themes":["unesco","historic","architecture","photogenic","year-round","car-accessible"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":2.5,"sc":10,"td":"UNESCO 'Longobards in Italy: Places of Power' — first Lombard duchy capital (568 AD) and Julius Caesar's Forum Iulii. Medieval lanes above the Natisone gorge, anchored by the Tempietto Longobardo and the medieval Devil's Bridge.","rs":"Walk from the Duomo to the Museo Nazionale, cross the Ponte del Diavolo above the gorge, then enter the Tempietto — a half-day UNESCO circuit through 2,000 years of layered Friulian history.","wl":"en","wt":"Cividale del Friuli","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Cividale_in_panoramic.jpg?width=800"},
  {"n":"Laghi di Fusine","la":46.473,"lo":13.648,"e":924,"co":"IT","region":"Friuli Venezia Giulia","cat":"alpine-lake","themes":["photogenic","swimmable","car-accessible","panoramic-view","family-friendly","year-round"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2.0,"sc":9,"td":"Two glacier-fed emerald lakes at 924 m beneath Mangart's north face near Tarvisio. The upper lake's mirror-still reflections of limestone walls and spruce forest are among the most iconic alpine-lake images in the Italian Alps.","rs":"Park at the Fusine valley entrance and walk the 5 km signed loop linking both lakes through spruce forest; combine with the Mangart saddle road for a full-day Julian Alps circuit.","wl":"it","wt":"Laghi di Fusine","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/2013-08-17_Lago_di_Fusine_superiore_-hu-_A_4547.jpg?width=800"},
  {"n":"Mangart (Sella di Mangart Road)","la":46.44,"lo":13.65389,"e":2679,"co":"IT","region":"Friuli Venezia Giulia","cat":"mountain-summit","themes":["panoramic-view","hike-required","car-accessible","photogenic","summer-only","special-experience"],"access":["car","foot"],"season":["summer","autumn"],"dur":3.5,"sc":9,"td":"Julian Alps border summit at 2,679 m shared with Slovenia. The Italian-side road from Cave del Predil climbs to Sella di Mangart (2,072 m) — one of the highest paved drives in the eastern Alps — with vast panoramas over the Fusine lakes, Tarvisio and Triglav.","rs":"Drive from Cave del Predil or Fusine valley to Sella di Mangart, then tackle the via ferrata to the summit for 360° views spanning Italy, Slovenia and Austria.","wl":"en","wt":"Mangart","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Mangart_16.jpg?width=800"},
  {"n":"Parco Naturale Dolomiti Friulane","la":46.333,"lo":12.567,"e":null,"co":"IT","region":"Friuli Venezia Giulia","cat":"national-park","themes":["unesco","panoramic-view","hike-required","photogenic","hidden-gem","special-experience"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":5.0,"sc":9,"td":"The least-visited part of the UNESCO Dolomites World Heritage Site: 36,950 ha of untouched limestone spires, deep gorges and pristine rivers. Europe's largest roadless nature reserve, home to 16 golden eagles and alpine ibex.","rs":"Enter via Forni di Sopra or Cimolais; hike the Sentiero della Val Zemola for gorge scenery, or take the boat transfer through Vajont to remote Erto cliff villages on the reserve's south edge.","wl":"en","wt":"Friulian Dolomites Natural Park","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Lorenzago_Cridola_2.JPG?width=800"},
  {"n":"Sacrario Militare di Redipuglia","la":45.867,"lo":13.483,"e":23,"co":"IT","region":"Friuli Venezia Giulia","cat":"museum-cultural","themes":["historic","car-accessible","year-round","special-experience","iconic"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":1.5,"sc":9,"td":"Italy's largest WWI military memorial: 100,000 Italian soldiers rest on 22 terraced marble steps on Monte Sei Busi, each grave inscribed 'Presente!' — one of the most emotionally powerful monuments in Europe, built 1938.","rs":"Drive or take the train to Fogliano Redipuglia station; climb the 22 marble staircase terraces to the hilltop cross for views over the Isonzo plain — site of 11 WWI battles and over 650,000 deaths.","wl":"en","wt":"Sacrario militare di Redipuglia","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Sacrario_Militare_di_Redipuglia.jpg?width=800"},
  {"n":"Sauris (Zahre)","la":46.467,"lo":12.717,"e":1212,"co":"IT","region":"Friuli Venezia Giulia","cat":"village","themes":["hidden-gem","food-drink","photogenic","year-round","car-accessible","historic"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":2.5,"sc":9,"td":"One of Italy's most beautiful villages at 1,212 m — a German-speaking (Zahrisch dialect) enclave of 400 residents established c. 1300. Famed for prized mountain speck ham, artisan Zahre craft beer and traditional timber architecture.","rs":"Wind up the narrow access road to Sauris di Sopra; visit the Petris speck curing house, tour the Zahre brewery, then hike the ridge trail for views down over the dam lake.","wl":"en","wt":"Sauris","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Sauris_di_Sopra_002.jpg?width=800"},
  {"n":"Tarvisio","la":46.505,"lo":13.57833,"e":754,"co":"IT","region":"Friuli Venezia Giulia","cat":"village","themes":["year-round","winter-sport","car-accessible","historic","family-friendly","iconic"],"access":["car","train","foot"],"season":["spring","summer","autumn","winter"],"dur":2.0,"sc":9,"td":"Italy's alpine border town where Romance, Germanic and Slavic Europe meet at the Tre Confini tripoint. Lively gateway to Fusine lakes, Predil, Mangart road and Monte Lussari cable-car pilgrimage shrine, all within 20 km.","rs":"Base yourself in Tarvisio for day trips: Fusine lakes, Predil lake, Mangart road and the Lussari cable car; well-served by rail from Udine and on the Villach–Venice line.","wl":"en","wt":"Tarvisio","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Trbiz.JPG?width=800"},
  {"n":"Forni di Sopra","la":46.417,"lo":12.583,"e":907,"co":"IT","region":"Friuli Venezia Giulia","cat":"village","themes":["photogenic","car-accessible","winter-sport","year-round","family-friendly","panoramic-view"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":2.0,"sc":8,"td":"Mountain resort village at 907 m at the source of the Tagliamento, bordering the Dolomiti Friulane NP. Friuli's most-visited alpine settlement, renowned for 3,000+ wild-flower species and ski slopes reaching 2,100 m.","rs":"Drive the scenic SS52 to Forni di Sopra; hike the Tagliamento glacier trail, take the Varmost lift for Dolomiti Friulane panoramas, or ski the high Crusicalas slopes in winter.","wl":"en","wt":"Forni di Sopra","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/FornidiSopra-panorama.jpg?width=800"},
  {"n":"Lago di Barcis","la":46.183,"lo":12.567,"e":409,"co":"IT","region":"Friuli Venezia Giulia","cat":"alpine-lake","themes":["photogenic","swimmable","car-accessible","panoramic-view","family-friendly","hidden-gem"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":2.0,"sc":8,"td":"A spectacular turquoise reservoir carved into the Valcellina gorge of the Friulian Dolomites pre-Alps. Its vivid teal colour and the Dint trail Skywalk — a glass-floored walkway bolted above the waterline — are unmissable.","rs":"Drive SS251 from Pordenone through the dramatic Cellina gorge road to Barcis; walk the Dint via ferrata Skywalk for aerial lake views, or rent a kayak from the village shore.","wl":"en","wt":"Barcis","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Lago_di_Barcis_%28Barcis_Lake%29_-_Dint_trail.jpg?width=800"},
  {"n":"Sella Nevea & Monte Canin","la":46.39056,"lo":13.47556,"e":1195,"co":"IT","region":"Friuli Venezia Giulia","cat":"viewpoint-panorama","themes":["winter-sport","cable-car","panoramic-view","hike-required","photogenic","year-round"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":3.0,"sc":8,"td":"Julian Alps pass at 1,195 m linking Chiusaforte with Cave del Predil. The cross-border Kanin funifor cable car ascends to 2,292 m, unlocking vast snowfields, high-karst plateaus and ski runs lasting into May.","rs":"Drive up from Chiusaforte; ride the Kanin funifor to the upper plateau at 2,292 m for panoramic karst hiking, or ski the international slopes across the Italian–Slovenian border.","wl":"en","wt":"Sella Nevea","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Sella_Nevea.jpg?width=800"},
  {"n":"Tempietto Longobardo","la":46.093,"lo":13.431,"e":135,"co":"IT","region":"Friuli Venezia Giulia","cat":"monastery-church","themes":["unesco","historic","architecture","hidden-gem","year-round","car-accessible"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":1.0,"sc":8,"td":"The finest surviving Lombard interior in the world: an 8th-century palatine chapel with breathtaking stucco figures of six female saints and vibrant frescoes inside Cividale del Friuli — a UNESCO Longobards in Italy heritage site.","rs":"Enter through the Museo Cristiano in Cividale del Friuli; allow at least an hour for the stucco ceiling, fresco paintings and carved columns of this tiny but astonishing Lombard jewel.","wl":"en","wt":"Oratorio di Santa Maria in Valle","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Cividale_0904_Tempietto_Longobardo.jpg?width=800"},
  {"n":"Lago del Predil","la":46.417,"lo":13.567,"e":969,"co":"IT","region":"Friuli Venezia Giulia","cat":"alpine-lake","themes":["photogenic","swimmable","car-accessible","panoramic-view","hidden-gem","historic"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":1.5,"sc":7,"td":"Turquoise alpine lake at 969 m — the second-largest natural lake in Friuli-VG — surrounded by Julian Alps peaks. Ruins of an 1885 Austro-Hungarian WWI fortress on the shore add history to stunning mountain scenery.","rs":"Easy circuit walk from Cave del Predil village around the lake; explore the fortress ruins and combine with the nearby Predil Pass road to the Slovenian border.","wl":"en","wt":"Lake Predil","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Lago_del_Predil%2C_Tarvisio%2C_2013.jpg?width=800"},
  {"n":"Lago di Sauris","la":46.447,"lo":12.718,"e":977,"co":"IT","region":"Friuli Venezia Giulia","cat":"alpine-lake","themes":["photogenic","car-accessible","panoramic-view","family-friendly","hidden-gem","swimmable"],"access":["car","foot"],"season":["spring","summer","autumn"],"dur":1.5,"sc":7,"td":"A high-altitude reservoir at ~977 m behind one of Europe's highest concrete dams, its electric-blue waters mirroring wooded Carnic Alps slopes. The dramatic dam walls and mountain reflections create a striking pre-alpine tableau beneath Sauris village.","rs":"Stop at the mirador on the access road just above the dam; combine with a lakeside forest walk and a full village visit up in Sauris di Sopra for the complete Carnic Alps experience.","wl":"it","wt":"Lago di Sauris","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Staumauer_vom_Lago_di_Sauris_07102007_03.jpg?width=800"},
  {"n":"Sappada (Plodn)","la":46.567,"lo":12.683,"e":1250,"co":"IT","region":"Friuli Venezia Giulia","cat":"village","themes":["hidden-gem","year-round","car-accessible","winter-sport","food-drink","photogenic"],"access":["car","foot"],"season":["spring","summer","autumn","winter"],"dur":2.0,"sc":7,"td":"Bavarian-dialect language island at 1,250 m, transferred from Veneto to Friuli in 2017. One of Italy's most beautiful villages, celebrated for traditional Plodn wooden hamlets (Kratten), winter carnival masks and Carnic Alps Dolomite scenery.","rs":"Drive the Piave valley road into Sappada; explore the ancient Kratten hamlets strung along the valley, ski the Plodn slopes in winter, or hike the Peralba ridge toward Monte Coglians in summer.","wl":"en","wt":"Sappada","bp":"https://commons.wikimedia.org/wiki/Special:FilePath/Sappada_panorama.jpg?width=800"}
];
