/* Helper: index POIs by category for fast filtering. */
const AUSTRIAN_POIS_BY_CAT = AUSTRIAN_POIS.reduce((m, p) => {
  (m[p.cat] = m[p.cat] || []).push(p); return m;
}, {});

/* Helper: index POIs by region. */
const AUSTRIAN_POIS_BY_REGION = AUSTRIAN_POIS.reduce((m, p) => {
  (m[p.region] = m[p.region] || []).push(p); return m;
}, {});

/* Helper: filter POIs by an array of themes (any-of match). */
function austrianPoisWithThemes(themes) {
  const set = new Set(themes);
  return AUSTRIAN_POIS.filter(p => p.themes.some(t => set.has(t)));
}

/* Helper: top-N most notable POIs (score >= threshold). */
function austrianPoisTop(n = 25, scoreFloor = 8) {
  return AUSTRIAN_POIS
    .filter(p => (p.sc || 0) >= scoreFloor)
    .slice()
    .sort((a, b) => (b.sc || 0) - (a.sc || 0))
    .slice(0, n);
}

if (typeof module !== 'undefined') {
  module.exports = { AUSTRIAN_POIS, AUSTRIAN_POIS_BY_CAT, AUSTRIAN_POIS_BY_REGION, austrianPoisWithThemes, austrianPoisTop };
}
/* ====== end   assets/js/austrian-pois.js ====== */
;
