function writeLayerModeStorage(key, value) {
  try {
    if (value === "" || value == null) window.localStorage?.removeItem(key);
    else window.localStorage?.setItem(key, String(value));
  } catch (_) {}
}
function sanitizeLayerModeId(modeId, fallback = "survey") {
  return LAYER_MODE_IDS.includes(modeId) ? modeId : fallback;
}
const LayerMode = {
  current: sanitizeLayerModeId(readLayerModeStorage(LAYER_MODE_STORAGE_KEY, "survey")),
  prior: sanitizeLayerModeId(readLayerModeStorage(LAYER_MODE_PRIOR_STORAGE_KEY, ""), ""),
  locked: readLayerModeStorage(LAYER_MODE_LOCKED_STORAGE_KEY, "false") === "true",
  customized: false,
};
window.LayerMode = LayerMode;
const POI_LAYER_PRESET_IDS = ["photo", "family", "cultural", "hidden", "wine"];
const POI_LAYER_PRESET_LABELS = {
  photo: "Photo",
  family: "Family",
  cultural: "Cultural",
  hidden: "Hidden",
  wine: "Wine",
};
const layerControlState = {
  passOverlayVisible: true,
  passStatuses: allPassStatusFilterSet(),
  passStatusLatch: "",
  passQualityMin: 0,
  poiFamilies: new Set(POI_FAMILY_KEYS),
  poiThemePreset: "",
  poiQualityMin: 0.6,
  poiPlannableOnly: false,
  soloFocus: false,
};
let layerControlInstance = null;
let conditionsStripInstance = null;
let applyingLayerModePreset = false;
let layerModeGhostTimer = null;
let layerModeToastTimer = null;
let layerModeToastEl = null;

function layerModeDefinition(modeId = LayerMode.current) {
  return LAYER_MODE_DEFINITIONS[sanitizeLayerModeId(modeId)];
}

function setLayerModePrior(modeId) {
  const prior = LAYER_MODE_IDS.includes(modeId) ? modeId : "";
  LayerMode.prior = prior;
  writeLayerModeStorage(LAYER_MODE_PRIOR_STORAGE_KEY, prior);
}

function prefersReducedLayerModeMotion() {
  return !!window.matchMedia?.("(prefers-reduced-motion: reduce)")?.matches;
}

function showLayerModeGhost(modeId) {
  if (prefersReducedLayerModeMotion()) return;
  const container = map.getContainer();
  container.querySelectorAll(".alpine-layer-mode-ghost").forEach(el => el.remove());
  clearTimeout(layerModeGhostTimer);
  const def = layerModeDefinition(modeId);
  const ghost = document.createElement("div");
  ghost.className = "itinera-layer-mode-ghost";
  ghost.innerHTML = `${uiIconHtml(def.iconId, "layer-mode-ghost-icon", def.label)} <span>${escapeHtml(def.label)} mode</span>`;
  ghost.setAttribute("aria-hidden", "true");
  container.appendChild(ghost);
  requestAnimationFrame(() => ghost.classList.add("is-visible"));
  layerModeGhostTimer = setTimeout(() => {
    ghost.classList.remove("is-visible");
    setTimeout(() => ghost.remove(), 180);
  }, 600);
}

function runLayerModeTransition(modeId) {
  if (prefersReducedLayerModeMotion()) return;
  const canvas = map.getCanvas?.();
  canvas?.classList.add("is-layer-mode-dipping");
  setTimeout(() => canvas?.classList.remove("is-layer-mode-dipping"), 300);
  showLayerModeGhost(modeId);
}

function showLayerModeToast(message) {
  if (!layerModeToastEl) {
    layerModeToastEl = document.createElement("div");
    layerModeToastEl.className = "itinera-map-toast";
    layerModeToastEl.setAttribute("role", "status");
    layerModeToastEl.setAttribute("aria-live", "polite");
    map.getContainer().appendChild(layerModeToastEl);
  }
  layerModeToastEl.textContent = message;
  layerModeToastEl.classList.add("is-visible");
  clearTimeout(layerModeToastTimer);
  layerModeToastTimer = setTimeout(() => {
    layerModeToastEl?.classList.remove("is-visible");
  }, 1400);
}

function markLayerModeCustomized() {
  if (applyingLayerModePreset || LayerMode.customized) return;
  LayerMode.customized = true;
  refreshLayerControlUI();
}

function applyLayerModeBasemap(name, { initial = false } = {}) {
  const next = VECTOR_BASEMAPS.find(b => b.name === name);
  if (!next) return;
  if (!initial) {
    setBaseMapByName(next.name);
    return;
  }
  const changed = currentBaseLayerName !== next.name;
  currentBaseLayerName = next.name;
  updateMapInfo(currentBaseLayerName);
  if (changed) {
    map.setStyle(next.style);
    map.once("idle", restoreMapLayers);
  }
}

function applyLayerModeDefaults(modeId, { initial = false, animate = false, persist = true } = {}) {
  const def = layerModeDefinition(modeId);
  applyingLayerModePreset = true;
  try {
    LayerMode.current = def.id;
    LayerMode.customized = false;
    if (persist) writeLayerModeStorage(LAYER_MODE_STORAGE_KEY, def.id);
    layerControlState.passOverlayVisible = !!def.passOverlayVisible;
    layerControlState.passStatuses = new Set(def.passStatuses);
    layerControlState.passStatusLatch = "";
    layerControlState.passQualityMin = Number(def.passQualityMin) || 0;
    poiLayerVisible = !!def.poiLayerVisible;
    layerControlState.poiFamilies = new Set(POI_FAMILY_KEYS);
    layerControlState.poiThemePreset = def.poiThemePreset || "";
    layerControlState.poiQualityMin = Number(def.poiQualityMin) || 0;
    layerControlState.poiPlannableOnly = !!def.poiPlannableOnly;
    layerControlState.soloFocus = !!def.soloFocus && plannedRouteActive;
    applyLayerModeBasemap(def.basemap, { initial });
    if (!initial) {
      alpineOverlayLayer.setSoloFocus(layerControlState.soloFocus);
      map.getContainer().classList.toggle("pass-stack-solo-focus", layerControlState.soloFocus);
    }
  } finally {
    applyingLayerModePreset = false;
  }
  if (!initial) {
    if (animate) runLayerModeTransition(def.id);
    notifyLayerFiltersChanged({ passes: true, pois: true });
  }
}

function notifyInitialLayerModePresetApplied() {
  let notified = false;
  const notifyOnce = () => {
    if (notified) return;
    notified = true;
    setTimeout(() => notifyLayerFiltersChanged({ passes: true, pois: true }), 0);
  };
  if (typeof map.loaded === "function" && map.loaded()) {
    notifyOnce();
  } else if (typeof map.once === "function") {
    map.once("load", notifyOnce);
    map.once("idle", notifyOnce);
  } else {
    notifyOnce();
  }
}

function setLayerModeLocked(locked) {
  LayerMode.locked = !!locked;
  writeLayerModeStorage(LAYER_MODE_LOCKED_STORAGE_KEY, LayerMode.locked ? "true" : "false");
  refreshLayerControlUI();
  showLayerModeToast(LayerMode.locked ? "Mode locked" : "Mode unlocked");
}

function setPlannedRouteActive(next) {
  const active = !!next;
  if (plannedRouteActive === active) return;
  plannedRouteActive = active;
  if (active) {
    if (LayerMode.current === "plan") setLayerSoloFocus(true);
    if (LayerMode.locked) {
      showLayerModeToast("Mode locked");
      refreshLayerControlUI();
      return;
    }
    if (LayerMode.current !== "plan") {
      setLayerModePrior(LayerMode.current);
      applyLayerModeDefaults("plan", { animate: true });
    }
    return;
  }
  setLayerSoloFocus(false);
  if (LayerMode.locked) {
    setLayerModePrior("");
    showLayerModeToast("Mode locked");
    refreshLayerControlUI();
    return;
  }
  if (LayerMode.current === "plan" && LayerMode.prior) {
    const restoreMode = sanitizeLayerModeId(LayerMode.prior, "survey");
    setLayerModePrior("");
    applyLayerModeDefaults(restoreMode, { animate: true });
    return;
  }
  setLayerModePrior("");
  refreshLayerControlUI();
}

applyLayerModeDefaults(LayerMode.current, { initial: true });
notifyInitialLayerModePresetApplied();

function passLayerControlQualityLabel() {
  const stars = Math.round(layerControlState.passQualityMin * 5);
  return stars <= 0 ? "All passes" : `${stars}+`;
}

function passLayerControlQualityLabelHtml() {
  const stars = Math.round(layerControlState.passQualityMin * 5);
  return stars <= 0 ? "All passes" : `${generatedScoreHtml(stars)}+`;
}

function poiLayerControlQualityLabel() {
  const stars = Math.round(layerControlState.poiQualityMin * 5);
  return stars <= 0 ? "All sights" : `${stars}+`;
}

function poiLayerControlQualityLabelHtml() {
  const stars = Math.round(layerControlState.poiQualityMin * 5);
  return stars <= 0 ? "All sights" : `${generatedScoreHtml(stars)}+`;
}

function layerPoiPresetDefinition(id) {
  if (!id) return null;
  try {
    return POI_PRESETS?.[id] || null;
  } catch (_) {
    return null;
  }
}

function passesLayerControlFilter(p) {
  const view = statusDisplay(passStatus(p));
  if (!layerControlState.passStatuses.has(view.state || "unknown")) return false;
  if (view.estimated && !layerControlState.passStatuses.has("estimated")) return false;
  const threshold = Number(layerControlState.passQualityMin) || 0;
  if (threshold > 0 && (p.quality || 0) < threshold) return false;
  return true;
}

function poiLayerControlFilter(p) {
  const family = POI_FAMILY_OF_CATEGORY[p.poiCategory] || "";
  if (family && !layerControlState.poiFamilies.has(family)) return false;
  if (layerControlState.poiPlannableOnly && !isPlannablePoi(p)) return false;

  const preset = layerPoiPresetDefinition(layerControlState.poiThemePreset);
  const presetCats = Array.isArray(preset?.cats) ? preset.cats : [];
  const presetThemes = Array.isArray(preset?.themes) ? preset.themes : [];
  if (presetCats.length && !presetCats.includes(p.poiCategory)) return false;
  if (presetThemes.length && !(p.poiThemes || []).some(t => presetThemes.includes(t))) return false;

  const sliderMin = Number(layerControlState.poiQualityMin) || 0;
  const presetMin = Number.isFinite(preset?.minScore) ? preset.minScore / 10 : 0;
  const threshold = Math.max(sliderMin, presetMin);
  if (threshold > 0 && (p.quality || 0) < threshold) return false;
  return true;
}

function refreshLayerControlUI() {
  layerControlInstance?.refresh?.();
}

function refreshConditionsStrip() {
  conditionsStripInstance?.refresh?.();
}

function setLayerPassStatusLatch(state) {
  const key = PASS_LAYER_STATUS_KEYS.includes(state) ? state : "";
  const nextLatch = layerControlState.passStatusLatch === key ? "" : key;
  layerControlState.passStatusLatch = nextLatch;
  layerControlState.passStatuses = nextLatch
    ? new Set([nextLatch, "estimated"])
    : allPassStatusFilterSet();
  notifyLayerFiltersChanged({ passes: true });
}

function notifyLayerFiltersChanged({ passes = false, pois = false } = {}) {
  updateMapSources();
  scheduleAlpineOverlayLayout();
  if (passes) {
    renderList();
    renderAdvancedPicker();
  }
  if (pois) {
    renderPoiList();
    renderAdvancedPoiPicker?.();
  }
  refreshLayerControlUI();
  refreshConditionsStrip();
}

function setPassOverlayVisible(visible) {
  const next = !!visible;
  if (layerControlState.passOverlayVisible === next) {
    refreshLayerControlUI();
    return;
  }
  layerControlState.passOverlayVisible = next;
  notifyLayerFiltersChanged({ passes: true });
}

function setLayerSoloFocus(visible) {
  const next = !!visible && plannedRouteActive;
  if (layerControlState.soloFocus === next) {
    refreshLayerControlUI();
    return;
  }
  layerControlState.soloFocus = next;
  alpineOverlayLayer.setSoloFocus(next);
  map.getContainer().classList.toggle("pass-stack-solo-focus", next);
  refreshLayerControlUI();
}

function statusColorExpression() {
  return [
    "match", ["get", "state"],
    "open", "#3ddc84",
    "restricted", "#ffb020",
    "closed", "#ef4444",
    "#8a96a0",
  ];
}

function passFeature(p) {
  const status = passStatus(p);
  const view = statusDisplay(status);
  const badge = plannedBadgeNumber(p) || 0;
  return {
    type: "Feature",
    id: p.id,
    geometry: { type: "Point", coordinates: [p.lon, p.lat] },
    properties: {
      id: p.id,
      kind: "pass",
      name: p.name,
      alt: p.alt || "",
      elev: p.elev,
      state: view.state,
      estimated: !!view.estimated,
      quality: p.quality || 0,
      tourIndex: badge,
      tourLabel: badge ? String(badge) : "",
    },
  };
}

function poiFeature(p) {
  const badge = plannedBadgeNumber(p) || 0;
  return {
    type: "Feature",
    id: p.id,
    geometry: { type: "Point", coordinates: [p.lon, p.lat] },
    properties: {
      id: p.id,
      kind: "poi",
      name: p.name,
      category: p.poiCategory || "",
      plannable: isPlannablePoi(p),
      quality: p.quality || 0,
      tourIndex: badge,
      tourLabel: badge ? String(badge) : "",
    },
  };
}

function featureCollection(items, mapper) {
  return { type: "FeatureCollection", features: items.map(mapper) };
}

function currentPassMapFeatures() {
  if (!layerControlState.passOverlayVisible) return EMPTY_FEATURE_COLLECTION;
  const items = passUiReady ? PASSES.filter(passesAllFilters) : PASSES;
  return featureCollection(items, passFeature);
}

function currentPoiMapFeatures() {
  if (!poiLayerVisible) return EMPTY_FEATURE_COLLECTION;
  if (!poiUiReady) return featureCollection(POIS, poiFeature);
  const q = (poiSearchEl?.value || "").trim().toLowerCase();
  return featureCollection(
    POIS.filter(p => poiPassesAllFilters(p)).filter(p => !q || poiSearchMatches(p, q)),
    poiFeature
  );
}

/* Scenic drives (multi-waypoint LineStrings). Currently Japan-only.
   Two FeatureCollections feed two MapLibre layers: a line layer for the
   route polyline, and a circle+label layer for the named waypoints. */
const SCENIC_DRIVES_RAW = ((typeof JAPAN_SCENIC_DRIVES !== "undefined" && Array.isArray(JAPAN_SCENIC_DRIVES))
  ? JAPAN_SCENIC_DRIVES
  : []);

function currentScenicDriveLineFeatures() {
  return {
    type: "FeatureCollection",
    features: SCENIC_DRIVES_RAW.map((d, i) => ({
      type: "Feature",
      id: `scenic-drive-${i}`,
      geometry: {
        type: "LineString",
        coordinates: (d.waypoints || []).map(w => [w.lo, w.la]),
      },
      properties: {
        kind: "scenic-drive",
        name: d.n,
        region: d.region || "",
        country: d.co || "",
        lengthKm: d.len_km || 0,
        driveMin: d.drive_min || 0,
        score: d.sc || 0,
      },
    })),
  };
}

function currentScenicDrivePointFeatures() {
  const features = [];
  for (let i = 0; i < SCENIC_DRIVES_RAW.length; i += 1) {
    const drive = SCENIC_DRIVES_RAW[i];
    const wps = drive.waypoints || [];
    for (let j = 0; j < wps.length; j += 1) {
      const w = wps[j];
      const isEndpoint = j === 0 || j === wps.length - 1;
      features.push({
        type: "Feature",
        id: `scenic-wp-${i}-${j}`,
        geometry: { type: "Point", coordinates: [w.lo, w.la] },
        properties: {
          kind: "scenic-drive-waypoint",
          driveName: drive.n,
          waypointName: w.n,
          isEndpoint,
        },
      });
    }
  }
  return { type: "FeatureCollection", features };
}

function setSourceData(sourceId, data) {
  const source = map.getSource(sourceId);
  if (source) source.setData(data);
}

function hasRequiredMapLayers() {
  return !!(
    map.getSource(PASS_SOURCE_ID) &&
    map.getSource(POI_SOURCE_ID) &&
    map.getSource(ROUTE_SOURCE_ID) &&
    map.getLayer("planned-route-core") &&
    map.getLayer(ITINERA_GL_LAYER_ID)
  );
}

function requestMapLayerRestore(attempt = 0) {
  if (mapLayerRestoreQueued) return;
  mapLayerRestoreQueued = true;
  const run = () => {
    mapLayerRestoreQueued = false;
    try {
      mapLayersReady = false;
      setupMapLayers();
      updateMapInfo(currentBaseLayerName);
    } catch (error) {
      if (attempt < 20) {
        setTimeout(() => requestMapLayerRestore(attempt + 1), 100);
        return;
      }
      console.error("Unable to restore Alpine map layers after style change", error);
    }
  };
  requestAnimationFrame(run);
}

function updateMapSources() {
  scheduleAlpineOverlayRender();
  if (!mapLayersReady || !hasRequiredMapLayers()) {
    requestMapLayerRestore();
    return;
  }
  setSourceData(PASS_SOURCE_ID, currentPassMapFeatures());
  setSourceData(POI_SOURCE_ID, currentPoiMapFeatures());
  updatePlannedTourLayers();
  updateLeisureOverlaySources();
  scheduleAlpineOverlayRender();
}

function addLayerWithSource(layer, beforeId) {
  if (map.getLayer(layer.id)) return;
  if (beforeId && map.getLayer(beforeId)) {
    map.addLayer(layer, beforeId);
    return;
  }
  map.addLayer(layer);
}

